const chatStateReads = new Map<string, Promise<ChatState>>();

interface ArtifactMigrationBackup {
  artifact: MessageArtifact;
  snapshot: MessageArtifact['snapshot'];
  aliases: MessageArtifact['persistedCharacterIdAliasesV30'];
  hadAliases: boolean;
  sync: MessageArtifact['stages']['sync'] | undefined;
  hadSync: boolean;
  lorebookEntryIds: MessageArtifact['lorebookEntryIds'];
  hadLorebookEntryIds: boolean;
}

const REQUIRED_MIGRATIONS = [
  'dynamicTablesV23',
  'internalFactsV23',
  'objectViewsV26',
  'objectAllocationV27',
  'summaryVersionsV27',
  'regionAllocationV28',
  'characterMergeV29',
  'persistedCharacterMergeV30',
] as const;

function currentStateStructure(raw: unknown, chatKey: string): raw is ChatState {
  if (!raw || typeof raw !== 'object') return false;
  const state = raw as ChatState;
  if (state.schemaVersion !== CURRENT_SCHEMA_VERSION || state.chatKey !== chatKey) return false;
  if (!Array.isArray(state.processedMessageKeys)
    || !Array.isArray(state.internalFacts)
    || !Array.isArray(state.smallSummaries)
    || !Array.isArray(state.largeSummaries)) return false;
  if (!state.processedMessageKeys.every((key) => typeof key === 'string')) return false;
  if (new Set(state.processedMessageKeys).size !== state.processedMessageKeys.length) return false;
  if (!['idle', 'success', 'failed'].includes(state.lastSyncStatus)) return false;
  if (typeof state.updatedAt !== 'string') return false;
  if (state.focusObjectId !== undefined && typeof state.focusObjectId !== 'string') return false;
  return REQUIRED_MIGRATIONS.every((key) => state.migration?.[key] === true);
}

async function readCurrentChatStateFast(
  namespace: Record<string, any>,
  state: ChatState,
  chatKey: string,
): Promise<ChatState> {
  if (!Object.prototype.hasOwnProperty.call(state, 'focusObjectId')) return state;
  const next = { ...state };
  const focusChanged = validateCurrentFocus(next, getSettings().tableRegistry);
  if (!focusChanged) return state;
  namespace.state = next;
  try {
    await persistMetadataFor(chatKey);
    return next;
  } catch (error) {
    namespace.state = state;
    throw error;
  }
}

async function readChatState(chatKey: string): Promise<ChatState> {
  assertChatCommitCurrent(chatKey, '聊天已切换，不读取旧聊天状态');
  const namespace = getChatMetadataNamespace();
  if (currentStateStructure(namespace.state, chatKey)) {
    return readCurrentChatStateFast(namespace, namespace.state, chatKey);
  }
  const hadState = Object.prototype.hasOwnProperty.call(namespace, 'state');
  const previousState = namespace.state;
  const backups: ArtifactMigrationBackup[] = [];
  for (const message of getChat()) {
    const artifact = message?.extra?.[MODULE_NAME] as MessageArtifact | undefined;
    if (!artifact || artifact.chatKey !== chatKey) continue;
    backups.push({
      artifact,
      snapshot: artifact.snapshot,
      aliases: artifact.persistedCharacterIdAliasesV30,
      hadAliases: Object.prototype.hasOwnProperty.call(artifact, 'persistedCharacterIdAliasesV30'),
      sync: artifact.stages?.sync,
      hadSync: Boolean(artifact.stages && Object.prototype.hasOwnProperty.call(artifact.stages, 'sync')),
      lorebookEntryIds: artifact.lorebookEntryIds,
      hadLorebookEntryIds: Object.prototype.hasOwnProperty.call(artifact, 'lorebookEntryIds'),
    });
  }
  const migration = migrateChatState(namespace.state as ChatState | undefined, chatKey);
  let chatPersisted = false;
  try {
    if (migration.artifactViewsChanged) {
      await persistChatFor(chatKey);
      chatPersisted = true;
    }
    namespace.state = migration.state;
    if (migration.metadataChanged) await persistMetadataFor(chatKey);
    return namespace.state as ChatState;
  } catch (error) {
    if (hadState) namespace.state = previousState;
    else delete namespace.state;
    // 若聊天尚未确认保存，恢复所有内存 artifact；若聊天已保存而 metadata 失败，
    // 保留随聊天落盘的 V30 ID 别名，让下一次读取能修复旧 focusObjectId 后完成迁移位。
    if (!chatPersisted) {
      for (const backup of backups) {
        backup.artifact.snapshot = backup.snapshot;
        if (backup.hadAliases) backup.artifact.persistedCharacterIdAliasesV30 = backup.aliases;
        else delete backup.artifact.persistedCharacterIdAliasesV30;
        if (backup.artifact.stages) {
          if (backup.hadSync) backup.artifact.stages.sync = backup.sync!;
          else delete (backup.artifact.stages as any).sync;
        }
        if (backup.hadLorebookEntryIds) backup.artifact.lorebookEntryIds = backup.lorebookEntryIds;
        else delete backup.artifact.lorebookEntryIds;
      }
    }
    throw error;
  }
}

export function getChatState(chatKey: string): Promise<ChatState> {
  const running = chatStateReads.get(chatKey);
  if (running) return running;
  const pending = readChatState(chatKey).finally(() => {
    if (chatStateReads.get(chatKey) === pending) chatStateReads.delete(chatKey);
  });
  chatStateReads.set(chatKey, pending);
  return pending;
}

/** ChatState 只能写入其自身 chatKey 对应的当前聊天 metadata。 */
export async function putChatState(state: ChatState): Promise<void> {
  assertChatCommitCurrent(state.chatKey, '聊天已切换，不写入旧聊天状态');
  state.schemaVersion = CURRENT_SCHEMA_VERSION;
  state.chatLocator = currentChatLocator() || state.chatLocator;
  state.internalFacts = normalizeInternalFacts(state.internalFacts);
  if (state.migration?.internalFactsV23 !== true || state.migration?.summaryVersionsV27 !== true) {
    migrateLegacyConsumption(state.internalFacts, state.smallSummaries, state.largeSummaries);
  }
  state.updatedAt = nowIso();
  const namespace = getChatMetadataNamespace();
  namespace.state = state;
  namespace.updatedAt = state.updatedAt;
  await persistMetadataFor(state.chatKey);
}

export async function clearAllStorage(chatKey = currentChatKey()): Promise<void> {
  assertChatCommitCurrent(chatKey, '聊天已切换，不清理旧聊天状态');
  const namespace = getChatMetadataNamespace();
  delete namespace.state;
  delete namespace.lorebookName;
  namespace.updatedAt = nowIso();
  await persistMetadataFor(chatKey);
}
