/**
 * 模块职责：依据动态表格注册表构造内部事实与行级状态补丁提示、JSON Schema。
 * 维护边界：只提取已发生、已显影内容；未返回行由插件保留，禁止模型重写完整旧快照。
 */
import type { TableDefinition, TableFieldDefinition } from '../constants';
import type { InternalFact, StateRow, StateSnapshot } from '../types';
import { DEFAULT_TABLE_REGISTRY, enabledTables, normalizeTableRegistry } from '../domain/table-registry';

const COMMON_FIELD_KEYS = new Set([
  'id', 'title', 'content', 'keywords', 'status', 'baseContent', 'currentFacts', 'currentStates',
  'recentHistory', 'solidifiedHistory', 'relatedObjects', 'relatedEvents',
]);
const ACTIVE_STATUS_RE = /current|active|进行|当前|活跃|未决|持续|开放|受限|暂停/i;
const MAX_INDEX_ROWS = 120;
const MAX_FULL_ROWS = 16;
const MAX_FULL_ROWS_PER_TABLE = 6;
const MAX_FACTS = 18;

function tables(registry?: TableDefinition[]): TableDefinition[] {
  return enabledTables(normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]));
}

function extraFieldInstruction(field: TableFieldDefinition): string {
  return `${field.key}（${field.label}）：${field.description || '按字段名称填写'}${field.required ? '，必填' : ''}`;
}

function compactRegistryDescription(active: TableDefinition[]): string {
  return active.map((table, index) => {
    const defaultTable = DEFAULT_TABLE_REGISTRY.find((item) => item.key === table.key);
    const extras = table.fields
      .filter((field) => {
        if (!COMMON_FIELD_KEYS.has(field.key)) return true;
        const base = defaultTable?.fields.find((item) => item.key === field.key);
        return !base || base.label !== field.label || base.description !== field.description || base.required !== field.required;
      })
      .map(extraFieldInstruction)
      .join('；');
    return `${index + 1}. ${table.key}｜${table.name}｜用途：${table.purpose}${extras ? `｜扩展字段：${extras}` : ''}`;
  }).join('\n');
}

export function stateSystemPrompt(registry?: TableDefinition[]): string {
  const active = tables(registry);
  const keys = active.map((table) => table.key).join('、');
  return `你是“镜渊”事实提取与状态维护器（多事件线、多对象）。你不续写故事，不推测未显影内容。

只输出可直接 JSON.parse 的完整对象，不要 Markdown、解释或思考标签。
根节点固定为 turnSummary、facts、operations。operations.table 只能使用启用表格：${keys || '（无）'}。

【一次生成，多线分区】
1. 一轮正文可能同时推进多条彼此无关的事件线；必须分别建立或沿用不同 event_id，绝不能混成同一事件。
2. 同一对象可以同时受多条事件线影响；在同一行中归并所有真实变化，不能让后一个事件覆盖前一个事件。
3. facts 的 related_entities 必须列出该事实直接影响的对象稳定名称，包括人物、地区、事件、物品、组织或全局对象；只知情、同场或围观不算影响。
4. 尽量在一次返回中完成本轮全部独立事件线和全部受影响条目的补丁。

【最小 operations 行级补丁协议】
1. operations 只返回本轮新增或变化的对象行；每项固定包含 op、table、id、title、content、keywords、status、fields、lifecycle，op 当前只能是 upsert。
2. 同一对象必须沿用旧 id。无变化对象不输出 operation；未返回行自动保留；不得重写整张旧表，也不得输出隐式清表操作。
3. fields 是动态字段补丁数组，每项固定为 {"key":"字段名","values":["值"]}。string 字段 values 只放一个字符串；string[] 字段按数组逐项填写；无额外字段时输出空数组。
4. lifecycle 始终输出完整对象。该行没有生命周期变化时，五个字符串输出空字符串，两个数组输出空数组；只有目标表注册了 lifecycle 且确有变化时才填写。
5. factIds、eventId、eventIds 与 recall 由插件根据 facts 本地生成，不要重复输出。
6. baseContent 是对象定义，已有非空值不得由普通状态提取改写。
7. currentFacts 写当前客观成立、持续较久但未来仍可能被替换的事实；currentStates 写正在发生、短期或阶段性的状态。
8. recentHistory 与 solidifiedHistory 只由小总结和大总结维护，状态提取不得写入 fields。

【内部事实 facts】
每条固定包含 fact_id、event_id、type、title、occurred、unresolved、status、time_start、time_end、time_label、related_entities、keywords、operation、confidence。
同一事实与事件线必须沿用旧 ID；只输出本轮 create、update、append、close 或 supersede 变化。

【事实边界】
- 只记录对后续仍有作用且来源明确的事实；同场、普通对话、表情、推测或身份联想不得赋予对象新的关系、能力、身份或长期影响，围观和临时动作也不自动建立对象或关系。
- 不输出 focus 表或焦点事实。关系和技能不得单列；关系变化写入角色 relationshipStates，能力变化写入 abilityStates。
- 他人陈述、传闻和推测使用 reported 或 uncertain，不得升级为 confirmed。
- 玩家输入可记录为声明动作；外部结果必须由角色正文或已有可靠事实确认。
- 当前地点只写时空；区域只记录离开后仍成立的定义、现行事实或持续变化。
- 场景切换后，已离开的旧场景不得继续标为当前。
- 过程压缩为当前结果，未决事项不得强行闭合。

【启用表格】
${compactRegistryDescription(active) || '当前没有启用表格；operations 输出空数组。'}

【字段层级】
id：稳定 ID；title：稳定对象名；content：当前有效摘要；keywords：名称与稳定别名；status：当前阶段；baseContent：对象定义；currentFacts：现行事实；currentStates：当前状态；recentHistory：近期经历（状态提取禁写）；solidifiedHistory：历史事实（状态提取禁写）；relatedObjects：直接关联对象；relatedEvents：直接关联事件。

输出结构示意（省略无变化对象）：
{"turnSummary":"多线分别推进","facts":[{"fact_id":"f1","event_id":"e1","type":"event","title":"事件一","occurred":["已发生结果"],"unresolved":[],"status":"resolved","time_start":"当前","time_end":"当前","time_label":"","related_entities":["对象甲","地区甲"],"keywords":["事件一"],"operation":"close","confidence":"confirmed"}],"operations":[{"op":"upsert","table":"characters","id":"c1","title":"对象甲","content":"当前结果","keywords":["对象甲"],"status":"active","fields":[{"key":"currentFacts","values":["当前客观事实"]}],"lifecycle":{"existence":"","activity":"","memory":"","evidenceLevel":"","evidence":"","returnConditions":[],"returnBlockers":[]}}]}`;
}
function normalizeSearchText(value: unknown): string {
  return String(value ?? '').normalize('NFKC').toLowerCase().replace(/[\s\p{P}\p{S}]+/gu, '');
}

function stringList(value: unknown): string[] {
  return Array.isArray(value) ? value.map((item) => String(item ?? '').trim()).filter(Boolean) : [];
}

function boundedList(value: unknown, count: number, chars: number): string[] {
  return stringList(value).slice(-count).map((item) => item.slice(0, chars));
}

function modelRow(row: StateRow): Record<string, unknown> {
  const output: Record<string, unknown> = {
    id: row.id,
    title: row.title,
    content: String(row.content || '').slice(0, 800),
    keywords: (row.keywords ?? []).slice(0, 16),
    status: row.status,
    eventIds: row.eventIds ?? (row.eventId ? [row.eventId] : []),
  };
  if (row.lifecycle) output.lifecycle = row.lifecycle;
  const fields = row.fields && typeof row.fields === 'object' ? row.fields : {};
  for (const [key, value] of Object.entries(fields)) {
    if (key === 'baseContent') output[key] = String(value ?? '').slice(0, 700);
    else if (key === 'currentFacts' || key === 'currentStates') output[key] = boundedList(value, 10, 260);
    else if (key === 'recentHistory') output[key] = boundedList(value, 4, 320);
    else if (key === 'solidifiedHistory') output[key] = boundedList(value, 2, 260);
    else if (Array.isArray(value)) output[key] = boundedList(value, 10, 220);
    else output[key] = String(value ?? '').slice(0, 600);
  }
  return output;
}
function rowIndex(row: StateRow): Record<string, unknown> {
  return {
    id: row.id,
    title: row.title,
    status: row.status,
    keywords: row.keywords,
    eventIds: row.eventIds ?? (row.eventId ? [row.eventId] : []),
  };
}

function rowTerms(row: StateRow): string[] {
  return [row.id, row.title, ...(row.keywords ?? [])]
    .map(normalizeSearchText)
    .filter((term) => term.length >= 2);
}

function rowMatches(row: StateRow, source: string): boolean {
  return rowTerms(row).some((term) => source.includes(term));
}

function relatedTokens(row: StateRow): string[] {
  const fields = row.fields && typeof row.fields === 'object' ? row.fields : {};
  return [
    ...stringList((fields as any).relatedObjects),
    ...stringList((fields as any).relatedEvents),
  ].map(normalizeSearchText).filter(Boolean);
}

function compactSnapshotContext(previous: StateSnapshot, active: TableDefinition[], sourceText: string): {
  index: Record<string, unknown[]>;
  relevant: Record<string, unknown[]>;
} {
  const source = normalizeSearchText(sourceText);
  const all: Array<{ table: TableDefinition; row: StateRow; direct: boolean; active: boolean; order: number }> = [];
  let order = 0;
  for (const table of active) {
    for (const row of previous[table.key] ?? []) {
      const direct = rowMatches(row, source);
      const activeRow = table.role === 'spacetime' || table.role === 'events' && ACTIVE_STATUS_RE.test(row.status) || ACTIVE_STATUS_RE.test(row.status);
      all.push({ table, row, direct, active: activeRow, order: order += 1 });
    }
  }

  const seedTokens = new Set<string>();
  for (const item of all) {
    if (!item.direct && !item.active) continue;
    for (const term of rowTerms(item.row)) seedTokens.add(term);
  }
  const related = (item: typeof all[number]) => relatedTokens(item.row).some((term) => seedTokens.has(term));
  const priority = (item: typeof all[number]) => item.direct ? 4 : item.table.role === 'spacetime' ? 3 : related(item) ? 2 : item.active ? 1 : 0;
  const sorted = [...all].sort((a, b) => priority(b) - priority(a) || String(b.row.updatedAt || '').localeCompare(String(a.row.updatedAt || '')) || a.order - b.order);

  const index: Record<string, unknown[]> = {};
  for (const item of sorted.slice(0, MAX_INDEX_ROWS)) {
    (index[item.table.key] ||= []).push(rowIndex(item.row));
  }

  const relevant: Record<string, unknown[]> = {};
  let total = 0;
  const perTable = new Map<string, number>();
  for (const item of sorted) {
    if (priority(item) <= 0 && (previous[item.table.key]?.length ?? 0) > 8) continue;
    if (total >= MAX_FULL_ROWS) break;
    const count = perTable.get(item.table.key) ?? 0;
    if (count >= MAX_FULL_ROWS_PER_TABLE) continue;
    (relevant[item.table.key] ||= []).push(modelRow(item.row));
    perTable.set(item.table.key, count + 1);
    total += 1;
  }
  return { index, relevant };
}

function factMatches(fact: InternalFact, source: string): boolean {
  const terms = [fact.factId, fact.eventId, fact.title, ...fact.keywords, ...fact.relatedEntities]
    .map(normalizeSearchText)
    .filter((term) => term.length >= 2);
  return terms.some((term) => source.includes(term));
}

function activeFactPayload(facts: InternalFact[], sourceText: string): Record<string, unknown>[] {
  const source = normalizeSearchText(sourceText);
  const selected = facts.length <= MAX_FACTS
    ? facts
    : facts.filter((fact) => factMatches(fact, source) || fact.unresolvedItems.length > 0 || fact.active).slice(-MAX_FACTS);
  const fallback = selected.length ? selected : facts.slice(-12);
  return fallback.map((fact) => ({
    fact_id: fact.factId,
    event_id: fact.eventId,
    occurred: fact.occurredFacts,
    unresolved: fact.unresolvedItems,
    status: fact.status,
    time_range: fact.timeRange,
    related_entities: fact.relatedEntities,
    title: fact.title,
    type: fact.type,
    keywords: fact.keywords,
    confidence: fact.confidence,
    active: fact.active,
  }));
}

export function stateUserPrompt(
  previous: StateSnapshot,
  playerText: string,
  assistantText: string,
  registry?: TableDefinition[],
  internalFacts: InternalFact[] = [],
  repair = false,
): string {
  const active = tables(registry);
  const sourceText = `${playerText}\n${assistantText}`;
  const context = compactSnapshotContext(previous, active, sourceText);
  return `【相关内部事实】\n${JSON.stringify(activeFactPayload(internalFacts, sourceText))}

【旧视图索引：仅用于沿用稳定ID】\n${JSON.stringify(context.index)}

【与本轮相关的旧行全文】\n${JSON.stringify(context.relevant)}

【玩家本轮输入】\n${playerText || '（空）'}

【角色本轮正文】\n${assistantText}

只返回本轮事实变化和最小 operations 行级补丁。未返回的对象行由插件保留；不要复制无变化旧行。若旧视图索引中已有同一对象，必须沿用其 id。${repair ? '\n上一次输出无法解析；这次只输出合法JSON对象。' : ''}`;
}

function scalarSchema(field: TableFieldDefinition, table: TableDefinition): Record<string, any> {
  const defaultField = DEFAULT_TABLE_REGISTRY
    .find((item) => item.key === table.key)
    ?.fields.find((item) => item.key === field.key);
  const customized = !defaultField
    || defaultField.label !== field.label
    || defaultField.description !== field.description
    || defaultField.type !== field.type;
  const semantics = customized ? {
    title: field.label,
    description: `${field.label}：${field.description || '按字段名称填写'}`,
  } : {};
  if (field.type === 'string[]') return { type: 'array', items: { type: 'string' }, ...semantics };
  if (field.type === 'lifecycle') {
    return {
      type: 'object',
      ...semantics,
      properties: {
        existence: { type: 'string' }, activity: { type: 'string' }, memory: { type: 'string' }, evidenceLevel: { type: 'string' }, evidence: { type: 'string' },
        returnConditions: { type: 'array', items: { type: 'string' } }, returnBlockers: { type: 'array', items: { type: 'string' } },
      },
      required: ['existence', 'activity', 'memory', 'evidenceLevel', 'evidence', 'returnConditions', 'returnBlockers'],
      additionalProperties: false,
    };
  }
  return { type: 'string', ...semantics };
}

function rowSchema(table: TableDefinition): Record<string, any> {
  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (const field of table.fields) {
    properties[field.key] = scalarSchema(field, table);
    if (field.required) required.push(field.key);
  }
  // factIds、eventId、eventIds 与 recall 全部由插件从 facts 本地派生，不进入模型 Schema。
  return { type: 'object', properties, required: [...new Set(required)], additionalProperties: false };
}


function transportFactSchema(): Record<string, any> {
  return {
    type: 'object',
    properties: {
      fact_id: { type: 'string' },
      event_id: { type: 'string' },
      type: { type: 'string' },
      title: { type: 'string' },
      occurred: { type: 'array', items: { type: 'string' } },
      unresolved: { type: 'array', items: { type: 'string' } },
      status: { type: 'string' },
      time_start: { type: 'string' },
      time_end: { type: 'string' },
      time_label: { type: 'string' },
      related_entities: { type: 'array', items: { type: 'string' } },
      keywords: { type: 'array', items: { type: 'string' } },
      operation: { type: 'string', enum: ['create', 'update', 'append', 'close', 'supersede'] },
      confidence: { type: 'string', enum: ['confirmed', 'recorded', 'reported', 'uncertain'] },
    },
    required: [
      'fact_id', 'event_id', 'type', 'title', 'occurred', 'unresolved', 'status',
      'time_start', 'time_end', 'time_label', 'related_entities', 'keywords', 'operation', 'confidence',
    ],
    additionalProperties: false,
  };
}

function transportFieldPatchSchema(): Record<string, any> {
  return {
    type: 'object',
    properties: {
      key: { type: 'string' },
      values: { type: 'array', items: { type: 'string' } },
    },
    required: ['key', 'values'],
    additionalProperties: false,
  };
}

function transportLifecycleSchema(): Record<string, any> {
  return {
    type: 'object',
    properties: {
      existence: { type: 'string' },
      activity: { type: 'string' },
      memory: { type: 'string' },
      evidenceLevel: { type: 'string' },
      evidence: { type: 'string' },
      returnConditions: { type: 'array', items: { type: 'string' } },
      returnBlockers: { type: 'array', items: { type: 'string' } },
    },
    required: ['existence', 'activity', 'memory', 'evidenceLevel', 'evidence', 'returnConditions', 'returnBlockers'],
    additionalProperties: false,
  };
}

function transportOperationSchema(active: TableDefinition[]): Record<string, any> {
  return {
    type: 'object',
    properties: {
      op: { type: 'string', enum: ['upsert'] },
      table: { type: 'string', enum: active.map((table) => table.key) },
      id: { type: 'string' },
      title: { type: 'string' },
      content: { type: 'string' },
      keywords: { type: 'array', items: { type: 'string' } },
      status: { type: 'string' },
      fields: { type: 'array', items: transportFieldPatchSchema() },
      lifecycle: transportLifecycleSchema(),
    },
    required: ['op', 'table', 'id', 'title', 'content', 'keywords', 'status', 'fields', 'lifecycle'],
    additionalProperties: false,
  };
}

/**
 * 发送给 SillyTavern/供应商的严格、扁平 operations Schema。
 * 所有对象属性均列入 required，动态字段通过 key/values 传输；完整动态表格 Schema 仍只在镜渊本地校验。
 */
export function stateTransportJsonSchema(registry?: TableDefinition[]): Record<string, any> {
  const active = tables(registry);
  return {
    name: 'MirrorAbyssStateOperationsV37',
    description: '镜渊状态事实与严格扁平对象补丁',
    strict: true,
    value: {
      type: 'object',
      properties: {
        turnSummary: { type: 'string' },
        facts: { type: 'array', items: transportFactSchema() },
        operations: { type: 'array', items: transportOperationSchema(active) },
      },
      required: ['turnSummary', 'facts', 'operations'],
      additionalProperties: false,
    },
  };
}

export function stateJsonSchema(registry?: TableDefinition[]): Record<string, any> {
  const active = tables(registry);
  const snapshotProperties: Record<string, any> = Object.fromEntries(active.map((table) => [table.key, {
    type: 'array',
    title: table.name,
    description: `${table.name}｜用途：${table.purpose}｜本轮新增或变化行；无变化时省略该表；空数组仅视为无变化，不表示清空`,
    items: rowSchema(table),
  }]));
  return {
    name: 'MirrorAbyssMultiEventPatchV35',
    description: '镜渊多事件线事实变化与多对象行级补丁',
    strict: false,
    value: {
      $schema: 'http://json-schema.org/draft-04/schema#',
      type: 'object',
      properties: {
        turnSummary: { type: 'string' },
        facts: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              fact_id: { type: 'string' }, factId: { type: 'string' }, id: { type: 'string' },
              event_id: { type: 'string' }, eventId: { type: 'string' }, entity_id: { type: 'string' }, entityId: { type: 'string' },
              type: { type: 'string' }, title: { type: 'string' }, content: { type: 'string' },
              occurred: { type: 'array', items: { type: 'string' } }, occurredFacts: { type: 'array', items: { type: 'string' } },
              unresolved: { type: 'array', items: { type: 'string' } }, unresolvedItems: { type: 'array', items: { type: 'string' } },
              status: { type: 'string' },
              time_range: { type: 'object', properties: { start: { type: 'string' }, end: { type: 'string' }, label: { type: 'string' } }, additionalProperties: false },
              timeRange: { type: 'object', properties: { start: { type: 'string' }, end: { type: 'string' }, label: { type: 'string' } }, additionalProperties: false },
              related_entities: { type: 'array', items: { type: 'string' } }, relatedEntities: { type: 'array', items: { type: 'string' } },
              keywords: { type: 'array', items: { type: 'string' } },
              operation: { type: 'string', enum: ['create', 'update', 'append', 'close', 'supersede'] }, confidence: { type: 'string', enum: ['confirmed', 'recorded', 'reported', 'uncertain'] },
            },
            required: ['type', 'title', 'status', 'keywords', 'operation', 'confidence'],
            additionalProperties: false,
          },
        },
        snapshot: { type: 'object', properties: snapshotProperties, additionalProperties: false },
      },
      required: ['turnSummary', 'facts', 'snapshot'], additionalProperties: false,
    },
  };
}
