function currentArtifact(): {
  index: number;
  artifact: MessageArtifact;
} | null {
  if (selectedMessageIndex !== null) {
    const artifact = getArtifactAt(selectedMessageIndex);
    if (artifact) return { index: selectedMessageIndex, artifact };
    return null;
  }
  return latestArtifact();
}

function statusText(value: string): string {
  const map: Record<string, string> = {
    idle: "等待",
    queued: "排队",
    running: "处理中",
    success: "成功",
    failed: "失败",
    cancelled: "已取消",
    skipped: "跳过",
    blocked: "阻断",
  };
  return map[value] || value;
}

function statusClass(value: string): string {
  if (value === "success" || value === "skipped") return "success";
  if (value === "failed" || value === "blocked") return "danger";
  if (value === "cancelled") return "neutral";
  if (value === "running" || value === "queued") return "working";
  return "neutral";
}

function stageCards(artifact?: MessageArtifact): string {
  const stages = artifact?.stages;
  const rows = [
    ["audit", "规则审核"],
    ["revision", "定向修正"],
    ["state", "状态提取"],
    ["summary", "分层总结"],
    ["sync", "世界书同步"],
  ] as const;
  return `<div class="ma11-stage-grid">${rows
    .map(([key, label]) => {
      const stage = stages?.[key] ?? { status: "idle", attempts: 0 };
      return `<article class="ma11-stage-card ${statusClass(stage.status)}">
      <div><b>${label}</b><span>${statusText(stage.status)}</span></div>
      <small>尝试 ${stage.attempts || 0} 次</small>
      ${stage.error ? `<p>${escapeHtml(stage.error)}</p>` : ""}
    </article>`;
    })
    .join("")}</div>`;
}

function stageActionButtonsHtml(
  artifactInfo: ReturnType<typeof currentArtifact>,
): string {
  const settings = getSettings();
  const latestIndex = latestAssistantIndex();
  const isLatestText = artifactInfo
    ? artifactInfo.index === latestIndex
    : selectedMessageIndex === null && latestIndex >= 0;
  const artifact = artifactInfo?.artifact;
  const latestSnapshot = latestSnapshotArtifact();
  const canAudit = Boolean(settings.enabled && settings.auditEnabled && settings.auditPrompt.trim() && isLatestText);
  const canRevise = Boolean(
    settings.enabled
    && isLatestText
    && artifact?.audit
    && !artifact.audit.passed
    && artifact.audit.decision !== 'block',
  );
  const canState = Boolean(
    settings.enabled
    && isLatestText
    && (!settings.auditEnabled || artifact?.audit?.passed),
  );
  const canSummarize = Boolean(
    settings.enabled
    && latestSnapshot
    && artifactInfo?.artifact.messageKey === latestSnapshot.artifact.messageKey,
  );
  return `<div class="ma11-actions ma11-stage-actions">
    <button data-ma11-action="run-audit" ${canAudit ? '' : 'disabled'}>审核正文</button>
    <button data-ma11-action="run-revision" ${canRevise ? '' : 'disabled'}>定向修正</button>
    <button data-ma11-action="run-state" ${canState ? '' : 'disabled'}>生成表格</button>
    <button data-ma11-action="force-small" ${canSummarize ? '' : 'disabled'}>小总结</button>
    <button data-ma11-action="force-large" ${canSummarize ? '' : 'disabled'}>大总结</button>
  </div>`;
}

function recentTasksHtml(): { count: number; html: string } {
  const jobs = taskQueue.list().slice(0, 5);
  return {
    count: jobs.length,
    html: jobs.length
      ? jobs.map((task: any) => {
          const timing = [
            Number.isFinite(task.queueWaitMs) ? `排队 ${task.queueWaitMs}ms` : "",
            Number.isFinite(task.runMs) ? `执行 ${task.runMs}ms` : "",
          ].filter(Boolean).join(" · ");
          return `<div><span>${escapeHtml(task.label)}${timing ? `<small>${escapeHtml(timing)}</small>` : ""}</span><em class="${task.state}">${escapeHtml(statusText(task.state))}</em></div>`;
        }).join("")
      : '<p class="ma11-empty">没有运行中的任务。</p>',
  };
}

function refreshTaskList(): void {
  const workspace = document.querySelector<HTMLElement>("#ma11-workspace");
  const list = workspace?.querySelector<HTMLElement>("[data-ma11-task-list]");
  const count = workspace?.querySelector<HTMLElement>("[data-ma11-task-count]");
  if (!list || !count) return;
  const tasks = recentTasksHtml();
  count.textContent = tasks.count ? `${tasks.count} 条最近任务` : "空闲";
  list.innerHTML = tasks.html;
}

function handleQueueChange(): void {
  refreshTaskList();
  if (taskQueue.list().some((task) => task.state === "queued" || task.state === "running")) return;
  const workspace = document.querySelector<HTMLElement>("#ma11-workspace");
  const active = document.activeElement as HTMLElement | null;
  if (workspace?.contains(active) && active?.matches("input, textarea, select, [contenteditable='true']")) return;
  void renderWorkspace();
}

function historyRecoveryHtml(chatState: any): string {
  const recovery = chatState?.historyRecovery;
  if (!recovery) return "";
  const current = Number.isInteger(recovery.currentIndex) ? `第 ${recovery.currentIndex + 1} 条消息` : "当前历史";
  const progress = recovery.totalCount ? `${recovery.completedCount}/${recovery.totalCount}` : "检查中";
  if (recovery.phase === "failed") {
    return `<section class="ma11-card ma11-history-warning"><header><b>历史重建未完成</b><span>${escapeHtml(current)}</span></header><p>${escapeHtml(recovery.error || chatState.lastSyncError || "状态提取失败")}</p><div class="ma11-actions"><button data-ma11-action="recalculate-history">从失败位置继续</button></div></section>`;
  }
  const labels: Record<string, string> = {
    "rebuilding-core": "正在重建核心状态",
    "rebuilding-derived": "正在恢复总结",
    "publishing-lorebook": "正在发布世界书",
    partial: "核心状态已恢复，派生恢复不完整",
  };
  return `<section class="ma11-card ma11-history-warning"><header><b>${escapeHtml(labels[recovery.phase] || "正在恢复历史")}</b><span>${escapeHtml(progress)}</span></header><p>${escapeHtml(chatState.lastSyncError || current)}</p></section>`;
}

