interface PositionedGraphNode extends GraphNode {
  x: number;
  y: number;
}

function graphNodePositions(graph: RelationshipGraph): PositionedGraphNode[] {
  const width = 1000;
  const height = 680;
  const center = { x: width / 2, y: height / 2 };
  const groups = new Map<string, GraphNode[]>();
  for (const node of graph.nodes) {
    const key =
      node.type === "focus"
        ? "focus"
        : node.type === "character"
          ? "character"
          : node.type === "relationship"
            ? "relationship"
            : "world";
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key)!.push(node);
  }
  const output: PositionedGraphNode[] = [];
  const focus = groups.get("focus") ?? [];
  focus.forEach((node, index) =>
    output.push({ ...node, x: center.x + index * 56, y: center.y }),
  );
  const ring = (key: string, radiusX: number, radiusY: number, offset = 0) => {
    const nodes = groups.get(key) ?? [];
    nodes.forEach((node, index) => {
      const angle = offset + (Math.PI * 2 * index) / Math.max(nodes.length, 1);
      output.push({
        ...node,
        x: center.x + Math.cos(angle) * radiusX,
        y: center.y + Math.sin(angle) * radiusY,
      });
    });
  };
  ring("character", 250, 185, -Math.PI / 2);
  ring("relationship", 365, 250, Math.PI / 6);
  ring("world", 455, 300, 0);
  if (!focus.length && output.length) {
    output[0].x = center.x;
    output[0].y = center.y;
  }
  return output;
}

function graphTypeLabel(type: GraphNode["type"]): string {
  const labels: Record<GraphNode["type"], string> = {
    focus: "焦点",
    character: "人物",
    relationship: "关系",
    item: "物品",
    event: "事件",
    region: "区域",
  };
  return labels[type];
}

function graphLifecycleClass(node: GraphNode): string {
  if (node.existence === "死亡已确认") return "dead";
  if (node.existence === "存在未知" || node.existence === "身份存疑" || node.existence === "失踪") return "uncertain";
  if (node.activity === "已归档") return "archived";
  if (node.activity === "长期休眠") return "long-dormant";
  if (node.activity === "休眠") return "dormant";
  return "";
}

function graphHtml(artifactInfo: ReturnType<typeof currentArtifact>): string {
  const settings = getSettings();
  const snapshot = artifactInfo?.artifact.snapshot;
  const graph = buildRelationshipGraph(snapshot, settings.ui.graphScope, settings.tableRegistry);
  const positioned = graphNodePositions(graph);
  const positions = new Map(positioned.map((node) => [node.id, node]));
  const selected =
    positioned.find((node) => node.id === selectedGraphNodeId) ?? positioned[0];
  if (selected && !selectedGraphNodeId) selectedGraphNodeId = selected.id;
  const zoom = clampGraphZoom(settings.ui.graphZoom);
  settings.ui.graphZoom = zoom;
  const edgeSvg = graph.edges
    .map((edge) => {
      const source = positions.get(edge.source);
      const target = positions.get(edge.target);
      if (!source || !target) return "";
      const mx = (source.x + target.x) / 2;
      const my = (source.y + target.y) / 2;
      return `<g class="ma11-graph-edge"><line x1="${source.x}" y1="${source.y}" x2="${target.x}" y2="${target.y}"><title>${escapeHtml(`${edge.label}：${edge.detail}`)}</title></line>${graph.edges.length <= 18 ? `<text x="${mx}" y="${my}">${escapeHtml(edge.label)}</text>` : ""}</g>`;
    })
    .join("");
  const nodeSvg = positioned
    .map(
      (node) =>
        `<g class="ma11-graph-node ${node.type} ${graphLifecycleClass(node)} ${selected?.id === node.id ? "selected" : ""}" data-ma11-graph-node="${escapeHtml(node.id)}" transform="translate(${node.x} ${node.y})" tabindex="0" role="button"><circle r="34"></circle><text text-anchor="middle" y="4">${escapeHtml(node.label.length > 10 ? `${node.label.slice(0, 9)}…` : node.label)}</text><title>${escapeHtml(`${node.label}\n${node.detail}`)}</title></g>`,
    )
    .join("");
  const graphWidth = Math.round(1000 * zoom);
  const graphHeight = Math.round(680 * zoom);
  return `
    <section class="ma11-toolbar ma11-graph-toolbar">
      <div><h2>对象图谱</h2><p>由当前状态表生成，只读展示，不额外调用模型。</p></div>
      <div class="ma11-graph-toolbar-actions">
        <div class="ma11-segmented"><button class="${settings.ui.graphScope === "relations" ? "active" : ""}" data-ma11-graph-scope="relations">人物关系</button><button class="${settings.ui.graphScope === "world" ? "active" : ""}" data-ma11-graph-scope="world">全局网络</button></div>
        <div class="ma11-graph-zoom" aria-label="图谱缩放">
          <button type="button" data-ma11-graph-zoom="out" title="缩小">−</button>
          <input type="range" min="50" max="250" step="5" value="${Math.round(zoom * 100)}" data-ma11-graph-zoom-range aria-label="缩放比例" />
          <button type="button" data-ma11-graph-zoom="in" title="放大">＋</button>
          <button type="button" data-ma11-graph-zoom="reset">100%</button>
          <button type="button" data-ma11-graph-zoom="fit">适应</button>
          <output>${Math.round(zoom * 100)}%</output>
        </div>
      </div>
    </section>
    ${graph.nodes.length ? `<section class="ma11-graph-layout"><div class="ma11-graph-canvas"><svg viewBox="0 0 1000 680" width="${graphWidth}" height="${graphHeight}" style="width:${graphWidth}px;height:${graphHeight}px" preserveAspectRatio="xMidYMid meet" aria-label="镜渊对象图谱">${edgeSvg}${nodeSvg}</svg></div><aside class="ma11-graph-detail">${selected ? `<span class="ma11-graph-type ${selected.type}">${escapeHtml(graphTypeLabel(selected.type))}</span><h3>${escapeHtml(selected.label)}</h3><p>${escapeHtml(selected.detail || "暂无详细记录")}</p><dl><dt>状态</dt><dd>${escapeHtml(selected.status || "未标注")}</dd>${selected.existence ? `<dt>存在</dt><dd>${escapeHtml(selected.existence)}</dd>` : ""}${selected.activity ? `<dt>活跃</dt><dd>${escapeHtml(selected.activity)}</dd>` : ""}${selected.memory ? `<dt>记忆</dt><dd>${escapeHtml(selected.memory)}</dd>` : ""}</dl>` : '<p class="ma11-empty">点击节点查看详情。</p>'}</aside></section>` : '<section class="ma11-empty-panel">当前状态表没有可绘制的关系节点。先在“人物”和“关系”表中生成或添加记录。</section>'}`;
}

