async function renderWorkspace(): Promise<void> {
  const workspace = document.querySelector<HTMLElement>("#ma11-workspace");
  if (!workspace || workspace.hidden) return;
  if (rendering) {
    renderAgain = true;
    return;
  }
  rendering = true;
  const renderChatKey = currentChatKey();
  try {
    const settings = getSettings();
    const info = currentArtifact();
    workspace
      .querySelectorAll<HTMLElement>("[data-ma11-tab]")
      .forEach((button) =>
        button.classList.toggle(
          "active",
          button.dataset.ma11Tab === settings.ui.activeTab,
        ),
      );
    let html = "";
    if (settings.ui.activeTab === "overview") html = await overviewHtml(info);
    if (settings.ui.activeTab === "tables") html = await tableHtml(info);
    if (settings.ui.activeTab === "tableManager") html = tableManagerHtml(info);
    if (settings.ui.activeTab === "graph") html = graphHtml(info);
    if (settings.ui.activeTab === "summaries") html = await summariesHtml();
    if (settings.ui.activeTab === "audit") html = auditHtml();
    if (settings.ui.activeTab === "sync") html = await syncHtml();
    if (settings.ui.activeTab === "settings") html = settingsHtml();
    if (settings.ui.activeTab === "diagnostics") html = await diagnosticsHtml();
    if (!workspace.isConnected || currentChatKey() !== renderChatKey) {
      renderAgain = true;
      return;
    }
    const content = workspace.querySelector<HTMLElement>("#ma11-workspace-content");
    if (content) content.innerHTML = html;
  } catch (error) {
    if (currentChatKey() !== renderChatKey) {
      renderAgain = true;
      return;
    }
    const message = toErrorMessage(error);
    const content = workspace.querySelector<HTMLElement>("#ma11-workspace-content");
    if (content) {
      content.innerHTML = `<section class="ma11-card"><header><b>界面加载失败</b></header><p class="ma11-message-error">${escapeHtml(message)}</p><div class="ma11-actions"><button data-ma11-action="refresh-diagnostics">重新加载</button></div></section>`;
    }
    console.error("[MirrorAbyss] workspace render failed", error);
  } finally {
    rendering = false;
    if (renderAgain) {
      renderAgain = false;
      queueMicrotask(() => void renderWorkspace());
    }
  }
}

function setTab(tab: any): void {
  const settings = getSettings();
  settings.ui.activeTab = tab;
  saveSettings();
  void renderWorkspace();
}

function editableArtifact(): { index: number; artifact: MessageArtifact & { snapshot: StateSnapshot } } {
  if (!getSettings().enabled) throw new Error("镜渊已关闭，请先启用");
  if (editorChatKey && currentChatKey() !== editorChatKey) {
    throw new Error("聊天已切换，本次编辑不再保存");
  }
  const info = currentArtifact();
  const latest = latestSnapshotArtifact();
  if (!info?.artifact.snapshot || !latest || info.artifact.messageKey !== latest.artifact.messageKey) {
    throw new Error("历史状态表只读，只能编辑最新成功状态表");
  }
  if (editorMessageKey && info.artifact.messageKey !== editorMessageKey) {
    throw new Error("编辑目标已经变化，请重新打开编辑器");
  }
  assertArtifactCommitCurrent(info.artifact);
  return info as { index: number; artifact: MessageArtifact & { snapshot: StateSnapshot } };
}

function openRowEditor(tableKey: TableKey, row?: StateRow): void {
  const info = currentArtifact();
  editorChatKey = currentChatKey();
  editorMessageKey = info?.artifact.messageKey ?? null;
  const workspace = root();
  const backdrop = workspace.querySelector<HTMLElement>(
    ".ma11-editor-backdrop",
  )!;
  const form = workspace.querySelector<HTMLFormElement>("#ma11-row-editor")!;
  const tableDefinition = tableByKey(getSettings().tableRegistry, tableKey);
  if (tableDefinition) {
    const labels = {
      title: customizedFieldLabel(tableDefinition, "title", "对象"),
      content: customizedFieldLabel(tableDefinition, "content", "当前事实"),
      status: customizedFieldLabel(tableDefinition, "status", "状态"),
      keywords: `${customizedFieldLabel(tableDefinition, "keywords", "关键词")}（逗号分隔）`,
    };
    for (const [fieldKey, label] of Object.entries(labels)) {
      const target = form.querySelector<HTMLElement>(`[data-ma11-row-field-label="${fieldKey}"]`);
      if (target) target.textContent = label;
    }
  }
  (form.elements.namedItem("tableKey") as HTMLInputElement).value = tableKey;
  (form.elements.namedItem("rowId") as HTMLInputElement).value = row?.id || "";
  (form.elements.namedItem("title") as HTMLInputElement).value =
    row?.title || "";
  (form.elements.namedItem("content") as HTMLTextAreaElement).value =
    row?.content || "";
  (form.elements.namedItem("status") as HTMLInputElement).value =
    row?.status || "active";
  (form.elements.namedItem("keywords") as HTMLInputElement).value =
    row?.keywords.join(", ") || "";
  (form.elements.namedItem("locked") as HTMLInputElement).checked = row?.locked ?? false;
  const objectFields = row?.fields ?? {};
  const setList = (name: string, value: unknown) => {
    (form.elements.namedItem(name) as HTMLTextAreaElement).value = Array.isArray(value) ? value.join("\n") : String(value ?? "");
  };
  setList("baseContent", objectFields.baseContent);
  setList("solidifiedHistory", objectFields.solidifiedHistory);
  setList("currentStates", objectFields.currentStates);
  setList("relatedObjects", objectFields.relatedObjects);
  setList("relatedEvents", objectFields.relatedEvents);
  setList("relationshipStates", objectFields.relationshipStates);
  setList("abilityStates", objectFields.abilityStates);
  const lifecycleFields = form.querySelector<HTMLElement>("[data-ma11-lifecycle-fields]");
  const supportsLifecycle = ["characters", "state"].includes(tableDefinition?.role || "");
  const characterObjectFields = form.querySelector<HTMLElement>("[data-ma11-character-object-fields]");
  if (characterObjectFields) characterObjectFields.hidden = !supportsLifecycle;
  if (lifecycleFields) lifecycleFields.hidden = !supportsLifecycle;
  if (supportsLifecycle) {
    const life = row?.lifecycle;
    (form.elements.namedItem("existence") as HTMLSelectElement).value = life?.existence || "未标注";
    (form.elements.namedItem("activity") as HTMLSelectElement).value = life?.activity || "未标注";
    (form.elements.namedItem("memory") as HTMLSelectElement).value = life?.memory || "未标注";
    (form.elements.namedItem("evidenceLevel") as HTMLSelectElement).value = life?.evidenceLevel || "未知";
    (form.elements.namedItem("evidence") as HTMLTextAreaElement).value = life?.evidence || "";
    (form.elements.namedItem("returnConditions") as HTMLTextAreaElement).value = life?.returnConditions.join("\n") || "";
    (form.elements.namedItem("returnBlockers") as HTMLTextAreaElement).value = life?.returnBlockers.join("\n") || "";
  }
  backdrop.hidden = false;
  (form.elements.namedItem("title") as HTMLInputElement).focus();
}

function closeEditor(): void {
  const workspace = document.querySelector<HTMLElement>("#ma11-workspace");
  const backdrop = workspace?.querySelector<HTMLElement>(
    ".ma11-editor-backdrop",
  );
  if (backdrop) backdrop.hidden = true;
  editorChatKey = null;
  editorMessageKey = null;
}

async function saveRow(form: HTMLFormElement): Promise<void> {
  const info = editableArtifact();
  const tableKey = (form.elements.namedItem("tableKey") as HTMLInputElement)
    .value as TableKey;
  const rowId = (form.elements.namedItem("rowId") as HTMLInputElement).value;
  const title = (
    form.elements.namedItem("title") as HTMLInputElement
  ).value.trim();
  const content = (
    form.elements.namedItem("content") as HTMLTextAreaElement
  ).value.trim();
  const status = (
    form.elements.namedItem("status") as HTMLInputElement
  ).value.trim();
  const keywords = (
    form.elements.namedItem("keywords") as HTMLInputElement
  ).value
    .split(/[,，]/)
    .map((item) => item.trim())
    .filter(Boolean);
  const locked = (form.elements.namedItem("locked") as HTMLInputElement).checked;
  const supportsLifecycle = ["characters", "state"].includes(tableByKey(getSettings().tableRegistry, tableKey)?.role || "");
  const listFrom = (name: string) => (form.elements.namedItem(name) as HTMLTextAreaElement).value
    .split(/\n|[；;]/)
    .map((item) => item.trim())
    .filter(Boolean);
  const lifecycle = supportsLifecycle ? {
    existence: (form.elements.namedItem("existence") as HTMLSelectElement).value as any,
    activity: (form.elements.namedItem("activity") as HTMLSelectElement).value as any,
    memory: (form.elements.namedItem("memory") as HTMLSelectElement).value as any,
    evidenceLevel: (form.elements.namedItem("evidenceLevel") as HTMLSelectElement).value as any,
    evidence: (form.elements.namedItem("evidence") as HTMLTextAreaElement).value.trim(),
    returnConditions: listFrom("returnConditions"),
    returnBlockers: listFrom("returnBlockers"),
  } : undefined;
  const fields: Record<string, unknown> = {
    baseContent: (form.elements.namedItem("baseContent") as HTMLTextAreaElement).value.trim(),
    solidifiedHistory: listFrom("solidifiedHistory"),
    currentStates: listFrom("currentStates"),
    relatedObjects: listFrom("relatedObjects"),
    relatedEvents: listFrom("relatedEvents"),
  };
  if (supportsLifecycle) {
    fields.relationshipStates = listFrom("relationshipStates");
    fields.abilityStates = listFrom("abilityStates");
  }
  // 未勾选“完全锁定”时写成 base 锁：玩家基础保留，后续明确事实仍可更新 currentStates 等可变层。
  info.artifact.snapshot = upsertManualRow(info.artifact.snapshot, tableKey, {
    id: rowId || undefined,
    title,
    content,
    status,
    keywords,
    locked,
    lockMode: locked ? "all" : "base",
    lifecycle,
    fields,
  }, getSettings().tableRegistry);
  const message = getMessage(info.index);
  if (message) attachArtifactToMessage(message, info.artifact);
  await putArtifact(info.artifact);
  await persistChatFor(info.artifact.chatKey);
  assertArtifactCommitCurrent(info.artifact);
  if (getSettings().lorebookSync) await retryStage(info.index, "sync");
  closeEditor();
  await renderWorkspace();
}

async function deleteRowAction(rowId: string): Promise<void> {
  const info = editableArtifact();
  const tableKey = getSettings().ui.activeTable;
  if (!confirm("确定删除这条状态吗？")) return;
  info.artifact.snapshot = deleteRow(info.artifact.snapshot, tableKey, rowId, getSettings().tableRegistry);
  const chatState = await getChatState(info.artifact.chatKey);
  if (chatState.focusObjectId === rowId) {
    chatState.focusObjectId = undefined;
    await putChatState(chatState);
  }
  const message = getMessage(info.index);
  if (message) attachArtifactToMessage(message, info.artifact);
  await putArtifact(info.artifact);
  await persistChatFor(info.artifact.chatKey);
  assertArtifactCommitCurrent(info.artifact);
  if (getSettings().lorebookSync) await retryStage(info.index, "sync");
  await renderWorkspace();
}

async function updateTableRegistryAndSync(registry: TableDefinition[]): Promise<void> {
  const settings = getSettings();
  settings.tableRegistry = normalizeTableRegistry(registry);
  const active = enabledTables(settings.tableRegistry);
  if (!active.some((table) => table.key === settings.ui.activeTable)) settings.ui.activeTable = active[0]?.key || "";
  settings.migration.dynamicTablesV23 = true;
  saveSettings();
  renderAllMessagePanels();
  const latest = latestSnapshotArtifact();
  if (settings.lorebookSync && latest && !((await getChatState(latest.artifact.chatKey)).historyInvalidation)) {
    try { await retryStage(latest.index, "sync"); }
    catch (error) { toast("warning", `表格设置已保存，但世界书刷新失败：${toErrorMessage(error)}`); }
  }
  await renderWorkspace();
}

function valueFromWorkspace(workspace: HTMLElement, selector: string): string {
  return workspace.querySelector<HTMLInputElement | HTMLTextAreaElement>(selector)?.value.trim() || "";
}

function updateSetting(
  target: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
): void {
  const key = target.dataset.ma11Setting;
  if (!key) return;
  const settings: any = getSettings();
  const value =
    target instanceof HTMLInputElement && target.type === "checkbox"
      ? target.checked
      : target instanceof HTMLInputElement && target.type === "number"
        ? Number(target.value)
        : target.value;
  settings[key] = value;
  saveSettings();
  if (key === "enabled") {
    setRequestAcceptance(Boolean(value));
    taskQueue.setAccepting(Boolean(value));
    if (!value) abortActiveRequests();
    const quick = document.querySelector<HTMLInputElement>('[data-ma11-quick-setting="enabled"]');
    if (quick) quick.checked = Boolean(value);
    renderAllMessagePanels();
    void renderWorkspace();
  }
  if (key === "showMessagePanel") renderAllMessagePanels();
  if (key === "lorebookLayout") void renderWorkspace();
}

function updateConnection(
  target: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement,
): void {
  const modeTask = target.dataset.ma11ConnectionMode as TaskKind | undefined;
  const profileTask = target.dataset.ma11ConnectionProfileId as TaskKind | undefined;
  const settings = getSettings();
  let shouldRender = false;
  if (modeTask) {
    settings.connections[modeTask].mode = target.value as any;
    shouldRender = true;
  }
  if (profileTask) {
    settings.connections[profileTask].profileId = safeText(target.value, 160).trim();
    const selected = connectionProfiles().find((profile) => profile.id === settings.connections[profileTask].profileId);
    settings.connections[profileTask].profile = selected?.name || '';
  }
  saveSettings();
  if (shouldRender) void renderWorkspace();
}

function bindWorkspace(workspace: HTMLElement): void {
  workspace.addEventListener("click", async (event) => {
    const target = event.target as HTMLElement;
    const tab = target.closest<HTMLElement>("[data-ma11-tab]")?.dataset.ma11Tab;
    if (tab) return setTab(tab);
    const action =
      target.closest<HTMLElement>("[data-ma11-action]")?.dataset.ma11Action;
    const actionButton = action ? target.closest<HTMLButtonElement>("[data-ma11-action]") : null;
    const testButton = target.closest<HTMLButtonElement>("[data-ma11-test]");
    const busyButton = actionButton ?? testButton;
    const originalButtonText = busyButton?.textContent ?? "";
    try {
      if (busyButton && !["close", "open-tables", "open-graph", "close-editor"].includes(action || "")) {
        busyButton.disabled = true;
        busyButton.setAttribute("aria-busy", "true");
        busyButton.textContent = "处理中…";
      }
      if (action === "close") workspace.hidden = true;
      if (action === "open-tables") setTab("tables");
      if (action === "open-graph") setTab("graph");
      if (action === "open-table-manager") setTab("tableManager");
      if (action === "process-latest") {
        if (!getSettings().enabled) throw new Error("镜渊已关闭，请先启用");
        const index = latestAssistantIndex();
        if (index < 0) throw new Error("没有可整理的AI正文");
        selectedMessageIndex = index;
        await processMessage(index, false);
        await renderWorkspace();
      }
      if (action === "recalculate-history") {
        const state = await getChatState(currentChatKey());
        if (state.historyInvalidation?.startIndex === undefined) {
          const answer = window.prompt(`请输入重算起点（1-${Math.max(1, getChat().length)}）`, "1");
          if (answer === null) return;
          const start = Number(answer);
          if (!Number.isInteger(start) || start < 1 || start > Math.max(1, getChat().length)) {
            throw new Error("重算起点必须是当前聊天范围内的消息序号");
          }
          await chooseHistoryRecalculationStart(start - 1);
        }
        await recalculateInvalidatedHistory();
        selectedMessageIndex = null;
        await renderWorkspace();
      }
      const stageCommand = action ? resolveWorkspaceStageCommand(action) : null;
      if (stageCommand?.kind === "retry") {
        const index = latestAssistantIndex();
        if (index < 0) throw new Error("没有可处理的AI正文");
        selectedMessageIndex = index;
        await retryStage(index, stageCommand.stage);
        await renderWorkspace();
      }
      if (stageCommand?.kind === "summary") {
        const info = latestSnapshotArtifact();
        if (!info) throw new Error("尚无可总结的状态");
        await forceSummary(info.index, stageCommand.summary);
        await renderWorkspace();
      }
      if (action === "retry-sync") {
        const info = latestSnapshotArtifact();
        if (!info) throw new Error("尚无可同步的状态");
        if (getSettings().lorebookLayout === "semantic") {
          const preview = await previewLorebookMaintenance(info.index);
          const warning = [
            `检测到 ${preview.legacyCandidates} 个历史候选，其中 ${preview.removable} 个可安全处理。`,
            `将保留 ${preview.protectedForeign} 个其他聊天条目和 ${preview.protectedUnknown} 个共享书 owner 未知条目。`,
            "是否继续清理并重新发布？",
          ].join("\n");
          if (!window.confirm(warning)) return;
          await applyLorebookMaintenance(info.index);
        } else {
          await retryStage(info.index, "sync");
        }
        await renderWorkspace();
      }
      const tableDefinitionKey = actionButton?.dataset.ma11TableKey || "";
      if (action === "create-table") {
        const name = valueFromWorkspace(workspace, "[data-ma11-new-table-name]");
        const purpose = valueFromWorkspace(workspace, "[data-ma11-new-table-purpose]");
        const fields = valueFromWorkspace(workspace, "[data-ma11-new-table-fields]");
        if (!name) throw new Error("请填写表格名称");
        await updateTableRegistryAndSync(createCustomTable(getSettings().tableRegistry, name, purpose, fields));
        toast("success", "自定义表格已新增，将从下一次状态提取开始生效");
      }
      if (action === "save-table" && tableDefinitionKey) {
        const name = valueFromWorkspace(workspace, `[data-ma11-table-name="${tableDefinitionKey}"]`);
        const purpose = valueFromWorkspace(workspace, `[data-ma11-table-purpose="${tableDefinitionKey}"]`);
        const headers = valueFromWorkspace(workspace, `[data-ma11-table-headers="${tableDefinitionKey}"]`);
        const fields = valueFromWorkspace(workspace, `[data-ma11-table-fields="${tableDefinitionKey}"]`);
        if (!name || !purpose) throw new Error("表格名称和用途说明不能为空");
        let registry = updateTableDefinition(getSettings().tableRegistry, tableDefinitionKey, { name, purpose });
        registry = updateTableHeaders(registry, tableDefinitionKey, headers);
        registry = updateTableFields(registry, tableDefinitionKey, fields);
        await updateTableRegistryAndSync(registry);
        toast("success", "表格定义已更新，将从下一次状态提取开始生效");
      }
      if (action === "move-table-up" && tableDefinitionKey) await updateTableRegistryAndSync(moveTableDefinition(getSettings().tableRegistry, tableDefinitionKey, -1));
      if (action === "move-table-down" && tableDefinitionKey) await updateTableRegistryAndSync(moveTableDefinition(getSettings().tableRegistry, tableDefinitionKey, 1));
      if (action === "delete-table" && tableDefinitionKey) {
        const definition = tableByKey(getSettings().tableRegistry, tableDefinitionKey);
        const warning = definition?.isDefault
          ? `确定删除默认视图“${definition.name}”吗？只会删除可见视图，不会删除内部事实、事件线、小总结、大总结或历史重建数据。`
          : `确定删除自定义视图“${definition?.name || tableDefinitionKey}”吗？内部事实和总结不会删除。`;
        if (window.confirm(warning)) await updateTableRegistryAndSync(removeTableDefinition(getSettings().tableRegistry, tableDefinitionKey));
      }
      if (action === "restore-default-tables") {
        if (window.confirm("恢复默认八表会替换当前表格注册表；自定义视图将退出，但内部事实、总结和人工世界书条目不会删除。是否继续？")) {
          await updateTableRegistryAndSync(restoreDefaultTableRegistry());
          toast("success", "已恢复默认八表");
        }
      }
      if (action === "set-focus" || action === "clear-focus") {
        const rowId = actionButton?.dataset.ma11FocusRow || "";
        const info = latestSnapshotArtifact();
        if (!info?.artifact.snapshot) throw new Error("尚无可设置焦点的角色视图");
        const registry = normalizeTableRegistry(getSettings().tableRegistry);
        const characterTable = registry.find((table) => ["characters", "state"].includes(table.role));
        if (!characterTable) throw new Error("当前没有角色视图");
        const row = (info.artifact.snapshot[characterTable.key] ?? []).find((item) => item.id === rowId);
        if (action === "set-focus" && !row) throw new Error("焦点目标不是当前角色条目");
        const state = await getChatState(info.artifact.chatKey);
        // 焦点只是聊天级 constant 开关：不写角色正文、不改状态、不触发任何模型任务。
        state.focusObjectId = action === "set-focus" ? rowId : undefined;
        await putChatState(state);
        if (getSettings().lorebookSync) await retryStage(info.index, "sync");
        toast("success", action === "set-focus" ? `已将“${row?.title || "角色"}”设为唯一常驻焦点` : "已取消常驻焦点");
        await renderWorkspace();
      }
      if (action === "add-row") openRowEditor(getSettings().ui.activeTable);
      if (action === "close-editor") closeEditor();
      if (action === "refresh-diagnostics") await renderWorkspace();
      if (action === "copy-diagnostics") {
        const report = await diagnosticReport();
        await navigator.clipboard.writeText(JSON.stringify(report, null, 2));
        toast("success", "诊断信息已复制");
      }
      if (action === "restart-plugin") {
        const restart = (globalThis as any).MirrorAbyss?.restart;
        if (typeof restart !== "function") throw new Error("插件重置入口不可用");
        toast("info", "正在重置镜渊插件…");
        await restart();
        return;
      }
      if (action === "reset-current-game") {
        if (!window.confirm("这会删除当前聊天的镜渊表格、总结、审核记录和镜渊世界书条目。其他聊天和插件设置不受影响。是否继续？")) return;
        if (!window.confirm("请再次确认：重置后只能重新调用模型整理当前聊天，无法自动恢复。")) return;
        const result = await resetCurrentGame();
        resetWorkspaceContext();
        renderAllMessagePanels();
        toast("success", `当前游戏已重置：清除 ${result.messages} 条消息记录、${result.lorebookEntries} 个世界书条目`);
        await renderWorkspace();
      }
      const graphScope = target.closest<HTMLElement>("[data-ma11-graph-scope]")
        ?.dataset.ma11GraphScope as "relations" | "world" | undefined;
      if (graphScope) {
        getSettings().ui.graphScope = graphScope;
        selectedGraphNodeId = null;
        saveSettings();
        await renderWorkspace();
      }
      const graphZoomAction = target.closest<HTMLElement>("[data-ma11-graph-zoom]")
        ?.dataset.ma11GraphZoom;
      if (graphZoomAction) {
        const settings = getSettings();
        const current = clampGraphZoom(settings.ui.graphZoom);
        if (graphZoomAction === "in") settings.ui.graphZoom = clampGraphZoom(current + 0.15);
        if (graphZoomAction === "out") settings.ui.graphZoom = clampGraphZoom(current - 0.15);
        if (graphZoomAction === "reset") settings.ui.graphZoom = 1;
        if (graphZoomAction === "fit") {
          const canvas = workspace.querySelector<HTMLElement>(".ma11-graph-canvas");
          const availableWidth = Math.max(320, canvas?.clientWidth || 760);
          const availableHeight = Math.max(280, canvas?.clientHeight || 560);
          settings.ui.graphZoom = clampGraphZoom(Math.min(availableWidth / 1000, availableHeight / 680));
        }
        saveSettings();
        await renderWorkspace();
      }
      const graphNodeId = target.closest<HTMLElement>("[data-ma11-graph-node]")
        ?.dataset.ma11GraphNode;
      if (graphNodeId) {
        selectedGraphNodeId = graphNodeId;
        await renderWorkspace();
      }
      const table = target.closest<HTMLElement>("[data-ma11-table]")?.dataset
        .ma11Table as TableKey | undefined;
      if (table) {
        getSettings().ui.activeTable = table;
        saveSettings();
        await renderWorkspace();
      }
      const editId = target.closest<HTMLElement>("[data-ma11-edit-row]")
        ?.dataset.ma11EditRow;
      if (editId) {
        const info = currentArtifact();
        const key = getSettings().ui.activeTable;
        const row = info?.artifact.snapshot?.[key].find(
          (item) => item.id === editId,
        );
        if (row) openRowEditor(key, row);
      }
      const deleteId = target.closest<HTMLElement>("[data-ma11-delete-row]")
        ?.dataset.ma11DeleteRow;
      if (deleteId) await deleteRowAction(deleteId);
      const testTask = target.closest<HTMLElement>("[data-ma11-test]")?.dataset
        .ma11Test as TaskKind | undefined;
      if (testTask) {
        const result = await testConnection(testTask);
        const schemaLabels: Record<string, string> = {
          supported: "Schema直接成功",
          "cached-bypass": "Schema已按缓存绕过",
          "rejected-fallback": "Schema请求被拒后普通JSON成功",
          "empty-fallback": "Schema返回空对象后普通JSON成功",
          "transient-fallback": "Schema临时故障后普通JSON成功",
          "plain-only": "仅普通JSON",
        };
        const schemaDetail = schemaLabels[result.schemaStatus] || result.schemaStatus;
        const detail = `${result.method}；耗时${result.elapsedMs}ms；连接${result.connected ? "成功" : "失败"}；${schemaDetail}；JSON${result.jsonValid ? "有效" : "无效"}；精确遵循${result.instructionFollowed ? "通过" : "未通过"}`;
        const diagnostic = result.schemaDetail ? `；Schema诊断：${result.schemaDetail}` : "";
        toast(result.instructionFollowed ? "success" : "warning", result.instructionFollowed ? `${detail}${diagnostic}` : `${detail}${diagnostic}；返回：${result.responsePreview}`);
      }
    } catch (error) {
      toast("error", toErrorMessage(error));
    } finally {
      if (busyButton?.isConnected) {
        busyButton.disabled = false;
        busyButton.removeAttribute("aria-busy");
        busyButton.textContent = originalButtonText;
      }
    }
  });

  workspace.addEventListener("change", (event) => {
    const target = event.target as
      HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement;
    if (target.dataset.ma11Setting) updateSetting(target);
    if (target.dataset.ma11RecallSetting) {
      const key = target.dataset.ma11RecallSetting as keyof ReturnType<typeof getSettings>["lorebookRecall"];
      const value = Number(target.value);
      (getSettings().lorebookRecall as any)[key] = value;
      saveSettings();
    }
    if (target.dataset.ma11TableEnabled) {
      const key = target.dataset.ma11TableEnabled;
      void updateTableRegistryAndSync(updateTableDefinition(getSettings().tableRegistry, key, { enabled: target.checked }))
        .catch((error) => toast("error", toErrorMessage(error)));
    }
    if (
      target.dataset.ma11ConnectionMode ||
      target.dataset.ma11ConnectionProfileId
    ) updateConnection(target);
  });
  workspace.addEventListener("input", (event) => {
    const target = event.target as HTMLInputElement | HTMLTextAreaElement;
    if (target.dataset.ma11GraphZoomRange !== undefined) {
      getSettings().ui.graphZoom = clampGraphZoom(Number(target.value) / 100);
      saveSettings();
      const output = workspace.querySelector<HTMLOutputElement>(".ma11-graph-zoom output");
      if (output) output.value = `${Math.round(getSettings().ui.graphZoom * 100)}%`;
      const svg = workspace.querySelector<SVGElement>(".ma11-graph-canvas svg");
      if (svg) {
        const zoom = getSettings().ui.graphZoom;
        svg.setAttribute("width", String(Math.round(1000 * zoom)));
        svg.setAttribute("height", String(Math.round(680 * zoom)));
        svg.setAttribute("style", `width:${Math.round(1000 * zoom)}px;height:${Math.round(680 * zoom)}px`);
      }
      return;
    }
    if (
      target.dataset.ma11Setting === "auditPrompt" ||
      target.dataset.ma11Setting === "revisionPrompt" ||
      target.dataset.ma11Setting === "lorebookName"
    )
      updateSetting(target);
    if (target.dataset.ma11ConnectionProfileId) updateConnection(target);
  });
  workspace
    .querySelector<HTMLFormElement>("#ma11-row-editor")
    ?.addEventListener("submit", (event) => {
      event.preventDefault();
      if (savingRow) return;
      savingRow = true;
      const form = event.currentTarget as HTMLFormElement;
      const submit = form.querySelector<HTMLButtonElement>('button[type="submit"]');
      if (submit) {
        submit.disabled = true;
        submit.textContent = "保存中…";
      }
      void saveRow(form)
        .catch((error) => toast("error", toErrorMessage(error)))
        .finally(() => {
          savingRow = false;
          if (submit?.isConnected) {
            submit.disabled = false;
            submit.textContent = "保存";
          }
        });
    });
}

export function openWorkspace(tab?: any, messageIndex?: number): void {
  const workspace = root();
  if (Number.isInteger(messageIndex))
    selectedMessageIndex = Number(messageIndex);
  if (tab) getSettings().ui.activeTab = tab;
  workspace.hidden = false;
  void renderWorkspace();
}

export function closeWorkspace(): void {
  const workspace = document.querySelector<HTMLElement>("#ma11-workspace");
  if (workspace) workspace.hidden = true;
}

export function resetWorkspaceContext(): void {
  selectedMessageIndex = null;
  selectedGraphNodeId = null;
  closeEditor();
}

export function disposeWorkspace(): void {
  resetWorkspaceContext();
  queueUnsubscribe?.();
  queueUnsubscribe = null;
  savingRow = false;
  renderAgain = false;
  document.querySelector("#ma11-workspace")?.remove();
}

export function refreshWorkspace(): void {
  void renderWorkspace();
}
