/**
 * 模块职责：按 event_id 消费内部事实生成小总结，并仅消费未固化小总结生成大总结。
 * 维护边界：失败不破坏核心事实；同一事实和小总结不得重复消费。
 */
import { getSettings } from '../core/context';
import { assertArtifactCommitCurrent, persistChatFor } from '../core/commit-guard';
import { nowIso, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { markFactsConsumed, markFactsSolidified, pendingFactsByEvent } from '../domain/internal-facts';
import { normalizeTableRegistry } from '../domain/table-registry';
import { normalizeSummary } from '../domain/summary';
import { applySedimentation, deriveEventSedimentationPlan } from '../domain/sedimentation';
import { generateStructuredTask } from '../llm/structured';
import { largeSummaryPrompt, largeSummarySystemPrompt, smallSummaryBatchPrompt, smallSummarySystemPrompt } from '../prompts/summary';
import { getChatState, putArtifact, putChatState } from '../storage/repository';
import type { InternalFact, MessageArtifact, StateRow, StateSnapshot, SummaryArtifact } from '../types';

function eventClosed(facts: InternalFact[]): boolean {
  if (!facts.length) return false;
  // 内部事实按首次出现顺序保存，更新时 updatedAt 前移。以最后一次事件状态信号为准：
  // 旧阶段已结束但后续阶段仍活跃时不能关闭；后续明确结果可以覆盖早期“胜负未定”等旧未决表述。
  const latest = facts.reduce((selected, fact, index) => {
    const selectedTime = Date.parse(selected.fact.updatedAt) || 0;
    const factTime = Date.parse(fact.updatedAt) || 0;
    return factTime > selectedTime || (factTime === selectedTime && index > selected.index) ? { fact, index } : selected;
  }, { fact: facts[0], index: 0 }).fact;
  const settled = !latest.active || /(结束|已解决|已关闭|完成|归档|closed|resolved|ended)/i.test(latest.status);
  return settled && latest.unresolvedItems.length === 0;
}

function entryToken(value: unknown): string {
  return String(value ?? '').normalize('NFKC').toLowerCase().replace(/[\s·•._—–\-|｜:：()（）【】\[\]]+/g, '');
}

function summaryMemoryText(summary: SummaryArtifact): string {
  const title = String(summary.title || '').trim();
  const body = String(summary.summary || '').trim();
  return title ? `【${title}】${body}` : body;
}

function rowEventIds(row: StateRow): string[] {
  return [...new Set([...(row.eventIds ?? []), String(row.eventId || '').trim()].filter(Boolean))];
}

/**
 * 总结不再发布独立世界书条目，而是把同一事件的近期/历史文本传播回所有真正受影响的对象条目。
 * 删除使用精确旧版本文本，新增只命中 event_id、fact_id 或 related_entities，避免跨线污染。
 */
function applySummaryLayer(
  snapshot: StateSnapshot,
  eventId: string,
  facts: InternalFact[],
  layer: 'recentHistory' | 'solidifiedHistory',
  addText: string,
  removeTexts: string[],
  registryValue: unknown,
): StateSnapshot {
  const registry = normalizeTableRegistry(registryValue);
  const relatedTokens = new Set(facts.flatMap((fact) => fact.relatedEntities).map(entryToken).filter(Boolean));
  const eventTitleTokens = new Set(facts.map((fact) => entryToken(fact.title)).filter(Boolean));
  const factIds = new Set(facts.map((fact) => fact.factId).filter(Boolean));
  const removals = new Set(removeTexts.map((item) => String(item || '').trim()).filter(Boolean));
  const next = structuredClone(snapshot);
  for (const table of registry) {
    for (const row of next[table.key] ?? []) {
      const rowTokens = [entryToken(row.id), entryToken(row.title)].filter(Boolean);
      const linkedByEvent = rowEventIds(row).includes(eventId);
      const linkedByFact = (row.factIds ?? []).some((id) => factIds.has(id));
      const linkedByObject = rowTokens.some((token) => relatedTokens.has(token));
      const linkedEventRow = table.role === 'events' && rowTokens.some((token) => eventTitleTokens.has(token));
      const target = linkedByEvent || linkedByFact || linkedByObject || linkedEventRow;
      // 只允许修改本事件真正关联的条目；完全锁定条目连旧总结迁移也不得自动触碰。
      if (!target || row.locked || row.lockMode === 'all') continue;
      row.fields ||= {};
      const current = Array.isArray(row.fields[layer])
        ? (row.fields[layer] as unknown[]).map((item) => String(item ?? '').trim()).filter(Boolean)
        : [];
      let values = current.filter((item) => !removals.has(item));
      if (addText) values.push(addText);
      values = [...new Set(values)].slice(-40);
      if (JSON.stringify(current) === JSON.stringify(values)) continue;
      row.fields[layer] = values;
      row.updatedAt = nowIso();
    }
  }
  return next;
}
interface PendingSmallEventGroup { eventId: string; facts: InternalFact[]; closed: boolean; messages: number; }

function pendingSmallEventGroups(facts: InternalFact[], threshold: number, force: boolean): PendingSmallEventGroup[] {
  const allByEvent = new Map<string, InternalFact[]>();
  for (const fact of facts) {
    const list = allByEvent.get(fact.eventId) ?? [];
    list.push(fact);
    allByEvent.set(fact.eventId, list);
  }
  return [...pendingFactsByEvent(facts).entries()]
    .map(([eventId, eventFacts]) => ({
      eventId,
      facts: eventFacts,
      closed: eventClosed(allByEvent.get(eventId) ?? eventFacts),
      messages: new Set(eventFacts.flatMap((fact) => fact.sourceMessageIds)).size,
    }))
    // 开放事件只按跨消息进度或明确结束触发；单回合返回很多事实不能被误判为完成了一段事件线。
    .filter((group) => force || group.closed || group.messages >= threshold)
    .sort((a, b) => Number(b.closed) - Number(a.closed) || b.facts.length - a.facts.length || a.eventId.localeCompare(b.eventId));
}

/** 兼容旧调用：仅返回每条事件线当前活动的小总结版本。 */
export function pendingSmallSummaries(small: SummaryArtifact[], large: SummaryArtifact[]): SummaryArtifact[] {
  const consumed = new Set(large.flatMap((item) => item.sourceSummaryIds ?? item.sourceKeys));
  return small.filter((item) => !item.solidifiedByLargeSummaryId && !item.supersededBySmallSummaryId && !consumed.has(item.id));
}

interface PendingLargeEventGroup {
  eventId: string;
  items: SummaryArtifact[];
  latest: SummaryArtifact;
  previousLarge?: SummaryArtifact;
  sourceSummaryIds: string[];
  consumedVersionIds: string[];
  sourceFactIds: string[];
  closed: boolean;
}

function pendingLargeEventGroups(
  small: SummaryArtifact[],
  large: SummaryArtifact[],
  threshold: number,
  force: boolean,
): PendingLargeEventGroup[] {
  const consumed = new Set(large.flatMap((item) => item.sourceSummaryIds ?? item.sourceKeys));
  const groups = new Map<string, SummaryArtifact[]>();
  for (const item of small) {
    if (item.solidifiedByLargeSummaryId || consumed.has(item.id)) continue;
    // 缺 event_id 的旧数据按自身 ID 隔离，绝不因标题相似把不同事件混线。
    const eventId = String(item.eventId || item.id).trim();
    groups.set(eventId, [...(groups.get(eventId) ?? []), item]);
  }
  const minimum = Math.max(1, Math.round(Number(threshold) || 4));
  const output: PendingLargeEventGroup[] = [];
  for (const [eventId, items] of groups) {
    const ordered = items.map((item, index) => ({ item, index })).sort((a, b) =>
      String(a.item.createdAt || '').localeCompare(String(b.item.createdAt || '')) || a.index - b.index,
    ).map(({ item }) => item);
    const latest = [...ordered].reverse().find((item) => !item.supersededBySmallSummaryId) ?? ordered.at(-1)!;
    const closed = latest.eventClosed === true;
    if (!force && !closed && ordered.length < minimum) continue;
    const previousLarge = [...large].reverse().find((item) => item.eventId === eventId || item.eventIds?.includes(eventId));
    output.push({
      eventId,
      items: ordered,
      latest,
      previousLarge,
      // 小总结新版本是累计版本；大总结只直接读取最新版本，但提交后要把整条旧版本链一起标记为已固化。
      sourceSummaryIds: [latest.id],
      consumedVersionIds: ordered.map((item) => item.id),
      sourceFactIds: [...new Set(latest.sourceFactIds ?? latest.sourceKeys)],
      closed,
    });
  }
  return output.sort((a, b) => Number(b.closed) - Number(a.closed)
    || b.items.length - a.items.length
    || a.eventId.localeCompare(b.eventId));
}

export function hasEligibleSmallSummary(facts: InternalFact[], threshold: number): boolean {
  return pendingSmallEventGroups(facts, Math.max(1, Math.round(Number(threshold) || 12)), false).length > 0;
}

export function hasEligibleLargeSummary(small: SummaryArtifact[], large: SummaryArtifact[], threshold: number): boolean {
  return pendingLargeEventGroups(small, large, threshold, false).length > 0;
}

export async function generateSmallSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const threshold = Math.max(1, Math.round(Number(settings.smallSummaryTurns) || 12));
  // 尽量一次处理所有到期事件线；上限只防止极端输入重新撞上网关超时。
  const selected = pendingSmallEventGroups(chatState.internalFacts ?? [], threshold, force).slice(0, 8);
  if (!selected.length) return null;
  const prepared = selected.map((group) => ({
    ...group,
    previous: [...chatState.smallSummaries].reverse().find((item) =>
      item.eventId === group.eventId && !item.solidifiedByLargeSummaryId && !item.supersededBySmallSummaryId,
    ),
  }));
  const parsed = await generateStructuredTask({
    task: 'smallSummary',
    systemPrompt: smallSummarySystemPrompt(),
    prompt: smallSummaryBatchPrompt(prepared.map((group) => ({ eventId: group.eventId, facts: group.facts, previous: group.previous }))),
    structureDescription: '{"summaries":[{"event_id":"...","title":"...","summary":"...","keywords":["..."],"unresolved":["..."]}]}',
    maxTokens: Math.min(2200, 700 + prepared.length * 260),
  } as any);
  assertArtifactCommitCurrent(artifact);
  const rawSummaries = Array.isArray(parsed?.summaries)
    ? parsed.summaries
    : prepared.length === 1 && parsed && typeof parsed === 'object' ? [{ ...parsed, event_id: parsed.event_id || prepared[0].eventId }] : [];
  const byEvent = new Map<string, Record<string, any>>();
  for (const item of rawSummaries) {
    if (!item || typeof item !== 'object') continue;
    const eventId = String((item as any).event_id ?? (item as any).eventId ?? '').trim();
    if (!eventId || byEvent.has(eventId)) continue;
    byEvent.set(eventId, item as Record<string, any>);
  }
  const expected = new Set(prepared.map((group) => group.eventId));
  for (const eventId of expected) if (!byEvent.has(eventId)) throw new Error(`小总结缺少事件线结果：${eventId}`);
  for (const eventId of byEvent.keys()) if (!expected.has(eventId)) throw new Error(`小总结返回未请求事件线：${eventId}`);

  const generated = prepared.map((group) => {
    const newFactIds = group.facts.map((fact) => fact.factId);
    const sourceFactIds = [...new Set([...(group.previous?.sourceFactIds ?? group.previous?.sourceKeys ?? []), ...newFactIds])];
    const summary = normalizeSummary(byEvent.get(group.eventId)!, 'small', sourceFactIds, undefined, { eventId: group.eventId, sourceFactIds });
    summary.previousSmallSummaryId = group.previous?.id;
    summary.eventClosed = group.closed;
    if (!summary.summary) throw new Error(`小总结模型返回空摘要：${group.eventId}`);
    return { group, summary, newFactIds };
  });

  const previousSnapshot = artifact.snapshot ? structuredClone(artifact.snapshot) : undefined;
  const previousFacts = structuredClone(chatState.internalFacts);
  const previousSummaries = structuredClone(chatState.smallSummaries);
  try {
    if (artifact.snapshot) {
      let nextSnapshot = artifact.snapshot;
      for (const { group, summary, newFactIds } of generated) {
        summary.sedimentation = deriveEventSedimentationPlan(
          nextSnapshot,
          group.eventId,
          newFactIds,
          group.closed,
          settings.tableRegistry,
        );
        nextSnapshot = applySedimentation(nextSnapshot, summary, settings.tableRegistry);
        nextSnapshot = applySummaryLayer(
          nextSnapshot,
          group.eventId,
          group.facts,
          'recentHistory',
          summaryMemoryText(summary),
          group.previous ? [summaryMemoryText(group.previous)] : [],
          settings.tableRegistry,
        );
      }
      artifact.snapshot = nextSnapshot;
      assertArtifactCommitCurrent(artifact);
      await persistChatFor(artifact.chatKey);
    }
    chatState.smallSummaries.push(...generated.map((item) => item.summary));
    for (const { group, summary, newFactIds } of generated) {
      if (group.previous) group.previous.supersededBySmallSummaryId = summary.id;
      markFactsConsumed(chatState.internalFacts, newFactIds, summary.id);
    }
    await putChatState(chatState);
  } catch (error) {
    artifact.snapshot = previousSnapshot;
    chatState.internalFacts = previousFacts;
    chatState.smallSummaries = previousSummaries;
    try {
      assertArtifactCommitCurrent(artifact);
      await persistChatFor(artifact.chatKey).catch(() => undefined);
    } catch {
      // 聊天或正文已变化，旧任务回滚不得接触新聊天。
    }
    throw error;
  }
  return generated.at(-1)?.summary ?? null;
}

export async function generateLargeSummary(artifact: MessageArtifact, force = false): Promise<SummaryArtifact | null> {
  const settings = getSettings();
  const chatState = await getChatState(artifact.chatKey);
  const threshold = Math.max(1, Number(settings.largeSummaryCount) || 4);
  // 尽量一次处理所有到期事件线；设上限只用于防止极端输入重新撞上网关超时。
  const groups = pendingLargeEventGroups(chatState.smallSummaries, chatState.largeSummaries, threshold, force).slice(0, 8);
  if (!groups.length) return null;
  const parsed = await generateStructuredTask({
    task: 'largeSummary',
    systemPrompt: largeSummarySystemPrompt(),
    prompt: largeSummaryPrompt(groups.map((group) => ({
      eventId: group.eventId,
      latestSmall: group.latest,
      sourceSummaryIds: group.sourceSummaryIds,
      previousLarge: group.previousLarge,
    }))),
    structureDescription: '{"summaries":[{"event_id":"...","title":"...","summary":"...","keywords":["..."],"unresolved":["..."]}]}',
    maxTokens: Math.min(2200, 700 + groups.length * 260),
  } as any);
  assertArtifactCommitCurrent(artifact);
  const rawSummaries = Array.isArray(parsed?.summaries)
    ? parsed.summaries
    : groups.length === 1 && parsed && typeof parsed === 'object' ? [{ ...parsed, event_id: parsed.event_id || groups[0].eventId }] : [];
  const byEvent = new Map<string, Record<string, any>>();
  for (const item of rawSummaries) {
    if (!item || typeof item !== 'object') continue;
    const eventId = String((item as any).event_id ?? (item as any).eventId ?? '').trim();
    if (!eventId || byEvent.has(eventId)) continue;
    byEvent.set(eventId, item as Record<string, any>);
  }
  const expected = new Set(groups.map((group) => group.eventId));
  for (const eventId of expected) if (!byEvent.has(eventId)) throw new Error(`大总结缺少事件线结果：${eventId}`);
  for (const eventId of byEvent.keys()) if (!expected.has(eventId)) throw new Error(`大总结返回未请求事件线：${eventId}`);

  const generated = groups.map((group) => {
    const value = byEvent.get(group.eventId)!;
    const summary = normalizeSummary(value, 'large', group.sourceSummaryIds, group.previousLarge?.id, {
      eventId: group.eventId,
      eventIds: [group.eventId],
      sourceSummaryIds: group.sourceSummaryIds,
      sourceFactIds: group.sourceFactIds,
    });
    if (!summary.summary) throw new Error(`大总结模型返回空摘要：${group.eventId}`);
    return { group, summary };
  });

  const previousLargeList = structuredClone(chatState.largeSummaries);
  const previousSmall = structuredClone(chatState.smallSummaries);
  const previousFacts = structuredClone(chatState.internalFacts);
  const previousSnapshot = artifact.snapshot ? structuredClone(artifact.snapshot) : undefined;
  try {
    if (artifact.snapshot) {
      let nextSnapshot = artifact.snapshot;
      for (const { group, summary } of generated) {
        const eventFacts = chatState.internalFacts.filter((fact) => fact.eventId === group.eventId);
        nextSnapshot = applySummaryLayer(
          nextSnapshot,
          group.eventId,
          eventFacts,
          'recentHistory',
          '',
          group.items.map(summaryMemoryText),
          settings.tableRegistry,
        );
        nextSnapshot = applySummaryLayer(
          nextSnapshot,
          group.eventId,
          eventFacts,
          'solidifiedHistory',
          summaryMemoryText(summary),
          group.previousLarge ? [summaryMemoryText(group.previousLarge)] : [],
          settings.tableRegistry,
        );
      }
      artifact.snapshot = nextSnapshot;
      assertArtifactCommitCurrent(artifact);
      await persistChatFor(artifact.chatKey);
    }
    chatState.largeSummaries.push(...generated.map((item) => item.summary));
    await putChatState(chatState);
    const readBack = await getChatState(artifact.chatKey);
    const generatedIds = new Set(generated.map((item) => item.summary.id));
    if (![...generatedIds].every((id) => readBack.largeSummaries.some((item) => item.id === id))) {
      throw new Error('大总结批量写入后回读校验失败');
    }
    for (const { group, summary } of generated) {
      const selectedIds = new Set(group.consumedVersionIds);
      for (const item of readBack.smallSummaries) if (selectedIds.has(item.id)) item.solidifiedByLargeSummaryId = summary.id;
      markFactsSolidified(readBack.internalFacts, group.sourceFactIds, summary.id);
    }
    await putChatState(readBack);
  } catch (error) {
    artifact.snapshot = previousSnapshot;
    chatState.largeSummaries = previousLargeList;
    chatState.smallSummaries = previousSmall;
    chatState.internalFacts = previousFacts;
    if (previousSnapshot) {
      try {
        assertArtifactCommitCurrent(artifact);
        await persistChatFor(artifact.chatKey).catch(() => undefined);
      } catch {
        // 聊天或正文已变化，旧总结回滚不得接触新聊天。
      }
    }
    throw error;
  }

  return generated.at(-1)?.summary ?? null;
}

export async function runSummaryStage(artifact: MessageArtifact, kind: 'small' | 'large', force = false): Promise<boolean> {
  const settings = getSettings();
  const enabled = kind === 'small' ? settings.autoSmallSummary : settings.autoLargeSummary;
  if (!enabled && !force) return false;
  const previousStatus = artifact.stages.summary.status;
  const preserveEarlierFailure = !force && previousStatus === 'failed';
  if (!preserveEarlierFailure) markStage(artifact, 'summary', 'running');
  await putArtifact(artifact);
  try {
    const generated = kind === 'small'
      ? await generateSmallSummary(artifact, force)
      : await generateLargeSummary(artifact, force);
    if (!preserveEarlierFailure) markStage(artifact, 'summary', generated || previousStatus === 'success' ? 'success' : 'skipped');
    await putArtifact(artifact);
    return Boolean(generated);
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
    const label = kind === 'small' ? '小总结' : '大总结';
    const previous = artifact.stages.summary.error;
    const current = `${label}失败：${toErrorMessage(error)}`;
    markStage(artifact, 'summary', 'failed', previous && previous !== current ? `${previous}；${current}` : current);
    await putArtifact(artifact);
    throw error;
  }
}

export async function maybeRunSummaries(artifact: MessageArtifact, forceSmall = false, forceLarge = false): Promise<void> {
  const errors: string[] = [];
  try { await runSummaryStage(artifact, 'small', forceSmall); }
  catch (error) { if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error; errors.push(`小总结：${toErrorMessage(error)}`); }
  try { await runSummaryStage(artifact, 'large', forceLarge); }
  catch (error) { if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error; errors.push(`大总结：${toErrorMessage(error)}`); }
  if (errors.length) {
    const combined = errors.join('；');
    markStage(artifact, 'summary', 'failed', combined);
    await putArtifact(artifact);
    throw new Error(combined);
  }
}

/** 历史恢复专用：不 force，只把当前确实达到条件的受影响事件线与未固化小总结排空。 */
export async function rebuildEligibleSummaries(artifact: MessageArtifact): Promise<void> {
  const settings = getSettings();
  const errors: string[] = [];
  markStage(artifact, 'summary', 'running');
  await putArtifact(artifact);

  if (settings.autoSmallSummary) {
    try {
      while (await generateSmallSummary(artifact, false)) {
        // 每次成功至少消费一个 event_id 的待总结事实，循环必然收敛。
      }
    } catch (error) {
      if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
      errors.push(`小总结：${toErrorMessage(error)}`);
    }
  }

  if (settings.autoLargeSummary) {
    try {
      while (await generateLargeSummary(artifact, false)) {
        // 每次成功固化一批未固化小总结，剩余不足阈值时停止。
      }
    } catch (error) {
      if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
      errors.push(`大总结：${toErrorMessage(error)}`);
    }
  }

  if (errors.length) {
    markStage(artifact, 'summary', 'failed', errors.join('；'));
    await putArtifact(artifact);
    throw new Error(errors.join('；'));
  }
  markStage(artifact, 'summary', settings.autoSmallSummary || settings.autoLargeSummary ? 'success' : 'skipped');
  await putArtifact(artifact);
}
