/**
 * 模块职责：构造按事件线的小总结，以及“上一版大总结 + 未固化小总结”的大总结提示。
 * 维护边界：不读取全部聊天正文，不依据可见表格重新推断事实。
 */
import type { InternalFact, SummaryArtifact } from '../types';

export function smallSummarySystemPrompt(): string {
  return `你是镜渊阶段沉降结算器，也是按 event_id 工作的事件线小总结器。只输出合法JSON对象，不续写，不推测，不把未发生结果写死。
一次请求可能包含多条彼此无关的事件线。必须按 event_id 分别总结，绝不能把不同事件线的人物、地点、因果或结果混在一起。
小总结按每一个 event_id 汇总已经发生的事件线，不是聊天轮次流水账，也不是当前表格压缩。
必须保留：起因、已发生的关键经过、已产生的变化、当前结果、尚未解决事项、对后续仍有效的影响。
必须删除：重复动作、气氛描写、无因果作用的旁观者、无后续意义的临时反应、已被新事实覆盖的旧表述。
事件未结束时，只总结已确定发生的部分，并明确未解决事项。旁观者、观众、路人、喝彩、议论和同场者不得进入总结，除非其行为改变事件结果。
输出根字段固定为 summaries；每项固定为 event_id、title、summary、keywords、unresolved。可见表退出由代码按 event_id / fact_id 安全处理，不由你指定行号。`;
}

export interface SmallSummaryEventBatch {
  eventId: string;
  facts: InternalFact[];
  previous?: SummaryArtifact;
}

function compactSmallFacts(facts: InternalFact[]): Record<string, unknown>[] {
  return facts.map((fact) => ({
    fact_id: fact.factId,
    event_id: fact.eventId,
    source_message_ids: fact.sourceMessageIds,
    title: fact.title,
    occurred: fact.occurredFacts,
    unresolved: fact.unresolvedItems,
    status: fact.status,
    time_range: fact.timeRange,
    related_entities: fact.relatedEntities,
    keywords: fact.keywords,
    confidence: fact.confidence,
  }));
}

export function smallSummaryBatchPrompt(groups: SmallSummaryEventBatch[]): string {
  const payload = groups.map((group) => ({
    event_id: group.eventId,
    previous_small: group.previous ? {
      id: group.previous.id,
      title: group.previous.title,
      summary: group.previous.summary,
      unresolved: group.previous.unresolvedItems ?? [],
      keywords: group.previous.keywords,
    } : null,
    new_facts: compactSmallFacts(group.facts),
  }));
  return `为下列每条 event_id 分别生成自己的新版本小总结。可以一次生成多条，但禁止跨事件合并事实、人物、地点或因果。
只使用各自上一版小总结和各自新增内部事实，不读取或补全聊天正文。新版本必须累计保留仍有效的既有事实，并用新事实更新、关闭或替代旧表述。

【独立事件线批次】
${JSON.stringify(payload)}

只输出：{"summaries":[{"event_id":"...","title":"...","summary":"...","keywords":["..."],"unresolved":["..."]}]}
每个输入 event_id 必须且只能返回一项。`;
}

/** 兼容单事件调用。 */
export function smallSummaryPrompt(eventId: string, facts: InternalFact[], previous?: SummaryArtifact): string {
  return smallSummaryBatchPrompt([{ eventId, facts, previous }]);
}

export interface LargeSummaryEventBatch {
  eventId: string;
  latestSmall: SummaryArtifact;
  sourceSummaryIds: string[];
  previousLarge?: SummaryArtifact;
}

export function largeSummarySystemPrompt(): string {
  return `你是镜渊长期沉降结算器。只输出合法JSON对象，不读取聊天正文，不补全未显影内容。
一次请求可能包含多条彼此无关的事件线。必须按 event_id 分别生成长期总结，绝不能把不同事件线混成同一段历史。
每条事件线只压缩自身的小总结：当前层细节最多，近期层次之，长期历史只保留最终结果、核心因果与持续影响。`;
}

export function largeSummaryPrompt(groups: LargeSummaryEventBatch[]): string {
  const payload = groups.map((group) => ({
    event_id: group.eventId,
    previous_large: group.previousLarge ? {
      id: group.previousLarge.id,
      title: group.previousLarge.title,
      summary: group.previousLarge.summary,
      unresolved: group.previousLarge.unresolvedItems ?? [],
      keywords: group.previousLarge.keywords,
    } : null,
    latest_small: {
      id: group.latestSmall.id,
      title: group.latestSmall.title,
      summary: group.latestSmall.summary,
      unresolved: group.latestSmall.unresolvedItems ?? [],
      keywords: group.latestSmall.keywords,
    },
    source_summary_ids: group.sourceSummaryIds,
  }));
  return `将下列每条 event_id 分别压缩为自己的累计长期总结。可以一次生成多条，但禁止跨事件合并事实、因果、人物或地点。
职责：固化已经发生的结果；保留长期影响和仍未解决事项；删除动作细节、重复过程与已被结果覆盖的描述。没有介入或改变长期因果的信息必须删除。

【独立事件线批次】
${JSON.stringify(payload)}

只输出：{"summaries":[{"event_id":"...","title":"...","summary":"...","keywords":["..."],"unresolved":["..."]}]}
每个输入 event_id 必须且只能返回一项。`;
}
