/**
 * 模块职责：通过 SillyTavern 当前连接或 Connection Profile 发起模型请求。
 * 维护边界：插件不保存密钥、不切换全局 Profile；同连接请求由 request-scheduler 串行。
 */
import { getContext, getSettings } from '../core/context';
import { beginModelRequest, finishModelRequest } from '../core/requests';
import { hashText, parseJsonObject, safeText, toErrorMessage, withTimeout } from '../core/utils';
import type { GenerateOptions } from '../types';
import type { TaskKind } from '../constants';
import { requestScheduler } from './request-scheduler';

const TASK_RESPONSE_TOKENS: Record<TaskKind, number> = {
  audit: 1800,
  revision: 4096,
  state: 4096,
  smallSummary: 2400,
  largeSummary: 3200,
};


const schemaUnsupportedConnections = new Set<string>();
const schemaRejectedRequests = new Set<string>();
const SCHEMA_CAPABILITY_STORAGE_KEY = 'mirrorAbyss.schemaCapabilities.v35';
const LEGACY_SCHEMA_CAPABILITY_STORAGE_KEY = 'mirrorAbyss.schemaUnsupported.v31';

interface StoredSchemaCapabilities {
  unsupportedConnections: string[];
  rejectedSchemas: string[];
}

function readStoredSchemaCapabilities(): StoredSchemaCapabilities {
  try {
    const raw = globalThis.sessionStorage?.getItem(SCHEMA_CAPABILITY_STORAGE_KEY);
    const parsed = raw ? JSON.parse(raw) : {};
    return {
      unsupportedConnections: Array.isArray(parsed?.unsupportedConnections)
        ? parsed.unsupportedConnections.filter((item: unknown) => typeof item === 'string')
        : [],
      rejectedSchemas: Array.isArray(parsed?.rejectedSchemas)
        ? parsed.rejectedSchemas.filter((item: unknown) => typeof item === 'string')
        : [],
    };
  } catch {
    return { unsupportedConnections: [], rejectedSchemas: [] };
  }
}

function persistSchemaCapabilities(): void {
  try {
    globalThis.sessionStorage?.setItem(SCHEMA_CAPABILITY_STORAGE_KEY, JSON.stringify({
      unsupportedConnections: [...schemaUnsupportedConnections],
      rejectedSchemas: [...schemaRejectedRequests],
    }));
    // v31 把普通 400/500 也写成连接不支持，不能继续继承这批被污染的结论。
    globalThis.sessionStorage?.removeItem(LEGACY_SCHEMA_CAPABILITY_STORAGE_KEY);
  } catch {
    // 浏览器禁用存储时退回当前页面内存缓存。
  }
}

const storedSchemaCapabilities = readStoredSchemaCapabilities();
for (const key of storedSchemaCapabilities.unsupportedConnections) schemaUnsupportedConnections.add(key);
for (const key of storedSchemaCapabilities.rejectedSchemas) schemaRejectedRequests.add(key);

function taskConnectionKey(task: TaskKind): string {
  const connection = getSettings().connections[task];
  if (connection?.mode === 'profile') {
    const profileId = resolveProfileId(connection);
    const profile = supportedProfiles().find((item: any) => item?.id === profileId);
    return `profile:${profileId || 'unselected'}:${hashText(`${profile?.api || ''}|${profile?.model || ''}`)}`;
  }
  const context = getContext();
  const currentIdentity = [
    context.mainApi,
    context.chatCompletionSettings?.model,
    context.oai_settings?.chat_completion_source,
    context.oai_settings?.openai_model,
    context.textgenerationwebui_settings?.custom_model,
    context.selected_model,
    context.model,
    context.api_server,
  ].map((value) => safeText(value, 240)).join('|');
  return `current-chat:${hashText(currentIdentity)}`;
}

function schemaRequestKey(task: TaskKind, jsonSchema: Record<string, any>): string {
  return `${taskConnectionKey(task)}:${task}:${hashText(JSON.stringify(jsonSchema))}`;
}

/**
 * 连接级不支持只用于明确的“该接口没有结构化输出能力”。
 * 某一份复杂 Schema 被拒绝时只跳过该 Schema 指纹，不能连带禁用同连接上的其他任务。
 */
export function shouldSkipJsonSchema(task: TaskKind, jsonSchema?: Record<string, any>): boolean {
  if (schemaUnsupportedConnections.has(taskConnectionKey(task))) return true;
  return Boolean(jsonSchema && schemaRejectedRequests.has(schemaRequestKey(task, jsonSchema)));
}

export function rememberJsonSchemaUnsupported(task: TaskKind): void {
  schemaUnsupportedConnections.add(taskConnectionKey(task));
  persistSchemaCapabilities();
}

export function rememberJsonSchemaRejected(task: TaskKind, jsonSchema: Record<string, any>): void {
  schemaRejectedRequests.add(schemaRequestKey(task, jsonSchema));
  persistSchemaCapabilities();
}

/** 只有明确说明接口/参数不支持结构化输出时，才可写入连接级能力缓存。 */
export function isDefinitiveJsonSchemaUnsupported(error: unknown): boolean {
  const message = toErrorMessage(error);
  return /(?:json[_ -]?schema|structured outputs?|response[_ -]?format).*(?:not supported|unsupported|not available)|(?:does not|doesn't) support.*(?:json[_ -]?schema|structured outputs?|response[_ -]?format)|unknown (?:field|parameter).*(?:json_schema|response_format)|unrecognized (?:field|parameter).*(?:json_schema|response_format)/i.test(message);
}

/** 普通 400、invalid schema 等只能证明这一份请求被拒绝，不能证明整条连接不支持。 */
export function isJsonSchemaRequestRejected(error: unknown): boolean {
  const message = toErrorMessage(error);
  return /\bbad request\b|\bstatus\s*400\b|\bhttp\s*400\b|invalid (?:json[_ -]?)?schema|schema.*invalid|response[_ -]?format.*invalid/i.test(message);
}

export function resetJsonSchemaCapabilityCache(): void {
  schemaUnsupportedConnections.clear();
  schemaRejectedRequests.clear();
  try {
    globalThis.sessionStorage?.removeItem(SCHEMA_CAPABILITY_STORAGE_KEY);
    globalThis.sessionStorage?.removeItem(LEGACY_SCHEMA_CAPABILITY_STORAGE_KEY);
  } catch {
    // ignore unavailable storage
  }
}

function responseTokens(options: GenerateOptions): number {
  const requested = Number(options.maxTokens);
  if (Number.isFinite(requested) && requested > 0) {
    return Math.max(128, Math.min(32768, Math.round(requested)));
  }
  return TASK_RESPONSE_TOKENS[options.task];
}

function textFromValue(value: unknown): string {
  if (typeof value === 'string') return value.trim();
  if (value && typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch {
      return '';
    }
  }
  return '';
}

function generationText(result: any): string {
  if (typeof result === 'string') return result.trim();
  const envelopeKeys = ['content', 'text', 'output', 'result', 'value', 'pipe'];
  for (const key of envelopeKeys) {
    const text = textFromValue(result?.[key]);
    if (text) return text;
  }
  for (const value of [
    result?.message?.content,
    result?.choices?.[0]?.message?.content,
    result?.choices?.[0]?.text,
  ]) {
    const text = textFromValue(value);
    if (text) return text;
  }
  const hasEnvelope = Boolean(
    result
    && typeof result === 'object'
    && (
      envelopeKeys.some((key) => key in result)
      || 'message' in result
      || 'choices' in result
    )
  );
  return hasEnvelope ? '' : textFromValue(result) || safeText(result, 200000).trim();
}

function cleanProfileName(value: unknown): string {
  return safeText(value, 160).replace(/["|\r\n]/g, '').trim();
}

function connectionManagerStore(): { profiles: any[]; selectedProfile?: string } | null {
  const context = getContext();
  const store = context.extensionSettings?.connectionManager;
  if (!store || !Array.isArray(store.profiles)) return null;
  return store;
}

function supportedProfiles(): any[] {
  const context = getContext();
  try {
    const service = context.ConnectionManagerRequestService;
    if (typeof service?.getSupportedProfiles === 'function') return service.getSupportedProfiles();
  } catch {
    // fall back to raw profile list; request call will still validate.
  }
  return connectionManagerStore()?.profiles ?? [];
}

function resolveProfileId(connection: { profileId?: string; profile?: string }): string {
  const profiles = supportedProfiles();
  if (connection.profileId && profiles.some((profile: any) => profile?.id === connection.profileId)) return connection.profileId;
  const legacyName = cleanProfileName(connection.profile);
  const match = profiles.find((profile: any) => cleanProfileName(profile?.name) === legacyName);
  if (match?.id) {
    connection.profileId = String(match.id);
    return String(match.id);
  }
  return '';
}

function profileApiMode(profileId: string): 'openai' | 'textgenerationwebui' | '' {
  const context = getContext();
  const profile = supportedProfiles().find((item: any) => item?.id === profileId);
  const selected = context.CONNECT_API_MAP?.[profile?.api]?.selected;
  return selected === 'openai' || selected === 'textgenerationwebui' ? selected : '';
}

function messagesFromOptions(options: GenerateOptions): Array<{ role: string; content: string }> {
  const messages: Array<{ role: string; content: string }> = [];
  if (options.systemPrompt.trim()) messages.push({ role: 'system', content: options.systemPrompt });
  if (Array.isArray(options.prompt)) {
    for (const item of options.prompt) {
      const role = safeText(item?.role, 30).trim() || 'user';
      const content = safeText(item?.content, 200000);
      if (content.trim()) messages.push({ role, content });
    }
  } else {
    messages.push({ role: 'user', content: options.prompt });
  }
  return messages;
}

async function generateCurrent(options: GenerateOptions, controller: AbortController): Promise<string> {
  const context = getContext();
  if (typeof context.generateRaw !== 'function') throw new Error('当前SillyTavern未提供generateRaw');
  const settings = getSettings();
  const result = await withTimeout(
    Promise.resolve(context.generateRaw({
      systemPrompt: options.systemPrompt,
      prompt: options.prompt,
      jsonSchema: options.jsonSchema,
      responseLength: responseTokens(options),
      signal: options.signal,
    })),
    Math.max(10000, Number(settings.requestTimeoutMs) || 90000),
    `${options.task}模型调用`,
    controller,
  );
  const text = generationText(result);
  if (!text) throw new Error(`${options.task}模型返回为空`);
  return text;
}

async function generateWithNativeProfile(options: GenerateOptions, profileId: string, controller: AbortController): Promise<string> {
  const context = getContext();
  const service = context.ConnectionManagerRequestService;
  if (typeof service?.sendRequest !== 'function') {
    throw new Error('当前SillyTavern未提供ConnectionManagerRequestService');
  }
  const settings = getSettings();
  const messages = messagesFromOptions(options);
  const overridePayload: Record<string, any> = { stream: false };
  if (options.jsonSchema && profileApiMode(profileId) === 'openai') {
    overridePayload.json_schema = options.jsonSchema;
  }
  const result = await withTimeout(
    Promise.resolve(service.sendRequest(
      profileId,
      messages,
      responseTokens(options),
      {
        stream: false,
        extractData: true,
        includePreset: false,
        includeInstruct: false,
        signal: options.signal,
      },
      overridePayload,
    )),
    Math.max(10000, Number(settings.requestTimeoutMs) || 90000),
    `${options.task} Connection Profile请求`,
    controller,
  );
  const text = generationText(result);
  if (!text) throw new Error(`${options.task} Connection Profile返回为空`);
  return text;
}

export function listSupportedConnectionProfiles(): Array<{ id: string; name: string; api?: string; model?: string }> {
  return supportedProfiles()
    .map((profile: any) => ({
      id: safeText(profile?.id, 160),
      name: cleanProfileName(profile?.name) || '未命名配置',
      api: safeText(profile?.api, 80),
      model: safeText(profile?.model, 240),
    }))
    .filter((profile: any) => profile.id);
}

export function describeTaskConnection(task: TaskKind): string {
  const connection = getSettings().connections[task];
  if (connection?.mode === 'profile') {
    const id = resolveProfileId(connection);
    const profile = listSupportedConnectionProfiles().find((item) => item.id === id);
    return `Connection Profile：${profile?.name || cleanProfileName(connection.profile) || '未选择'}`;
  }
  return '当前聊天连接';
}

/**
 * 所有业务模型调用的统一入口。连接解析、lane 排队、超时与活动请求登记都在此收口。
 */
export async function generateTask(options: GenerateOptions): Promise<string> {
  const controller = beginModelRequest();
  const externalSignal = options.signal;
  const forwardAbort = () => controller.abort((externalSignal as any)?.reason);
  if (externalSignal?.aborted) forwardAbort();
  else externalSignal?.addEventListener('abort', forwardAbort, { once: true });
  try {
    const request = { ...options, signal: controller.signal };
    const connection = getSettings().connections[options.task];
    const profileId = connection?.mode === 'profile' ? resolveProfileId(connection) : '';
    const lane = connection?.mode === 'profile' ? `profile:${profileId || 'unselected'}` : 'current-chat';
    const promptChars = Array.isArray(options.prompt)
      ? options.prompt.reduce((sum, item) => sum + safeText(item?.content, 200000).length, 0)
      : safeText(options.prompt, 200000).length;
    const tokenLimit = responseTokens(options);
    return await requestScheduler.run(lane, options.task, controller.signal, async () => {
      if (connection?.mode === 'profile') {
        if (!profileId) throw new Error(`${options.task}未选择有效的Connection Profile`);
        return generateWithNativeProfile(request, profileId, controller);
      }
      return generateCurrent(request, controller);
    }, {
      requestPurpose: options.requestPurpose || (options.jsonSchema ? 'schema' : 'plain'),
      systemPromptChars: options.systemPrompt.length,
      promptChars,
      responseTokens: tokenLimit,
      hasJsonSchema: Boolean(options.jsonSchema),
      jsonSchemaName: options.jsonSchema ? safeText(options.jsonSchema.name, 120) : undefined,
      jsonSchemaBytes: options.jsonSchema ? JSON.stringify(options.jsonSchema).length : 0,
    });
  } finally {
    externalSignal?.removeEventListener('abort', forwardAbort);
    finishModelRequest(controller);
  }
}

export function requestTraceReport(): Record<string, any>[] {
  return requestScheduler.list();
}

export type ConnectionSchemaStatus =
  | 'supported'
  | 'cached-bypass'
  | 'rejected-fallback'
  | 'empty-fallback'
  | 'transient-fallback'
  | 'plain-only';

export interface ConnectionTestResult {
  connected: boolean;
  instructionFollowed: boolean;
  jsonValid: boolean;
  method: string;
  elapsedMs: number;
  responsePreview: string;
  schemaStatus: ConnectionSchemaStatus;
  schemaDetail: string;
}

export async function testConnection(task: GenerateOptions['task']): Promise<ConnectionTestResult> {
  const started = performance.now();
  let raw = '';
  let schemaStatus: ConnectionSchemaStatus = 'supported';
  let schemaDetail = '';
  const request: GenerateOptions = {
    task,
    systemPrompt: '你是API结构测试器。禁止解释、禁止Markdown、禁止思考标签。',
    prompt: '只输出这个JSON对象：{"ok":true,"source":"mirror-abyss"}',
    maxTokens: 256,
    jsonSchema: {
      name: 'MirrorAbyssConnectionTestV35',
      description: '镜渊原生连接结构化输出测试',
      strict: false,
      value: {
        $schema: 'http://json-schema.org/draft-04/schema#',
        type: 'object',
        required: ['ok', 'source'],
        properties: {
          ok: { type: 'boolean' },
          source: { type: 'string' },
        },
        additionalProperties: false,
      },
    },
  };
  const schema = request.jsonSchema as Record<string, any>;
  let schemaFailure: unknown;
  if (shouldSkipJsonSchema(task, schema)) {
    schemaStatus = 'cached-bypass';
    raw = await generateTask({ ...request, jsonSchema: undefined, requestPurpose: 'plain' });
  } else {
    try {
      raw = await generateTask({ ...request, requestPurpose: 'schema' });
      if (raw.trim() === '{}') {
        schemaStatus = 'empty-fallback';
        schemaFailure = new Error('结构化输出返回空对象');
      }
    } catch (error) {
      if (error instanceof Error && error.name === 'AbortError') throw error;
      schemaFailure = error;
      schemaDetail = safeText(toErrorMessage(error), 240);
      if (isDefinitiveJsonSchemaUnsupported(error)) {
        schemaStatus = 'rejected-fallback';
        rememberJsonSchemaUnsupported(task);
      } else if (isJsonSchemaRequestRejected(error)) {
        schemaStatus = 'rejected-fallback';
      } else {
        schemaStatus = 'transient-fallback';
      }
    }
  }
  if (schemaFailure) {
    try {
      raw = await generateTask({ ...request, jsonSchema: undefined, requestPurpose: 'fallback' });
      if (schemaStatus === 'rejected-fallback' && !isDefinitiveJsonSchemaUnsupported(schemaFailure)) {
        rememberJsonSchemaRejected(task, schema);
      }
      if (schemaStatus === 'empty-fallback') rememberJsonSchemaRejected(task, schema);
    } catch (fallbackError) {
      if (fallbackError instanceof Error && fallbackError.name === 'AbortError') throw fallbackError;
      throw new Error(
        `${describeTaskConnection(task)}连接失败。结构化请求：${toErrorMessage(schemaFailure)}；无Schema回退：${toErrorMessage(fallbackError)}`,
      );
    }
  }
  let jsonValid = false;
  let instructionFollowed = false;
  try {
    const parsed = parseJsonObject(raw);
    jsonValid = true;
    instructionFollowed = parsed.ok === true && parsed.source === 'mirror-abyss';
  } catch {
    // response remains useful for diagnosing instruction-following.
  }
  return {
    connected: Boolean(raw.trim()),
    instructionFollowed,
    jsonValid,
    method: describeTaskConnection(task),
    elapsedMs: Math.round(performance.now() - started),
    responsePreview: raw.replace(/\s+/g, ' ').slice(0, 240),
    schemaStatus,
    schemaDetail,
  };
}
