/**
 * 模块职责：按动态注册表归一化可见事实视图，并合并人工/锁定数据。
 * 维护边界：快照只是视图；source=manual 或 locked=true 的行必须保留，内部事实真相在 ChatState.internalFacts。
 */
import { type TableDefinition, type TableKey } from '../constants';
import type { ActivityState, CharacterLifecycle, EvidenceLevel, ExistenceState, MemoryState, StateRow, StateSnapshot } from '../types';
import { makeId, nowIso, safeText } from '../core/utils';
import { isPurePassiveObserverText } from './observer';
import { DEFAULT_TABLE_REGISTRY, enabledTables, migrateSnapshotTables, normalizeTableRegistry, tableByKey, tableByRole } from './table-registry';

const EXISTENCE_STATES = new Set<ExistenceState>([
  '存活', '死亡已确认', '存在未知', '失踪', '身份存疑', '虚构或误认已确认', '存在被抹除', '未标注', '不适用',
]);
const ACTIVITY_STATES = new Set<ActivityState>([
  '当前在场', '当前相关', '离场但仍活跃', '休眠', '长期休眠', '已归档', '未标注', '不适用',
]);
const MEMORY_STATES = new Set<MemoryState>([
  '广泛记得', '部分人物记得', '仅记录留存', '仅痕迹留存', '无人可确认记得', '记忆被篡改', '记忆被抹除', '未标注', '不适用',
]);
const EVIDENCE_LEVELS = new Set<EvidenceLevel>(['已确认', '可靠记录', '多方陈述', '单方陈述', '推测', '未知']);
const STANDARD_FIELDS = new Set(['id', 'title', 'name', 'content', 'summary', 'keywords', 'status', 'source', 'locked', 'lockMode', 'lifecycle', 'updatedAt', 'factIds', 'fact_ids', 'eventId', 'event_id', 'eventIds', 'event_ids', 'recall', 'fields']);

function registryOrDefault(registry?: TableDefinition[]): TableDefinition[] {
  return normalizeTableRegistry(registry?.length ? registry : DEFAULT_TABLE_REGISTRY as TableDefinition[]);
}

/** 非枚举 characters 别名只用于 rc.19 测试/API 兼容，不会进入模型 JSON。 */
function characterTableKey(registry: TableDefinition[]): string | undefined {
  return tableByRole(registry, 'characters', false)?.key || tableByRole(registry, 'state', false)?.key;
}

function attachLegacyAliases(snapshot: StateSnapshot, registry: TableDefinition[]): StateSnapshot {
  const key = characterTableKey(registry);
  if (!key || !(key in snapshot)) return snapshot;
  for (const alias of ['characters', 'state']) {
    if (alias === key || Object.prototype.hasOwnProperty.call(snapshot, alias)) continue;
    Object.defineProperty(snapshot, alias, {
      configurable: true, enumerable: false,
      get: () => snapshot[key],
      set: (value) => { snapshot[key] = Array.isArray(value) ? value : []; },
    });
  }
  return snapshot;
}

export function emptySnapshot(registry?: TableDefinition[], includeDisabled = true): StateSnapshot {
  const tables = registryOrDefault(registry).filter((table) => includeDisabled || table.enabled);
  return attachLegacyAliases(Object.fromEntries(tables.map((table) => [table.key, []])) as StateSnapshot, tables);
}

export function normalizeKeywords(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, 80).trim()).filter(Boolean))].slice(0, 24);
}
function normalizeStringList(value: unknown, limit = 20, itemLimit = 240): string[] {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => safeText(item, itemLimit).trim()).filter(Boolean))].slice(0, limit);
}
function enumValue<T extends string>(value: unknown, allowed: Set<T>, fallback: T): T {
  const text = safeText(value, 80).trim() as T;
  return allowed.has(text) ? text : fallback;
}

export function defaultLifecycle(): CharacterLifecycle {
  return { existence: '未标注', activity: '未标注', memory: '未标注', evidenceLevel: '未知', evidence: '', returnConditions: [], returnBlockers: [] };
}
export function normalizeLifecycle(value: unknown, previous?: CharacterLifecycle): CharacterLifecycle {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const base = previous ?? defaultLifecycle();
  return {
    existence: enumValue(source.existence ?? base.existence, EXISTENCE_STATES, base.existence),
    activity: enumValue(source.activity ?? base.activity, ACTIVITY_STATES, base.activity),
    memory: enumValue(source.memory ?? base.memory, MEMORY_STATES, base.memory),
    evidenceLevel: enumValue(source.evidenceLevel ?? base.evidenceLevel, EVIDENCE_LEVELS, base.evidenceLevel),
    evidence: safeText(source.evidence ?? base.evidence, 4000).trim(),
    returnConditions: normalizeStringList(source.returnConditions ?? base.returnConditions),
    returnBlockers: normalizeStringList(source.returnBlockers ?? base.returnBlockers),
  };
}

function normalizeRecall(value: unknown, title: string, keywords: string[]) {
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const any = normalizeStringList(source.any, 24, 100);
  return {
    any: any.length ? any : normalizeKeywords([title, ...keywords]),
    all: normalizeStringList(source.all, 16, 100),
    exclude: normalizeStringList(source.exclude, 16, 100),
  };
}

function normalizeCustomFields(source: Record<string, unknown>, table: TableDefinition, previous?: StateRow): Record<string, unknown> {
  const prior = previous?.fields && typeof previous.fields === 'object' ? previous.fields : {};
  const nested = source.fields && typeof source.fields === 'object' ? source.fields as Record<string, unknown> : {};
  const output: Record<string, unknown> = {};
  for (const field of table.fields) {
    if (STANDARD_FIELDS.has(field.key) || field.key === 'lifecycle') continue;
    const raw = source[field.key] ?? nested[field.key] ?? prior[field.key];
    if (field.type === 'string[]') output[field.key] = normalizeStringList(raw, 30, 500);
    else output[field.key] = safeText(raw, 4000).trim();
  }
  return output;
}

export function normalizeRow(value: unknown, tableKey: TableKey, index: number, previous?: StateRow, registry?: TableDefinition[]): StateRow {
  const tables = registryOrDefault(registry);
  const table = tableByKey(tables, tableKey) ?? { key: tableKey, name: tableKey, role: 'custom', fields: [] } as unknown as TableDefinition;
  const source = value && typeof value === 'object' ? value as Record<string, unknown> : {};
  const now = nowIso();
  const id = safeText(source.id || previous?.id || makeId(tableKey), 160).trim() || makeId(tableKey);
  const manual = source.source === 'manual' || previous?.source === 'manual';
  const locked = Boolean(source.locked ?? previous?.locked ?? false);
  const rawLockMode = safeText(source.lockMode ?? previous?.lockMode, 20).trim();
  const lockMode: 'base' | 'all' | undefined = locked || rawLockMode === 'all' ? 'all' : manual || rawLockMode === 'base' ? 'base' : undefined;
  const title = safeText(source.title || source.name || previous?.title || `${table.name} ${index + 1}`, 240).trim();
  const keywords = normalizeKeywords(source.keywords ?? previous?.keywords ?? []);
  const supportsLifecycle = ['characters', 'state'].includes(table.role) || table.fields.some((field) => field.type === 'lifecycle');
  const lifecycleInput = source.lifecycle ?? previous?.lifecycle;
  const factIds = normalizeStringList(source.factIds ?? source.fact_ids ?? previous?.factIds, 40, 160);
  const eventId = safeText(source.eventId ?? source.event_id ?? previous?.eventId, 160).trim() || undefined;
  const eventIds = normalizeStringList(source.eventIds ?? source.event_ids ?? previous?.eventIds ?? (eventId ? [eventId] : []), 60, 160);
  if (eventId && !eventIds.includes(eventId)) eventIds.unshift(eventId);
  const content = safeText(source.content || source.summary || previous?.content || '', 12000).trim();
  const fields = normalizeCustomFields(source, table, previous);
  if (manual && !safeText(fields.baseContent, 12000).trim() && content) fields.baseContent = content;
  return {
    id,
    title,
    content,
    keywords,
    status: safeText(source.status || previous?.status || 'active', 120).trim() || 'active',
    source: manual ? 'manual' : 'auto',
    locked: lockMode === 'all',
    lockMode,
    lifecycle: supportsLifecycle && lifecycleInput ? normalizeLifecycle(lifecycleInput, previous?.lifecycle) : undefined,
    updatedAt: safeText(source.updatedAt || previous?.updatedAt || now, 80) || now,
    fields,
    factIds,
    eventId: eventId || eventIds[0],
    eventIds,
    recall: normalizeRecall(source.recall ?? previous?.recall, title, keywords),
  };
}

export function normalizeSnapshot(value: unknown, previousSnapshot?: StateSnapshot, registry?: TableDefinition[], includeDisabled = true): StateSnapshot {
  const tables = registryOrDefault(registry).filter((table) => includeDisabled || table.enabled);
  const source = migrateSnapshotTables(value, tables);
  const previous = previousSnapshot ? migrateSnapshotTables(previousSnapshot, tables) : {};
  const output = emptySnapshot(tables, true);
  for (const table of tables) {
    const key = table.key;
    const rows = Array.isArray(source[key]) ? source[key] : [];
    const previousMap = new Map((previous[key] ?? []).map((row: StateRow) => [row.id, row]));
    const used = new Set<string>();
    output[key] = rows.map((row: unknown, index: number) => {
      const rawId = row && typeof row === 'object' ? safeText((row as any).id, 160) : '';
      const normalized = normalizeRow(row, key, index, rawId ? previousMap.get(rawId) : undefined, tables);
      if (used.has(normalized.id)) normalized.id = makeId(key);
      used.add(normalized.id);
      return normalized;
    });
  }
  return attachLegacyAliases(output, tables);
}

function identityTitle(value: string): string {
  return String(value || '').normalize('NFKC').toLowerCase().replace(/[\s·•._—–\-|｜:：()（）【】\[\]]+/g, '');
}
function stateRows(snapshot: StateSnapshot, registry: TableDefinition[]): StateRow[] {
  const key = characterTableKey(registry);
  return key ? snapshot[key] ?? [] : [];
}

/** 保留已建立主体，人工/锁定行优先；仅视图层维护，不代表自动创建人物卡。 */
export function preservePersistentCharacters(previous: StateSnapshot, next: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const key = characterTableKey(tables);
  if (!key) return next;
  const nextRows = next[key] ?? (next[key] = []);
  const oldRows = previous[key] ?? previous.characters ?? [];
  const byId = new Map(nextRows.map((row) => [row.id, row]));
  const idRemap = new Map<string, string>();
  const oldTitleCounts = new Map<string, number>();
  const nextByTitle = new Map<string, StateRow[]>();
  for (const row of oldRows) {
    const title = identityTitle(row.title);
    if (title) oldTitleCounts.set(title, (oldTitleCounts.get(title) ?? 0) + 1);
  }
  for (const row of nextRows) {
    const title = identityTitle(row.title);
    if (title) nextByTitle.set(title, [...(nextByTitle.get(title) ?? []), row]);
  }
  for (const oldRow of oldRows) {
    if (byId.has(oldRow.id)) continue;
    const title = identityTitle(oldRow.title);
    const titleMatches = title ? nextByTitle.get(title) ?? [] : [];
    // 同名人物只有在旧、新两侧都唯一时才能用标题继承；否则必须按不同稳定 ID 全部保留。
    const titleMatch = title && oldTitleCounts.get(title) === 1 && titleMatches.length === 1
      ? titleMatches[0]
      : undefined;
    if (titleMatch) {
      const replacedId = titleMatch.id;
      titleMatch.id = oldRow.id;
      if (replacedId && replacedId !== oldRow.id) idRemap.set(replacedId, oldRow.id);
      if (oldRow.locked || oldRow.lockMode === 'all') {
        Object.assign(titleMatch, structuredClone(oldRow));
      } else if (oldRow.source === 'manual' || oldRow.lockMode === 'base') {
        const generatedFields = titleMatch.fields ?? {};
        const oldFields = oldRow.fields ?? {};
        titleMatch.title = oldRow.title;
        titleMatch.source = 'manual';
        titleMatch.locked = false;
        titleMatch.lockMode = 'base';
        titleMatch.fields = {
          ...structuredClone(oldFields),
          currentStates: structuredClone(generatedFields.currentStates ?? oldFields.currentStates ?? []),
          relationshipStates: structuredClone(generatedFields.relationshipStates ?? oldFields.relationshipStates ?? []),
          abilityStates: structuredClone(generatedFields.abilityStates ?? oldFields.abilityStates ?? []),
          relatedObjects: structuredClone(generatedFields.relatedObjects ?? oldFields.relatedObjects ?? []),
          relatedEvents: structuredClone(generatedFields.relatedEvents ?? oldFields.relatedEvents ?? []),
        };
      } else if (!titleMatch.lifecycle && oldRow.lifecycle) {
        titleMatch.lifecycle = structuredClone(oldRow.lifecycle);
      }
      byId.set(oldRow.id, titleMatch);
      continue;
    }
    const restored = structuredClone(oldRow);
    nextRows.push(restored);
    byId.set(restored.id, restored);
    if (title) nextByTitle.set(title, [...(nextByTitle.get(title) ?? []), restored]);
  }
  next[key] = nextRows;
  rewriteObjectReferences(next, idRemap);
  return attachLegacyAliases(next, tables);
}

/** 基础内容与已固化历史不是状态提取的可写区；已有值始终由上一快照覆盖回去。 */
export function preserveObjectBaseLayers(previous: StateSnapshot, next: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  for (const table of tables) {
    const previousRows = previous[table.key] ?? [];
    const byId = new Map(previousRows.map((row) => [row.id, row]));
    const previousByTitle = new Map<string, StateRow[]>();
    const nextTitleCounts = new Map<string, number>();
    for (const row of previousRows) {
      const title = identityTitle(row.title);
      if (title) previousByTitle.set(title, [...(previousByTitle.get(title) ?? []), row]);
    }
    for (const row of next[table.key] ?? []) {
      const title = identityTitle(row.title);
      if (title) nextTitleCounts.set(title, (nextTitleCounts.get(title) ?? 0) + 1);
    }
    for (const row of next[table.key] ?? []) {
      const title = identityTitle(row.title);
      const titleMatches = title ? previousByTitle.get(title) ?? [] : [];
      const uniqueTitleMatch = title && titleMatches.length === 1 && nextTitleCounts.get(title) === 1
        ? titleMatches[0]
        : undefined;
      const old = byId.get(row.id) ?? uniqueTitleMatch;
      if (!old) continue;
      row.fields ||= {};
      const oldFields = old.fields ?? {};
      const existingBase = safeText(oldFields.baseContent, 12000).trim();
      if (existingBase) row.fields.baseContent = structuredClone(oldFields.baseContent);
      // 空基础层允许在对象首次获得明确基础事实时初始化；一旦非空，后续状态提取不得改写。
      if ('recentHistory' in oldFields) row.fields.recentHistory = structuredClone(oldFields.recentHistory);
      else delete row.fields.recentHistory;
      if ('solidifiedHistory' in oldFields) row.fields.solidifiedHistory = structuredClone(oldFields.solidifiedHistory);
      else delete row.fields.solidifiedHistory;
    }
  }
  return attachLegacyAliases(next, tables);
}

function characterTitleAliases(title: string): string[] {
  const raw = String(title || '').trim();
  const parts = raw.split(/[｜|:：—–-]/).map(identityTitle).filter(Boolean);
  const stripped = identityTitle(raw.replace(/(?:人物|角色|人物状态|角色状态|档案|信息|当前状态)$/g, ''));
  return [...new Set([identityTitle(raw), stripped, ...parts].filter(Boolean))];
}
export function removeFocusCharacterDuplicates(snapshot: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const focusKey = tableByRole(tables, 'focus', false)?.key;
  if (!focusKey) return snapshot;
  const characters = stateRows(snapshot, tables);
  const aliases = new Set(characters.flatMap((row) => characterTitleAliases(row.title)));
  const contents = new Set(characters.map((row) => identityTitle(row.content)).filter((value) => value.length >= 12));
  snapshot[focusKey] = (snapshot[focusKey] ?? []).filter((row) => {
    if (row.source === 'manual' || row.locked) return true;
    const title = identityTitle(row.title);
    const content = identityTitle(row.content);
    return !(title && aliases.has(title)) && !(content.length >= 12 && contents.has(content));
  });
  return snapshot;
}


function rowArray(value: unknown): string[] {
  return Array.isArray(value) ? value.map((item) => safeText(item, 500).trim()).filter(Boolean) : [];
}

const PERSISTED_CHARACTER_STATE_FIELDS = ['currentFacts', 'currentStates', 'recentHistory', 'relationshipStates', 'abilityStates'] as const;
const PERSISTED_CHARACTER_SHARED_FIELDS = ['solidifiedHistory', 'relatedObjects', 'relatedEvents'] as const;

function persistedCharacterName(value: unknown): string {
  const original = safeText(value, 240).trim();
  let name = original
    .replace(/^(?:人物|角色)(?:的)?(?:当前)?状态\s*[:：|｜-]\s*/i, '')
    .replace(/^(?:人物|角色|档案|信息)\s*[:：|｜-]\s*/i, '')
    .replace(/\s*(?:的)?(?:人物|角色)?(?:当前)?状态\s*$/i, '')
    .replace(/\s*(?:人物|角色)?(?:档案|信息)\s*$/i, '')
    .trim();
  if (!name) name = original;
  const identity = identityTitle(name);
  return new Set(['角色', '人物', '未知', '未命名', 'unknown', 'unknowncharacter']).has(identity) ? '' : identity;
}

function explicitPersistedStateTitle(value: unknown): boolean {
  const title = safeText(value, 240).trim();
  return /^(?:人物|角色)(?:的)?(?:当前)?状态\s*[:：|｜-]/i.test(title)
    || /(?:的)?(?:人物|角色)?(?:当前)?状态\s*$/i.test(title);
}

function hasPersistedBaseSignal(row: StateRow): boolean {
  const baseContent = safeText(row.fields?.baseContent, 12000).trim();
  return Boolean(baseContent || row.source === 'manual' || row.locked || row.lockMode === 'base' || row.lockMode === 'all');
}

function hasPersistedStateSignal(row: StateRow): boolean {
  const generatedId = /^characters(?:_|$)/i.test(safeText(row.id, 160).trim());
  const mutableState = PERSISTED_CHARACTER_STATE_FIELDS.some((field) => rowArray(row.fields?.[field]).length > 0);
  return explicitPersistedStateTitle(row.title) || (generatedId && mutableState);
}

function mergedRecall(base: StateRow['recall'], state: StateRow['recall']): StateRow['recall'] {
  if (!base && !state) return undefined;
  return {
    any: [...new Set([...(base?.any ?? []), ...(state?.any ?? [])])],
    all: [...new Set([...(base?.all ?? []), ...(state?.all ?? [])])],
    exclude: [...new Set([...(base?.exclude ?? []), ...(state?.exclude ?? [])])],
  };
}

export interface PersistedCharacterMergeResult {
  snapshot: StateSnapshot;
  /** rc.25 为状态行生成的临时 ID -> 被保留的基础角色稳定 ID。 */
  idRemap: Map<string, string>;
  mergedCount: number;
}

/**
 * 仅供 V30 一次性升级使用：rc.25 可能已经把旧 characters/state 保存为同一 characters
 * 表内两个不同 ID。只有规范化名称分组恰好包含“一条受保护基础行 + 一条无保护状态行”
 * 时才自动合并；任何多候选或角色不唯一情况都原样保留。
 */
export function mergePersistedCharacterDuplicates(
  snapshot: StateSnapshot,
  registry?: TableDefinition[],
): PersistedCharacterMergeResult {
  const tables = registryOrDefault(registry);
  const key = characterTableKey(tables);
  const idRemap = new Map<string, string>();
  if (!key) return { snapshot, idRemap, mergedCount: 0 };
  // 尚保留可枚举旧 state 表时应交给 V29 的确定性双表迁移，V30 不参与猜测。
  if (key !== 'state' && Object.prototype.propertyIsEnumerable.call(snapshot, 'state') && Array.isArray(snapshot.state)) {
    return { snapshot, idRemap, mergedCount: 0 };
  }
  const rows = snapshot[key] ?? [];
  const groups = new Map<string, Array<{ row: StateRow; index: number }>>();
  rows.forEach((row, index) => {
    const name = persistedCharacterName(row.title);
    if (!name) return;
    groups.set(name, [...(groups.get(name) ?? []), { row, index }]);
  });

  const replacementByIndex = new Map<number, StateRow>();
  const removedIndexes = new Set<number>();
  let mergedCount = 0;
  for (const group of groups.values()) {
    // 超过两行即存在多候选；即使字段形态看似可分，也不能猜测哪一条状态属于哪一人物。
    if (group.length !== 2) continue;
    const bases = group.filter(({ row }) => hasPersistedBaseSignal(row));
    const states = group.filter(({ row }) => !hasPersistedBaseSignal(row) && hasPersistedStateSignal(row));
    if (bases.length !== 1 || states.length !== 1) continue;
    const baseEntry = bases[0];
    const stateEntry = states[0];
    if (baseEntry.row.id === stateEntry.row.id) continue;

    const base = baseEntry.row;
    const state = stateEntry.row;
    const baseFields = structuredClone(base.fields ?? {});
    const stateFields = state.fields ?? {};
    const fields: Record<string, unknown> = { ...baseFields };
    for (const field of PERSISTED_CHARACTER_STATE_FIELDS) {
      // 状态行是 rc.25 已保存的当前层；空数组也必须能关闭基础行上残留的旧状态。
      if (Object.prototype.hasOwnProperty.call(stateFields, field)) fields[field] = structuredClone(stateFields[field]);
    }
    for (const field of PERSISTED_CHARACTER_SHARED_FIELDS) {
      fields[field] = [...new Set([...rowArray(baseFields[field]), ...rowArray(stateFields[field])])];
    }
    for (const [field, value] of Object.entries(stateFields)) {
      if (field === 'baseContent' || field === 'solidifiedHistory'
        || PERSISTED_CHARACTER_STATE_FIELDS.includes(field as any)
        || PERSISTED_CHARACTER_SHARED_FIELDS.includes(field as any)) continue;
      const current = fields[field];
      if (Array.isArray(value)) fields[field] = [...new Set([...rowArray(current), ...rowArray(value)])];
      else if (!safeText(current, 4000).trim() && safeText(value, 4000).trim()) fields[field] = structuredClone(value);
    }

    const merged: StateRow = {
      ...structuredClone(base),
      id: base.id,
      title: base.title,
      content: state.content || base.content,
      status: state.status || base.status,
      updatedAt: state.updatedAt || base.updatedAt,
      keywords: [...new Set([...(base.keywords ?? []), ...(state.keywords ?? [])])],
      factIds: [...new Set([...(base.factIds ?? []), ...(state.factIds ?? [])])],
      eventId: state.eventId || base.eventId,
      eventIds: [...new Set([...(base.eventIds ?? (base.eventId ? [base.eventId] : [])), ...(state.eventIds ?? (state.eventId ? [state.eventId] : []))])],
      recall: mergedRecall(base.recall, state.recall),
      lifecycle: state.lifecycle ? structuredClone(state.lifecycle) : structuredClone(base.lifecycle),
      source: base.source,
      locked: base.locked,
      lockMode: base.lockMode,
      fields,
    };
    replacementByIndex.set(baseEntry.index, merged);
    removedIndexes.add(stateEntry.index);
    idRemap.set(state.id, base.id);
    mergedCount += 1;
  }

  if (!mergedCount) return { snapshot, idRemap, mergedCount };
  snapshot[key] = rows
    .map((row, index) => replacementByIndex.get(index) ?? row)
    .filter((_row, index) => !removedIndexes.has(index));

  // 删除状态行 ID 后，同一快照内（包括当前注册表已不认识的旧自定义表）引用必须一起迁移。
  rewriteObjectReferences(snapshot, idRemap);
  return { snapshot: attachLegacyAliases(snapshot, tables), idRemap, mergedCount };
}

/** 精确改写对象 ID 引用；不按标题、正文或子串猜测。 */
export function rewriteObjectReferences(snapshot: StateSnapshot, idRemap: Map<string, string>): StateSnapshot {
  if (!idRemap.size) return snapshot;
  for (const rows of Object.values(snapshot)) {
    if (!Array.isArray(rows)) continue;
    for (const row of rows as StateRow[]) {
      const related = rowArray(row.fields?.relatedObjects);
      if (!related.length) continue;
      row.fields ||= {};
      row.fields.relatedObjects = [...new Set(related.map((id) => idRemap.get(id) ?? id))];
    }
  }
  return snapshot;
}

function mergeRowsByIdentity(existing: StateRow, incoming: StateRow): StateRow {
  const fields: Record<string, unknown> = { ...(existing.fields ?? {}) };
  for (const [key, value] of Object.entries(incoming.fields ?? {})) {
    if (Array.isArray(value)) fields[key] = [...new Set([...rowArray(fields[key]), ...rowArray(value)])];
    else if (safeText(value, 4000).trim()) fields[key] = structuredClone(value);
  }
  return {
    ...existing,
    ...incoming,
    id: existing.id,
    title: incoming.title || existing.title,
    content: incoming.content || existing.content,
    keywords: [...new Set([...(existing.keywords ?? []), ...(incoming.keywords ?? [])])],
    factIds: [...new Set([...(existing.factIds ?? []), ...(incoming.factIds ?? [])])],
    eventId: incoming.eventId || existing.eventId,
    eventIds: [...new Set([...(existing.eventIds ?? (existing.eventId ? [existing.eventId] : [])), ...(incoming.eventIds ?? (incoming.eventId ? [incoming.eventId] : []))])],
    fields,
    source: existing.source === 'manual' || incoming.source === 'manual' ? 'manual' : 'auto',
    locked: Boolean(existing.locked || incoming.locked),
    lockMode: existing.lockMode === 'all' || incoming.lockMode === 'all' ? 'all' : existing.lockMode === 'base' || incoming.lockMode === 'base' ? 'base' : undefined,
  };
}

/**
 * 模型可能在下一轮给同一对象换 row.id。这里按 event_id、规范化标题和 fact_id 继承上一快照 ID，
 * 防止同一对象在世界书同步时因稳定键漂移分裂成多条。
 */
export function preserveStableObjectIds(previous: StateSnapshot, next: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const idRemap = new Map<string, string>();
  for (const table of tables) {
    const oldRows = previous[table.key] ?? [];
    const newRows = next[table.key] ?? [];
    const oldById = new Map(oldRows.map((row) => [row.id, row]));
    const oldByEvent = new Map<string, StateRow[]>();
    const oldByTitle = new Map<string, StateRow[]>();
    const oldByFact = new Map<string, StateRow[]>();
    const newEventCounts = new Map<string, number>();
    const newTitleCounts = new Map<string, number>();
    const newFactCounts = new Map<string, number>();
    for (const row of newRows) {
      if (row.eventId) newEventCounts.set(row.eventId, (newEventCounts.get(row.eventId) ?? 0) + 1);
      const title = identityTitle(row.title);
      if (title) newTitleCounts.set(title, (newTitleCounts.get(title) ?? 0) + 1);
      for (const factId of new Set(row.factIds ?? [])) {
        newFactCounts.set(factId, (newFactCounts.get(factId) ?? 0) + 1);
      }
    }
    for (const row of oldRows) {
      if (row.eventId) oldByEvent.set(row.eventId, [...(oldByEvent.get(row.eventId) ?? []), row]);
      const title = identityTitle(row.title);
      if (title) oldByTitle.set(title, [...(oldByTitle.get(title) ?? []), row]);
      for (const factId of new Set(row.factIds ?? [])) oldByFact.set(factId, [...(oldByFact.get(factId) ?? []), row]);
    }
    const claimed = new Set<string>();
    const uniqueUnclaimed = (rows: StateRow[] | undefined): StateRow | undefined => {
      if (rows?.length !== 1 || claimed.has(rows[0].id)) return undefined;
      return rows[0];
    };
    for (const row of newRows) {
      let matched = oldById.get(row.id);
      if (matched && claimed.has(matched.id)) matched = undefined;
      if (!matched && row.eventId && newEventCounts.get(row.eventId) === 1) {
        matched = uniqueUnclaimed(oldByEvent.get(row.eventId));
      }
      const title = identityTitle(row.title);
      if (!matched && title && newTitleCounts.get(title) === 1) matched = uniqueUnclaimed(oldByTitle.get(title));
      if (!matched && row.factIds?.length) {
        const candidates = new Set<StateRow>();
        for (const factId of new Set(row.factIds)) {
          if (newFactCounts.get(factId) !== 1) continue;
          const candidate = uniqueUnclaimed(oldByFact.get(factId));
          if (candidate) candidates.add(candidate);
        }
        if (candidates.size === 1) matched = [...candidates][0];
      }
      if (!matched) continue;
      const sameTitle = title && title === identityTitle(matched.title);
      const replacedId = row.id;
      row.id = matched.id;
      if (replacedId && replacedId !== matched.id) idRemap.set(replacedId, matched.id);
      if (sameTitle) row.title = matched.title;
      claimed.add(matched.id);
    }
    const merged = new Map<string, StateRow>();
    for (const row of newRows) {
      const current = merged.get(row.id);
      merged.set(row.id, current ? mergeRowsByIdentity(current, row) : row);
    }
    next[table.key] = [...merged.values()];
  }
  rewriteObjectReferences(next, idRemap);
  return attachLegacyAliases(next, tables);
}

function regionStateText(row: StateRow): string {
  const fields = row.fields ?? {};
  return [row.title, row.content, row.status, ...rowArray(fields.currentFacts), ...rowArray(fields.currentStates), ...rowArray(fields.recentHistory), ...rowArray(fields.solidifiedHistory)].join(' ');
}

/**
 * 区域不是“当前位置”的副本。仅因进入、停留或提及地点产生的自动区域行会被剔除；
 * 有基础定义、长期历史或离开场景后仍成立的区域变化继续保留。
 */
export function enforceObjectViewAllocation(snapshot: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const spacetimeKey = tableByRole(tables, 'spacetime', false)?.key;
  const regionKey = tableByRole(tables, 'regions', false)?.key;
  if (!spacetimeKey || !regionKey) return snapshot;
  const spacetimeRows = snapshot[spacetimeKey] ?? [];
  const activeRows = spacetimeRows.filter((row) => !/(已离开|历史场景|过去场景|非当前|已结束|已关闭|已归档|inactive|closed|ended|archived)/i.test(`${row.status} ${row.content}`));
  const current = activeRows.at(-1);
  if (!current) return snapshot;
  const currentIdentity = identityTitle(current.title);
  // 自动区域必须证明自己是独立对象：有稳定基础定义、已固化历史，或离开当前场景后仍成立的变化。
  // 纯进入/停留、设施列举、路径说明和一次性提及既不能复制当前时空，也不能以“另一个地点”名义残留。
  const persistentChangeSignal = /(封锁|解封|开放|关闭|停用|启用|损坏|损毁|坍塌|重建|占领|失守|戒严|污染|净化|改造|沦陷|恢复|摧毁|建成|归属改变|控制权|驻军撤离|驻军进驻|灾害|危机解除|永久|长期持续)/i;
  const sceneOnlySignal = /(当前|进入|来到|抵达|停留|正在|位于|设有|用于|用作|配备|包含|连接|通往|内部有|内有|可供)/i;
  const stableDefinitionSignal = /(属于|隶属|管辖|地处|坐落|是一座|是一个|是一处|是一片|区域类型|建筑类型|辖区|边界|常年|主要居民|主要产业|地貌|气候|历史上)/i;
  snapshot[regionKey] = (snapshot[regionKey] ?? []).filter((row) => {
    if (row.source === 'manual' || row.locked || row.lockMode === 'all') return true;
    const fields = row.fields ?? {};
    const baseContent = safeText(fields.baseContent, 12000).trim();
    const hasHistory = rowArray(fields.solidifiedHistory).length > 0;
    const text = regionStateText(row);
    if (hasHistory || persistentChangeSignal.test(text)) return true;

    // 没有基础层或持续变化的自动行只是一次性场景记录，不应进入区域对象视图。
    if (!baseContent) return false;
    const regionIdentity = identityTitle(row.title);
    const duplicatesCurrentPath = Boolean(regionIdentity && currentIdentity && (currentIdentity.includes(regionIdentity) || regionIdentity.includes(currentIdentity)));
    if (!duplicatesCurrentPath) return true;

    // 当前路径上的区域只有明确稳定定义才保留；“设有某设施/用于某功能”仍属于时空描述。
    return stableDefinitionSignal.test(baseContent) && !sceneOnlySignal.test(baseContent.replace(stableDefinitionSignal, ''));
  });
  return attachLegacyAliases(snapshot, tables);
}

export function snapshotRowCount(snapshot?: StateSnapshot, registry?: TableDefinition[], enabledOnly = false): number {
  if (!snapshot) return 0;
  const tables = registryOrDefault(registry).filter((table) => !enabledOnly || table.enabled);
  return tables.reduce((sum, table) => sum + (snapshot[table.key]?.length ?? 0), 0);
}
/**
 * UI 新增/编辑默认创建“人工基础保护”对象；只有显式 locked=true 才升级为完全锁定。
 * 这保证玩家写下的基础不被模型改写，同时允许后续明确事实更新状态层。
 */
export function upsertManualRow(snapshot: StateSnapshot, tableKey: TableKey, row: Partial<StateRow> & { id?: string }, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  const next = normalizeSnapshot(snapshot, snapshot, tables);
  next[tableKey] ||= [];
  const index = next[tableKey].findIndex((item) => item.id === row.id);
  const normalized = normalizeRow({ ...row, source: 'manual', locked: row.locked ?? false, updatedAt: nowIso() }, tableKey, index >= 0 ? index : next[tableKey].length, index >= 0 ? next[tableKey][index] : undefined, tables);
  if (index >= 0) next[tableKey][index] = normalized; else next[tableKey].push(normalized);
  return next;
}
export function deleteRow(snapshot: StateSnapshot, tableKey: TableKey, rowId: string, registry?: TableDefinition[]): StateSnapshot {
  const next = normalizeSnapshot(snapshot, snapshot, registry);
  next[tableKey] = (next[tableKey] ?? []).filter((row) => row.id !== rowId);
  return next;
}

export function stateSchemaDescription(registry?: TableDefinition[]): string {
  const example: Record<string, unknown[]> = {};
  for (const table of enabledTables(registryOrDefault(registry))) {
    const sample: Record<string, unknown> = {
      id: `${table.key}-1`, title: table.name, content: table.purpose, keywords: [table.name], status: 'active', factIds: ['fact_1'], eventId: 'event_1',
    };
    for (const field of table.fields) {
      if (STANDARD_FIELDS.has(field.key) || field.key === 'lifecycle') continue;
      sample[field.key] = field.type === 'string[]' ? [] : '';
    }
    example[table.key] = [sample];
  }
  return JSON.stringify(example, null, 2);
}

function relevanceText(row: StateRow): string {
  return `${row.title} ${row.content} ${row.status} ${row.keywords.join(' ')}`;
}
function isPassiveObserver(row: StateRow): boolean {
  if (row.source === 'manual' || row.locked) return false;
  return isPurePassiveObserverText(relevanceText(row));
}
/** 最后一层确定性过滤：纯旁观者及其临时反应不得留在活跃视图。 */
export function filterPassiveObservers(snapshot: StateSnapshot, registry?: TableDefinition[]): StateSnapshot {
  const tables = registryOrDefault(registry);
  for (const table of tables) {
    if (!table.enabled) continue;
    snapshot[table.key] = (snapshot[table.key] ?? []).filter((row) => !isPassiveObserver(row));
  }
  return snapshot;
}
