/**
 * 模块职责：执行结构化任务、Schema 兼容回退、确定性校验与最多一次语法修复。
 * 维护边界：Schema 失败只允许一次无 Schema 回退；取消和提交失效不得触发兼容重试；
 * 已能解析但不符合业务 Schema 的结果不得交给模型猜测修复。
 */
import type { TaskKind } from '../constants';
import { getSettings } from '../core/context';
import { isLikelyTruncatedJson, JsonObjectParseError, jsonPreview, parseJsonObjectCandidates, safeText, toErrorMessage } from '../core/utils';
import type { GenerateOptions } from '../types';
import {
  describeTaskConnection,
  generateTask,
  isDefinitiveJsonSchemaUnsupported,
  isJsonSchemaRequestRejected,
  rememberJsonSchemaRejected,
  rememberJsonSchemaUnsupported,
  shouldSkipJsonSchema,
} from './generator';
import { formatSchemaIssues, validateStructuredValue, type SchemaValidationOptions } from './schema-validation';

export interface StructuredGenerationOptions extends GenerateOptions {
  task: TaskKind;
  structureDescription: string;
  allowRepair?: boolean;
  validationOptions?: SchemaValidationOptions;
  /** 供应商传输 Schema 可保持轻量；本字段用于镜渊本地完整校验。 */
  validationSchema?: Record<string, any>;
  /** 在本地完整校验前，把轻量供应商协议归一化为镜渊业务结构。 */
  candidateTransform?: (candidate: Record<string, any>) => Record<string, any>;
}

class StructuredSchemaValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'StructuredSchemaValidationError';
  }
}

function repairSystemPrompt(structureDescription: string): string {
  return `你是JSON格式修复器。你不执行原任务、不补充新事实、不解释内容，只把给定模型输出转换成一个合法JSON对象。

要求：
1. 保留原输出中已经表达的语义，不自行重做审核、总结或状态提取。
2. 删除Markdown代码围栏、解释、前言、结语和思考标签。
3. 修复缺失引号、尾随逗号、全角标点等格式问题。
4. 输出必须能被JSON.parse直接解析，根节点必须是对象。
5. 只输出JSON对象，禁止输出任何额外文字。

【目标结构】
${structureDescription}`;
}

function repairUserPrompt(raw: string): string {
  return `【需要修复的原始输出】
${safeText(raw, 80000)}`;
}

const TASK_LABELS: Record<TaskKind, string> = {
  audit: '规则审核',
  revision: '定向修正',
  state: '状态表',
  smallSummary: '小总结',
  largeSummary: '大总结',
};

function isCancelledRequest(error: unknown): boolean {
  return error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name);
}

function structuredError(task: TaskKind, error: unknown, raw: string): Error {
  const connection = describeTaskConnection(task);
  const preview = error instanceof JsonObjectParseError ? error.preview : jsonPreview(raw);
  const detail = toErrorMessage(error);
  return new Error(`${TASK_LABELS[task]}未返回有效JSON结构（${connection}）。${detail}${preview ? `；返回片段：${preview}` : ''}`);
}

function parseAndValidateStructuredOutput(
  raw: string,
  jsonSchema?: Record<string, any>,
  validationOptions: SchemaValidationOptions = {},
  candidateTransform?: (candidate: Record<string, any>) => Record<string, any>,
): Record<string, any> {
  const candidates = parseJsonObjectCandidates(raw);

  let firstIssues = '';
  for (const source of candidates) {
    let candidate: Record<string, any>;
    try {
      candidate = candidateTransform ? candidateTransform(structuredClone(source)) : source;
    } catch (error) {
      if (!firstIssues) firstIssues = toErrorMessage(error);
      continue;
    }
    if (!jsonSchema) return candidate;
    const issues = validateStructuredValue(candidate, jsonSchema, 12, validationOptions);
    if (!issues.length) return candidate;
    if (!firstIssues) firstIssues = formatSchemaIssues(issues);
  }
  throw new StructuredSchemaValidationError(`JSON可以解析，但不符合目标Schema：${firstIssues || '结构不匹配'}`);
}

export async function repairStructuredOutput(
  task: TaskKind,
  raw: string,
  structureDescription: string,
  jsonSchema?: Record<string, any>,
  validationOptions: SchemaValidationOptions = {},
  candidateTransform?: (candidate: Record<string, any>) => Record<string, any>,
): Promise<Record<string, any>> {
  const repaired = await generateTask({
    task,
    systemPrompt: repairSystemPrompt(structureDescription),
    prompt: repairUserPrompt(raw),
    requestPurpose: 'json-repair',
  });
  return parseAndValidateStructuredOutput(repaired, jsonSchema, validationOptions, candidateTransform);
}

async function generateWithSchemaFallback(options: StructuredGenerationOptions): Promise<string> {
  if (options.jsonSchema && shouldSkipJsonSchema(options.task, options.jsonSchema)) {
    return generateTask({ ...options, jsonSchema: undefined, requestPurpose: 'plain' });
  }

  let schemaFailure: unknown;
  let rejectThisSchema = false;
  try {
    const raw = await generateTask({ ...options, requestPurpose: options.jsonSchema ? 'schema' : 'plain' });
    if (!options.jsonSchema || raw.trim() !== '{}') return raw;
    schemaFailure = new Error('结构化输出返回空对象，当前模型、接口或该Schema不兼容');
    rejectThisSchema = true;
  } catch (error) {
    if (!options.jsonSchema || isCancelledRequest(error)) throw error;
    schemaFailure = error;
    if (isDefinitiveJsonSchemaUnsupported(error)) rememberJsonSchemaUnsupported(options.task);
    else rejectThisSchema = isJsonSchemaRequestRejected(error);
  }

  try {
    const fallback = await generateTask({ ...options, jsonSchema: undefined, requestPurpose: 'fallback' });
    if (rejectThisSchema && options.jsonSchema) rememberJsonSchemaRejected(options.task, options.jsonSchema);
    return fallback;
  } catch (fallbackError) {
    if (isCancelledRequest(fallbackError)) throw fallbackError;
    throw new Error(
      `${TASK_LABELS[options.task]}请求失败（${describeTaskConnection(options.task)}）。结构化请求：${toErrorMessage(schemaFailure)}；无Schema回退：${toErrorMessage(fallbackError)}`,
    );
  }
}

/**
 * 结构化任务按“Schema → 一次无 Schema 兼容回退 → 本地解析与校验 → 可选一次语法修复”执行。
 * 该顺序是有限兼容，不允许形成循环调用。
 */
export async function generateStructuredTask(options: StructuredGenerationOptions): Promise<Record<string, any>> {
  const raw = await generateWithSchemaFallback(options);
  const validationSchema = options.validationSchema ?? options.jsonSchema;
  try {
    return parseAndValidateStructuredOutput(raw, validationSchema, options.validationOptions, options.candidateTransform);
  } catch (firstError) {
    if (firstError instanceof StructuredSchemaValidationError) {
      throw structuredError(options.task, firstError, raw);
    }
    if (isLikelyTruncatedJson(raw, firstError)) {
      throw structuredError(
        options.task,
        new Error('模型输出在JSON对象结束前被截断，缺失内容无法安全修复；请缩短结构化输出或重试'),
        raw,
      );
    }
    const allowRepair = options.allowRepair ?? getSettings().repairInvalidJsonOnce;
    if (!allowRepair) throw structuredError(options.task, firstError, raw);
    try {
      return await repairStructuredOutput(options.task, raw, options.structureDescription, validationSchema, options.validationOptions, options.candidateTransform);
    } catch (repairError) {
      if (repairError instanceof Error && repairError.message.startsWith(`${TASK_LABELS[options.task]}未返回有效JSON结构`)) {
        throw repairError;
      }
      throw structuredError(options.task, repairError, raw);
    }
  }
}
