/**
 * 模块职责：解析和执行规则审核，并应用标记、隐藏或进入修正的结果。
 * 维护边界：技术故障与内容违规必须分开；缺少合法 result 的对象不能默认判为违规。
 */
import { getMessage, getSettings, messageFingerprint, toast } from '../core/context';
import { assertArtifactCommitCurrent, persistChatFor } from '../core/commit-guard';
import { hashText, isLikelyTruncatedJson, jsonPreview, parseJsonObject, safeText, toErrorMessage } from '../core/utils';
import { attachArtifactToMessage, markStage } from '../domain/artifact';
import { describeTaskConnection, generateTask, isDefinitiveJsonSchemaUnsupported, isJsonSchemaRequestRejected, rememberJsonSchemaRejected, rememberJsonSchemaUnsupported, shouldSkipJsonSchema } from '../llm/generator';
import { repairStructuredOutput } from '../llm/structured';
import { auditJsonSchema, auditSystemPrompt, auditUserPrompt } from '../prompts/audit';
import { putArtifact } from '../storage/repository';
import type { AuditResult, AuditViolation, MessageArtifact } from '../types';

function list(value: unknown, maxItems = 24): string[] {
  if (!Array.isArray(value)) return [];
  return value.map((item) => safeText(item, 2000).trim()).filter(Boolean).slice(0, maxItems);
}

function violationList(value: unknown): AuditViolation[] {
  if (!Array.isArray(value)) return [];
  return value
    .map((item: any, index) => ({
      ruleId: safeText(item?.ruleId || `rule_${index + 1}`, 120).trim() || `rule_${index + 1}`,
      rule: safeText(item?.rule, 1000).trim(),
      evidence: safeText(item?.evidence, 3000).trim(),
      action: safeText(item?.action, 3000).trim(),
    }))
    .filter((item) => item.rule || item.evidence || item.action)
    .slice(0, 24);
}

function resultFingerprint(violations: AuditViolation[]): string {
  const normalized = violations
    .map((item) => `${item.ruleId}|${item.rule}`.toLowerCase().replace(/\s+/g, ' ').trim())
    .sort()
    .join('\n');
  return normalized ? hashText(normalized) : '';
}

/** 审核结果必须显式给出合法 result；空对象和缺字段对象不做默认违规推断。 */
export function parseAuditResult(raw: unknown): AuditResult {
  const text = safeText(raw, 100000).trim();
  try {
    const data = parseJsonObject(text);
    if (!['pass', 'revise', 'block'].includes(String(data.result))) {
      throw new Error('审核结果缺少有效的result字段');
    }
    const decision = String(data.result) as AuditResult['decision'];
    const violations = violationList(data.violations);
    const passed = decision === 'pass';
    return {
      passed,
      decision,
      reason: safeText(data.reason, 3000).trim() || (passed ? '通过' : '违反规则'),
      violations: passed ? [] : violations,
      preserve: list(data.preserve),
      rewriteInstruction: safeText(data.rewriteInstruction, 6000).trim(),
      violationFingerprint: passed ? '' : resultFingerprint(violations),
      replacementText: !passed && decision === 'revise'
        ? safeText(data.replacementText ?? data.finalText, 200000).trim() || undefined
        : undefined,
    };
  } catch {
    const lines = text.replace(/\r/g, '').split('\n');
    const first = (lines[0] || '').trim().toUpperCase();
    const reason = lines.slice(1).join('\n').trim();
    if (first === 'MA_OK') {
      return {
        passed: true,
        decision: 'pass',
        reason: reason || '通过',
        violations: [],
        preserve: [],
        rewriteInstruction: '',
        violationFingerprint: '',
      };
    }
    if (first === 'MA_FAIL') {
      const violations: AuditViolation[] = [{
        ruleId: 'legacy_failure',
        rule: '审核模型判定违反玩家规则',
        evidence: reason || '未给出具体证据',
        action: reason || '依据玩家规则定向修正违规内容',
      }];
      return {
        passed: false,
        decision: 'revise',
        reason: reason || '违反规则',
        violations,
        preserve: [],
        rewriteInstruction: reason || '只修正违规内容，不改变已成立的外部事实。',
        violationFingerprint: resultFingerprint(violations),
      };
    }
    throw new Error('规则审核模型未返回有效JSON、MA_OK或MA_FAIL');
  }
}

export function findMessageElement(index: number): HTMLElement | null {
  return document.querySelector<HTMLElement>(`.mes[mesid="${index}"], .mes[data-message-id="${index}"], #chat .mes:nth-of-type(${index + 1})`);
}

export function applyAuditVisibility(index: number, hidden: boolean, marked = false): void {
  const element = findMessageElement(index);
  element?.classList.toggle('ma11-audit-hidden-message', hidden);
  element?.classList.toggle('ma11-audit-marked-message', !hidden && marked);
}

function isCancelledAuditRequest(error: unknown): boolean {
  return error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name);
}

export async function auditText(playerRules: string, playerText: string, assistantText: string): Promise<AuditResult> {
  const request = {
    task: 'audit' as const,
    systemPrompt: auditSystemPrompt(),
    prompt: auditUserPrompt(playerRules, playerText, assistantText),
  };

  let raw = '';
  let structuredRequestError: unknown;
  let rejectAuditSchema = false;
  const schema = auditJsonSchema();
  if (shouldSkipJsonSchema('audit', schema)) {
    raw = await generateTask({ ...request, requestPurpose: 'plain' });
  } else {
    try {
      raw = await generateTask({ ...request, jsonSchema: schema, requestPurpose: 'schema' });
      if (raw.trim() === '{}') {
        structuredRequestError = new Error('结构化输出返回空对象，当前模型、接口或审核Schema不兼容');
        rejectAuditSchema = true;
      }
    } catch (error) {
      if (isCancelledAuditRequest(error)) throw error;
      structuredRequestError = error;
      if (isDefinitiveJsonSchemaUnsupported(error)) rememberJsonSchemaUnsupported('audit');
      else rejectAuditSchema = isJsonSchemaRequestRejected(error);
    }
  }

  if (structuredRequestError) {
    try {
      raw = await generateTask({ ...request, requestPurpose: 'fallback' });
      if (rejectAuditSchema) rememberJsonSchemaRejected('audit', schema);
    } catch (fallbackError) {
      if (isCancelledAuditRequest(fallbackError)) throw fallbackError;
      throw new Error(
        `规则审核请求失败（${describeTaskConnection('audit')}）。结构化请求：${toErrorMessage(structuredRequestError)}；无Schema回退：${toErrorMessage(fallbackError)}`,
      );
    }
  }

  try {
    return parseAuditResult(raw);
  } catch (firstError) {
    if (isLikelyTruncatedJson(raw, firstError)) {
      throw new Error(`规则审核未返回有效结构（${describeTaskConnection('audit')}）。模型输出在JSON对象结束前被截断，无法安全修复；返回片段：${jsonPreview(raw)}`);
    }
    if (raw.trim() === '{}') {
      const prefix = structuredRequestError
        ? `结构化请求失败后，无Schema回退仍返回空对象。原错误：${toErrorMessage(structuredRequestError)}`
        : '审核模型返回空对象';
      throw new Error(`规则审核未返回有效结构（${describeTaskConnection('audit')}）。${prefix}`);
    }
    if (!getSettings().repairInvalidJsonOnce) {
      throw new Error(`规则审核未返回有效结构（${describeTaskConnection('audit')}）。${toErrorMessage(firstError)}；返回片段：${jsonPreview(raw)}`);
    }
    try {
      const repaired = await repairStructuredOutput(
        'audit',
        raw,
        '{"result":"pass|revise|block","reason":"...","violations":[{"ruleId":"...","rule":"...","evidence":"...","action":"..."}],"preserve":["..."],"rewriteInstruction":"...","replacementText":"...或空字符串"}',
        schema,
      );
      return parseAuditResult(JSON.stringify(repaired));
    } catch (repairError) {
      if (isCancelledAuditRequest(repairError)) throw repairError;
      throw new Error(`规则审核未返回有效结构（${describeTaskConnection('audit')}）。${toErrorMessage(repairError)}；原始返回片段：${jsonPreview(raw)}`);
    }
  }
}

export async function applyAuditFailureAction(
  artifact: MessageArtifact,
  action: 'mark' | 'hide' | 'delete',
): Promise<void> {
  if (action === 'mark') {
    artifact.hiddenByAudit = false;
    applyAuditVisibility(artifact.messageIndex, false, true);
    return;
  }
  if (action === 'hide') {
    artifact.hiddenByAudit = true;
    applyAuditVisibility(artifact.messageIndex, true);
    return;
  }
  artifact.hiddenByAudit = true;
  applyAuditVisibility(artifact.messageIndex, true);
  toast('warning', '审核未通过；插件不会自动删除酒馆消息，已隐藏并保留人工处理入口');
}

/**
 * 审核只决定当前正文是否通过以及后续是否需要修正；技术异常由调用方按失败状态处理。
 */
export async function runAudit(artifact: MessageArtifact, force = false): Promise<AuditResult> {
  const settings = getSettings();
  artifact.stages.revision ||= { status: 'idle', attempts: 0 };
  if (!settings.auditEnabled) {
    markStage(artifact, 'audit', 'skipped');
    markStage(artifact, 'revision', 'skipped');
    artifact.hiddenByAudit = false;
    applyAuditVisibility(artifact.messageIndex, false, false);
    artifact.audit = {
      passed: true,
      decision: 'pass',
      reason: '未启用规则审核',
      violations: [],
      preserve: [],
      rewriteInstruction: '',
      violationFingerprint: '',
    };
    await putArtifact(artifact);
    return artifact.audit;
  }
  if (!settings.auditPrompt.trim()) throw new Error('已启用规则审核，但审核提示词为空');
  const ruleFingerprint = hashText(`${settings.auditPrompt}\n${settings.auditFailAction}\n${settings.maxRevisionAttempts}`);
  if (
    !force
    && artifact.stages.audit.status === 'success'
    && artifact.audit?.passed
    && artifact.approvedFingerprint === artifact.sourceFingerprint
    && (!(artifact as any).auditRuleFingerprint || (artifact as any).auditRuleFingerprint === ruleFingerprint)
  ) {
    (artifact as any).auditRuleFingerprint = ruleFingerprint;
    return artifact.audit;
  }

  markStage(artifact, 'audit', 'running');
  await putArtifact(artifact);
  try {
    const result = await auditText(settings.auditPrompt, artifact.playerText, artifact.assistantText);
    assertArtifactCommitCurrent(artifact);
    artifact.audit = result;
    (artifact as any).auditRuleFingerprint = ruleFingerprint;
    if (result.passed) {
      artifact.approvedFingerprint = artifact.sourceFingerprint;
      artifact.hiddenByAudit = false;
      applyAuditVisibility(artifact.messageIndex, false, false);
      markStage(artifact, 'audit', 'success');
      markStage(artifact, 'revision', 'skipped');
    } else {
      markStage(artifact, 'audit', 'blocked', result.reason);
    }
    const message = getMessage(artifact.messageIndex);
    if (!message) throw new Error('原AI正文已不存在，请重新整理');
    attachArtifactToMessage(message, artifact);
    await persistChatFor(artifact.chatKey);
    await putArtifact(artifact);
    return result;
  } catch (error) {
    if (error instanceof Error && ['AbortError', 'CommitRejectedError'].includes(error.name)) throw error;
    markStage(artifact, 'audit', 'failed', toErrorMessage(error));
    await putArtifact(artifact);
    throw error;
  }
}
