/**
 * 模块职责：解析当前聊天世界书并差异化发布、暂停或清理镜渊条目。
 * 维护边界：普通同步只按当前 chatKey 的 managedKey / logicalKey 匹配；备注、精确签名
 * 与旧 small/large 键只在玩家主动维护时检查，禁止影响人工条目、其他插件或其他聊天。
 */
import { VERSION } from '../constants';
import { assertArtifactCommitCurrent, assertChatCommitCurrent, persistMetadataFor } from '../core/commit-guard';
import { currentChatKey, getChatMetadataNamespace, getContext, getSettings } from '../core/context';
import { hashText, sanitizeBookName, toErrorMessage } from '../core/utils';
import { markStage } from '../domain/artifact';
import { getChatState, putArtifact, putChatState } from '../storage/repository';
import { TaskBlockedError } from './task-queue';
import { buildLorebookDocuments } from '../domain/lorebook-publish';
import type { MessageArtifact } from '../types';

let worldInfoModulePromise: Promise<any> | null = null;
let worldInfoApiForTests: any | null = null;
const lorebookMutationLocks = new Map<string, Promise<unknown>>();

export function resetLorebookRuntime(): void {
  worldInfoModulePromise = null;
  worldInfoApiForTests = null;
  lorebookMutationLocks.clear();
}

/** Node 集成测试使用；生产环境未设置时仍只加载 SillyTavern 的 world-info 模块。 */
export function setLorebookWorldInfoApiForTests(api: any | null): void {
  worldInfoApiForTests = api;
  worldInfoModulePromise = null;
}

async function worldInfoApi(): Promise<any> {
  if (worldInfoApiForTests) return worldInfoApiForTests;
  if (!worldInfoModulePromise) {
    const moduleUrl = '/scripts/world-info.js';
    worldInfoModulePromise = import(/* @vite-ignore */ moduleUrl);
  }
  return worldInfoModulePromise;
}

async function withLorebookMutation<T>(name: string, action: () => Promise<T>): Promise<T> {
  const lockKey = sanitizeBookName(name);
  if (!lockKey) return action();
  const previous = lorebookMutationLocks.get(lockKey) ?? Promise.resolve();
  const current = previous.catch(() => undefined).then(action);
  lorebookMutationLocks.set(lockKey, current);
  try {
    return await current;
  } finally {
    if (lorebookMutationLocks.get(lockKey) === current) lorebookMutationLocks.delete(lockKey);
  }
}

function generatedBookName(chatKey = currentChatKey()): string {
  const context = getContext();
  const display = sanitizeBookName(context.name2 || context.name1 || 'Chat') || 'Chat';
  return sanitizeBookName(`MA_${display}_${hashText(chatKey).slice(0, 8)}`);
}

function isDedicatedGeneratedBook(name: string, chatKey: string): boolean {
  return !sanitizeBookName(getSettings().lorebookName) && name === generatedBookName(chatKey);
}

function resolveTargetBookName(create: boolean, chatKey = currentChatKey()): string {
  const settings = getSettings();
  const meta = getChatMetadataNamespace();
  const context = getContext();
  let name = sanitizeBookName(settings.lorebookName || meta.lorebookName || context.chatMetadata?.world_info || '');
  if (!name && create && settings.autoCreateLorebook) name = generatedBookName(chatKey);
  return name;
}

async function ensureLorebook(name: string, chatKey: string, artifact?: MessageArtifact): Promise<any> {
  const assertCurrent = () => {
    if (artifact) assertArtifactCommitCurrent(artifact);
    else assertChatCommitCurrent(chatKey);
  };
  assertCurrent();
  const wi = await worldInfoApi();
  assertCurrent();
  let data = await wi.loadWorldInfo(name);
  assertCurrent();
  if (!data && typeof wi.createNewWorldInfo === 'function') {
    assertCurrent();
    await wi.createNewWorldInfo(name, { interactive: false });
    assertCurrent();
    data = await wi.loadWorldInfo(name);
    assertCurrent();
  }
  if (!data) {
    data = { entries: {} };
    assertCurrent();
    await wi.saveWorldInfo(name, data, true);
    assertCurrent();
  }
  const context = getContext();
  const meta = getChatMetadataNamespace();
  assertCurrent();
  context.chatMetadata ||= {};
  context.chatMetadata[wi.METADATA_KEY || 'world_info'] = name;
  meta.lorebookName = name;
  await persistMetadataFor(chatKey);
  assertCurrent();
  refreshChatLorebookIndicator(name);
  return wi;
}

/** 只有带当前模块 managed 元数据的条目才属于镜渊管理范围。 */
function managedInfo(entry: any): any {
  return entry?.extensions?.mirrorAbyssV11 ?? null;
}

function managedContentIdentity(value: unknown): string {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function managedCommentIdentity(value: unknown): string {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

/** 只把带镜渊固定备注前缀的条目视为可识别旧副本，普通人工条目不参与精确清理。 */
export function isMirrorAbyssGeneratedEntry(entry: any): boolean {
  return /^\[MA11\]\s+MA[｜|]/.test(managedCommentIdentity(entry?.comment));
}

/** 备注与正文共同组成精确签名；仅正文相似不会触发删除。 */
export function mirrorAbyssExactIdentity(comment: unknown, content: unknown): string {
  const normalizedComment = managedCommentIdentity(comment);
  const normalizedContent = managedContentIdentity(content);
  return normalizedComment && normalizedContent ? `${normalizedComment}\n${normalizedContent}` : '';
}

/**
 * 逻辑键是刷新/迁移后的第二身份。优先读托管元数据；旧摘要再从正文事件线恢复，
 * 对象条目最后才从完整备注恢复。不能只凭相似正文推断，否则共享世界书会误接管其他聊天。
 */
function legacyLogicalKey(entry: any, info: any): string {
  const explicit = String(info?.logicalKey || '').trim();
  if (explicit) return explicit;
  const comment = managedCommentIdentity(entry?.comment);
  const content = managedContentIdentity(entry?.content);
  if (/^\[MA11\]\s+MA[｜|]大总结(?:[｜|]|$)/.test(comment)) {
    const eventId = content.match(/\[长期事件线[：:]\s*([^\]\n]+)\]/)?.[1]?.trim();
    return eventId ? `large:event:${eventId}` : 'large:current';
  }
  if (/^\[MA11\]\s+MA[｜|]小总结(?:[｜|]|$)/.test(comment)) {
    const eventId = content.match(/\[事件线[：:]\s*([^\]\n]+)\]/)?.[1]?.trim();
    if (eventId) return `small:event:${eventId}`;
  }
  return '';
}

/**
 * 刷新 SillyTavern 世界书列表和编辑器。
 *
 * saveWorldInfo 只保证服务端与缓存更新；reloadEditor 只是同步触发下拉框 change。
 * 先更新 world_names，再重载当前编辑器；目标书正在显示或人工强制同步时，继续等待
 * showWorldEditor 完成实际 DOM 重绘，避免必须切换聊天后才能看到新条目。
 */
export async function reloadWorldInfoEditor(
  wi: any,
  name: string,
  loadIfNotSelected = false,
): Promise<boolean> {
  const context = getContext();
  const updateList = context.updateWorldInfoList ?? wi.updateWorldInfoList;
  if (typeof updateList === 'function') {
    await Promise.resolve(updateList.call(context));
  }

  const names = typeof context.getWorldInfoNames === 'function'
    ? context.getWorldInfoNames()
    : Array.isArray(wi.world_names)
      ? [...wi.world_names]
      : [];
  // 新建书偶尔会晚一拍进入下拉列表。这里不把列表滞后当成保存失败；
  // 后续 showWorldEditor 可以直接按书名读取缓存并重绘。
  const listed = !names.length || names.includes(name);

  const editorSelect = document.querySelector<HTMLSelectElement>('#world_editor_select');
  const selectedName = editorSelect?.selectedOptions?.[0]?.textContent?.trim() ?? '';
  const shouldRenderTarget = loadIfNotSelected || selectedName === name;
  const contextReload = context.reloadWorldInfoEditor;
  const moduleReload = wi.reloadEditor ?? wi.reloadWorldInfoEditor;
  const reload = contextReload ?? moduleReload;
  if (typeof reload === 'function' && listed) {
    await Promise.resolve(reload.call(contextReload ? context : wi, name, loadIfNotSelected));
  }

  if (shouldRenderTarget && typeof wi.showWorldEditor === 'function') {
    await wi.showWorldEditor(name);
    return true;
  } else if (typeof reload === 'function') {
    // change 事件由 SillyTavern 异步处理；至少让当前事件循环完成再返回。
    await new Promise<void>((resolve) => window.setTimeout(resolve, 0));
  }
  return false;
}

/** 聊天世界书关联写入后立即刷新按钮状态，不再等待下一次 CHAT_CHANGED。 */
function refreshChatLorebookIndicator(name: string): void {
  if (typeof document?.querySelectorAll !== 'function') return;
  const linked = Boolean(name);
  document.querySelectorAll<HTMLElement>('.chat_lorebook_button').forEach((button) => {
    button.classList.toggle('world_set', linked);
  });
}

function escapeRegex(value: string): string {
  return String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

export function triggerKeys(spec: any): string[] {
  const trigger = spec.trigger ?? { any: spec.keywords ?? [], all: [], exclude: [] };
  const any = Array.isArray(trigger.any) ? trigger.any.filter(Boolean) : [];
  const all = Array.isArray(trigger.all) ? trigger.all.filter(Boolean) : [];
  const exclude = Array.isArray(trigger.exclude) ? trigger.exclude.filter(Boolean) : [];
  if (!all.length && !exclude.length) return any;
  const anyLookahead = any.length ? `(?=[\\s\\S]*(?:${any.map(escapeRegex).join('|')}))` : '';
  const allLookaheads = all.map((item: string) => `(?=[\\s\\S]*${escapeRegex(item)})`).join('');
  const excludeLookahead = exclude.length ? `(?![\\s\\S]*(?:${exclude.map(escapeRegex).join('|')}))` : '';
  return [`/${excludeLookahead}${allLookaheads}${anyLookahead}[\\s\\S]*/i`];
}

function applyEntry(entry: any, chatKey: string, key: string, spec: any, wi: any): void {
  entry.comment = spec.comment;
  entry.content = spec.content;
  entry.constant = spec.recallMode === 'constant';
  entry.vectorized = spec.recallMode === 'vector';
  entry.key = spec.recallMode === 'trigger' ? triggerKeys(spec) : [];
  entry.keysecondary = [];
  entry.selective = false;
  entry.disable = false;
  entry.addMemo = true;
  entry.position = wi.world_info_position?.after ?? 1;
  // order 仅用于世界书编辑器显示顺序，不参与镜渊的记忆取舍。
  entry.order = spec.order;
  entry.preventRecursion = false;
  entry.excludeRecursion = false;
  entry.delayUntilRecursion = 0;
  entry.extensions ||= {};
  entry.extensions.mirrorAbyssV11 = {
    managed: true,
    chatKey,
    key,
    logicalKey: spec.logicalKey || key,
    kind: spec.kind,
    version: VERSION,
    recallMode: spec.recallMode,
    trigger: spec.trigger,
    vector: spec.vector,
    factIds: spec.factIds,
    eventIds: spec.eventIds,
  };
}

interface DesiredLorebookPlan {
  desired: Map<string, any>;
}

function summaryEventKey(item: any): string {
  return String(item?.eventId || item?.id || '').trim();
}

async function desiredSpecs(artifact: MessageArtifact): Promise<DesiredLorebookPlan> {
  const settings = getSettings();
  const state = await getChatState(artifact.chatKey);
  const documents = buildLorebookDocuments(
    artifact.snapshot,
    state.smallSummaries,
    state.largeSummaries,
    {
      layout: settings.lorebookLayout,
      vectorize: settings.vectorizeRows,
      latestContinuityConstant: settings.latestContinuityConstant,
      registry: settings.tableRegistry,
      internalFacts: state.internalFacts,
      similarityThreshold: settings.lorebookRecall.similarityThreshold,
      maxVectorResults: settings.lorebookRecall.maxVectorResults,
      totalCapacity: settings.lorebookRecall.totalCapacity,
      focusObjectId: state.focusObjectId,
    },
  );
  const desired = new Map(documents.map((document) => [document.key, document]));
  return { desired };
}

async function legacyCleanupScope(artifact: MessageArtifact): Promise<LorebookCleanupScope> {
  const state = await getChatState(artifact.chatKey);
  const logicalKeys = new Set<string>();
  const legacyKeys = new Set<string>();
  const comments = new Set<string>();
  for (const item of state.smallSummaries) {
    const eventKey = summaryEventKey(item);
    if (eventKey) logicalKeys.add(`small:event:${eventKey}`);
    legacyKeys.add(`small:${item.id}`);
    comments.add(managedCommentIdentity(`[MA11] MA｜小总结｜${item.title}`));
  }
  for (const item of state.largeSummaries) {
    const eventKey = summaryEventKey(item);
    if (eventKey) logicalKeys.add(`large:event:${eventKey}`);
    logicalKeys.add('large:current');
    legacyKeys.add(`large:${item.id}`);
    comments.add(managedCommentIdentity(`[MA11] MA｜大总结｜${item.title}`));
  }
  return { logicalKeys, legacyKeys, comments };
}


type ReconcilePair = {
  uid: string;
  entry: any;
  info: any;
  key: string;
  logicalKey: string;
  commentIdentity: string;
  exactIdentity: string;
  currentScope: boolean;
  generated: boolean;
};

export interface LorebookCleanupScope {
  logicalKeys?: Set<string>;
  legacyKeys?: Set<string>;
  comments?: Set<string>;
}

export interface LorebookReconcileResult {
  changed: boolean;
  entryIds: number[];
  created: number;
  adoptedLegacy: number;
  removed: number;
}

function legacyManagedKey(key: string): boolean {
  return (key.startsWith('small:') && !key.startsWith('small:event:'))
    || (key.startsWith('large:') && key !== 'large:current' && !key.startsWith('large:event:'));
}

function appendPair(index: Map<string, ReconcilePair[]>, key: string, pair: ReconcilePair): void {
  if (!key) return;
  index.set(key, [...(index.get(key) ?? []), pair]);
}

/**
 * 普通同步的唯一身份顺序：
 *
 * 1. 当前 chatKey + managedKey；
 * 2. 当前 chatKey + 两侧唯一 logicalKey；
 * 3. 否则创建。
 *
 * owner 未知与其他 chatKey 条目完全不进入普通同步候选。旧键和歧义 logicalKey 留给
 * 玩家主动维护，避免热路径中的历史猜测和顺序接管。
 */
export function reconcileLorebookEntries(
  data: any,
  desired: Map<string, any>,
  chatKey: string,
  wi: any,
  name: string,
  _dedicatedBook = false,
  _cleanup: LorebookCleanupScope = {},
): LorebookReconcileResult {
  data.entries ||= {};
  const pairs: ReconcilePair[] = [];
  const currentByKey = new Map<string, ReconcilePair[]>();
  const currentByLogical = new Map<string, ReconcilePair[]>();

  for (const [uid, entry] of Object.entries<any>(data.entries)) {
    const info = managedInfo(entry);
    const currentScope = Boolean(info?.managed && info.chatKey === chatKey);
    if (!currentScope) continue;
    const pair: ReconcilePair = {
      uid,
      entry,
      info,
      key: String(info?.key || ''),
      logicalKey: legacyLogicalKey(entry, info),
      commentIdentity: managedCommentIdentity(entry.comment),
      exactIdentity: mirrorAbyssExactIdentity(entry.comment, entry.content),
      currentScope,
      generated: isMirrorAbyssGeneratedEntry(entry),
    };
    pairs.push(pair);
    appendPair(currentByKey, pair.key, pair);
    appendPair(currentByLogical, pair.logicalKey, pair);
  }

  let changed = false;
  let created = 0;
  let removed = 0;
  const claimed = new Set<string>();
  const duplicateManaged = new Set<string>();
  const protectedAmbiguous = new Set<string>();
  const entryIds: number[] = [];
  const desiredLogicalCounts = new Map<string, number>();
  for (const [key, spec] of desired) {
    const logicalKey = String(spec.logicalKey || key);
    desiredLogicalCounts.set(logicalKey, (desiredLogicalCounts.get(logicalKey) ?? 0) + 1);
  }
  const stablePairOrder = (left: ReconcilePair, right: ReconcilePair) => {
    const leftNumber = Number(left.uid);
    const rightNumber = Number(right.uid);
    if (Number.isFinite(leftNumber) && Number.isFinite(rightNumber) && leftNumber !== rightNumber) {
      return leftNumber - rightNumber;
    }
    return left.uid.localeCompare(right.uid);
  };
  const desiredItems = [...desired.entries()].map(([key, spec]) => ({
    key,
    spec,
    logicalKey: String(spec.logicalKey || key),
    commentIdentity: managedCommentIdentity(spec.comment),
    exactIdentity: mirrorAbyssExactIdentity(spec.comment, spec.content),
    pair: undefined as ReconcilePair | undefined,
  }));

  // 第一遍先预留所有 managedKey 命中，避免 desired Map 顺序让 logicalKey 抢走稳定 UID。
  for (const item of desiredItems) {
    const keyCandidates = (currentByKey.get(item.key) ?? [])
      .filter((pair) => !claimed.has(pair.uid))
      .sort(stablePairOrder);
    item.pair = keyCandidates[0];
    if (item.pair) claimed.add(item.pair.uid);
    if (item.pair && keyCandidates.length > 1) {
      for (const duplicate of keyCandidates.slice(1)) duplicateManaged.add(duplicate.uid);
    }
  }

  // 第二遍只允许新旧两侧均唯一、且未被 managedKey 预留的 logicalKey 接管。
  for (const item of desiredItems) {
    if (item.pair) continue;
    const logicalCandidates = (currentByLogical.get(item.logicalKey) ?? [])
        .filter((candidate) => !claimed.has(candidate.uid) && !duplicateManaged.has(candidate.uid));
    const logicalUniqueOnBothSides = logicalCandidates.length === 1
      && desiredLogicalCounts.get(item.logicalKey) === 1;
    if (logicalUniqueOnBothSides) {
      item.pair = logicalCandidates[0];
      claimed.add(item.pair.uid);
    } else if (logicalCandidates.length) {
      for (const candidate of logicalCandidates) protectedAmbiguous.add(candidate.uid);
    }
  }

  for (const item of desiredItems) {
    let pair = item.pair;
    let entry = pair?.entry;
    if (!entry) {
      entry = wi.createWorldInfoEntry(name, data);
      if (!entry) throw new Error(`世界书条目创建失败：${item.key}`);
      const createdUid = String(entry.uid ?? Object.entries<any>(data.entries).find(([, value]) => value === entry)?.[0] ?? '');
      if (!createdUid) throw new Error(`世界书条目缺少UID：${item.key}`);
      pair = {
        uid: createdUid,
        entry,
        info: null,
        key: item.key,
        logicalKey: item.logicalKey,
        commentIdentity: item.commentIdentity,
        exactIdentity: item.exactIdentity,
        currentScope: true,
        generated: true,
      };
      created += 1;
      changed = true;
    }

    claimed.add(pair.uid);
    const before = JSON.stringify(entry);
    applyEntry(entry, chatKey, item.key, item.spec, wi);
    if (before !== JSON.stringify(entry)) changed = true;
    if (Number.isFinite(Number(entry.uid))) entryIds.push(Number(entry.uid));
  }

  for (const pair of pairs) {
    if (claimed.has(pair.uid)) continue;
    if (protectedAmbiguous.has(pair.uid)) continue;
    if (legacyManagedKey(pair.key)) continue;
    if (!duplicateManaged.has(pair.uid) && !pair.currentScope) continue;
    delete data.entries[pair.uid];
    removed += 1;
    changed = true;
  }

  return { changed, entryIds, created, adoptedLegacy: 0, removed };
}

/**
 * 玩家主动维护使用的历史归并器。它保留备注、精确签名和旧键考古，但共享书里 owner
 * 未知的条目只统计、不接管、不删除；明确属于其他 chatKey 的条目始终不可写。
 */
export function reconcileLorebookMaintenanceEntries(
  data: any,
  desired: Map<string, any>,
  chatKey: string,
  wi: any,
  name: string,
  dedicatedBook = false,
  cleanup: LorebookCleanupScope = {},
): LorebookReconcileResult {
  data.entries ||= {};
  const pairs: ReconcilePair[] = [];
  const currentByKey = new Map<string, ReconcilePair[]>();
  const currentByLogical = new Map<string, ReconcilePair[]>();
  const currentByComment = new Map<string, ReconcilePair[]>();
  const currentByExact = new Map<string, ReconcilePair[]>();
  const adoptableByLogical = new Map<string, ReconcilePair[]>();
  const adoptableByComment = new Map<string, ReconcilePair[]>();
  const adoptableByExact = new Map<string, ReconcilePair[]>();

  for (const [uid, entry] of Object.entries<any>(data.entries)) {
    const info = managedInfo(entry);
    const currentScope = Boolean(info?.managed && info.chatKey === chatKey);
    const generated = isMirrorAbyssGeneratedEntry(entry);
    const ownerUnknown = generated && (!info?.managed || !info?.chatKey);
    if (!currentScope && !(dedicatedBook && ownerUnknown)) continue;
    const pair: ReconcilePair = {
      uid,
      entry,
      info,
      key: String(info?.key || ''),
      logicalKey: legacyLogicalKey(entry, info),
      commentIdentity: managedCommentIdentity(entry.comment),
      exactIdentity: mirrorAbyssExactIdentity(entry.comment, entry.content),
      currentScope,
      generated,
    };
    pairs.push(pair);
    if (currentScope) {
      appendPair(currentByKey, pair.key, pair);
      appendPair(currentByLogical, pair.logicalKey, pair);
      appendPair(currentByComment, pair.commentIdentity, pair);
      appendPair(currentByExact, pair.exactIdentity, pair);
    }
    if (dedicatedBook && ownerUnknown) {
      appendPair(adoptableByLogical, pair.logicalKey, pair);
      appendPair(adoptableByComment, pair.commentIdentity, pair);
      appendPair(adoptableByExact, pair.exactIdentity, pair);
    }
  }

  let changed = false;
  let created = 0;
  let adoptedLegacy = 0;
  let removed = 0;
  const claimed = new Set<string>();
  const entryIds: number[] = [];
  const takeUnique = (items: ReconcilePair[] | undefined) => {
    const available = (items ?? []).filter((pair) => !claimed.has(pair.uid));
    return available.length === 1 ? available[0] : undefined;
  };

  for (const [key, spec] of desired) {
    const logicalKey = String(spec.logicalKey || key);
    const commentIdentity = managedCommentIdentity(spec.comment);
    const exactIdentity = mirrorAbyssExactIdentity(spec.comment, spec.content);
    let pair = takeUnique(currentByKey.get(key))
      ?? takeUnique(currentByLogical.get(logicalKey))
      ?? takeUnique(currentByComment.get(commentIdentity))
      ?? takeUnique(currentByExact.get(exactIdentity));
    if (!pair && dedicatedBook) {
      pair = takeUnique(adoptableByLogical.get(logicalKey))
        ?? takeUnique(adoptableByComment.get(commentIdentity))
        ?? takeUnique(adoptableByExact.get(exactIdentity));
      if (pair) adoptedLegacy += 1;
    }

    let entry = pair?.entry;
    if (!entry) {
      entry = wi.createWorldInfoEntry(name, data);
      if (!entry) throw new Error(`世界书条目创建失败：${key}`);
      const createdUid = String(
        entry.uid ?? Object.entries<any>(data.entries).find(([, value]) => value === entry)?.[0] ?? '',
      );
      if (!createdUid) throw new Error(`世界书条目缺少UID：${key}`);
      pair = {
        uid: createdUid,
        entry,
        info: null,
        key,
        logicalKey,
        commentIdentity,
        exactIdentity,
        currentScope: true,
        generated: true,
      };
      created += 1;
      changed = true;
    }
    claimed.add(pair.uid);
    const before = JSON.stringify(entry);
    applyEntry(entry, chatKey, key, spec, wi);
    if (before !== JSON.stringify(entry)) changed = true;
    if (Number.isFinite(Number(entry.uid))) entryIds.push(Number(entry.uid));
  }

  for (const pair of pairs) {
    if (claimed.has(pair.uid)) continue;
    const ownerUnknown = pair.generated && (!pair.info?.managed || !pair.info?.chatKey);
    const oldKeyInScope = pair.currentScope && (
      legacyManagedKey(pair.key)
      || Boolean(pair.key && cleanup.legacyKeys?.has(pair.key))
      || Boolean(pair.logicalKey && cleanup.logicalKeys?.has(pair.logicalKey))
      || Boolean(pair.commentIdentity && cleanup.comments?.has(pair.commentIdentity))
    );
    if (!oldKeyInScope && !(dedicatedBook && ownerUnknown)) continue;
    delete data.entries[pair.uid];
    removed += 1;
    changed = true;
  }

  return { changed, entryIds, created, adoptedLegacy, removed };
}

/**
 * 基于最新成功状态及总结执行差异同步；写入前后持续校验 artifact 是否仍然有效。
 */
async function syncLorebookOnce(
  artifact: MessageArtifact,
  name: string,
  force = false,
  options: { allowHistoryRecovery?: boolean } = {},
): Promise<void> {
  assertArtifactCommitCurrent(artifact);
  if (!artifact.snapshot || artifact.stages.state.status !== 'success') {
    throw new Error('没有成功状态表，停止世界书同步');
  }
  const settings = getSettings();
  if (!settings.lorebookSync && !force) {
    markStage(artifact, 'sync', 'skipped');
    await putArtifact(artifact);
    return;
  }
  markStage(artifact, 'sync', 'running');
  await putArtifact(artifact);
  const chatState = await getChatState(artifact.chatKey);
  if (chatState.historyInvalidation) {
    const recovery = chatState.historyRecovery as any;
    const recoveryAuthorized = Boolean(
      options.allowHistoryRecovery
      && recovery?.phase === 'publishing-lorebook'
      && chatState.latestSnapshotMessageKey === artifact.messageKey,
    );
    if (!recoveryAuthorized) {
      markStage(artifact, 'sync', 'blocked', '历史消息已变化，等待历史重建完成');
      chatState.lastSyncStatus = 'failed';
      chatState.lastSyncError = chatState.historyInvalidation.startIndex === undefined
        ? '历史删除位置未知，请先选择重算起点'
        : `第 ${chatState.historyInvalidation.startIndex + 1} 条消息之后的数据需要重算`;
      await putArtifact(artifact);
      await putChatState(chatState);
      throw new TaskBlockedError(chatState.lastSyncError);
    }
  }

  try {
    const wi = await ensureLorebook(name, artifact.chatKey, artifact);
    if (!name) throw new Error('没有可用的聊天世界书');
    const data = (await wi.loadWorldInfo(name)) || { entries: {} };
    data.entries ||= {};
    const plan = await desiredSpecs(artifact);
    const desired = plan.desired;
    const dedicatedBook = isDedicatedGeneratedBook(name, artifact.chatKey);
    const reconciliation = reconcileLorebookEntries(data, desired, artifact.chatKey, wi, name, dedicatedBook);
    const changed = reconciliation.changed;
    let entryIds = reconciliation.entryIds;
    assertArtifactCommitCurrent(artifact);
    if (changed) {
      await wi.saveWorldInfo(name, data, true);
      assertArtifactCommitCurrent(artifact);

      // 只有实际保存后做一次回读确认，清除保存路径回流的同 managedKey 副本。
      const verifiedData = (await wi.loadWorldInfo(name)) || data;
      const verification = reconcileLorebookEntries(
        verifiedData,
        desired,
        artifact.chatKey,
        wi,
        name,
        dedicatedBook,
      );
      entryIds = verification.entryIds;
      if (verification.changed) {
        assertArtifactCommitCurrent(artifact);
        await wi.saveWorldInfo(name, verifiedData, true);
        assertArtifactCommitCurrent(artifact);
      }

      const renderedTarget = await reloadWorldInfoEditor(wi, name, force);
      assertArtifactCommitCurrent(artifact);
      if (renderedTarget) {
        // 仅当 showWorldEditor 确实重绘目标书时，才检查编辑器旧缓存的延迟回写。
        const postReloadData = (await wi.loadWorldInfo(name)) || verifiedData;
        const postReloadVerification = reconcileLorebookEntries(
          postReloadData,
          desired,
          artifact.chatKey,
          wi,
          name,
          dedicatedBook,
        );
        entryIds = postReloadVerification.entryIds;
        if (postReloadVerification.changed) {
          assertArtifactCommitCurrent(artifact);
          await wi.saveWorldInfo(name, postReloadData, true);
          assertArtifactCommitCurrent(artifact);
        }
      }
    }
    assertArtifactCommitCurrent(artifact);
    artifact.lorebookEntryIds = entryIds;
    markStage(artifact, 'sync', 'success');
    chatState.lastLorebookName = name;
    chatState.lastSyncAt = new Date().toISOString();
    chatState.lastSyncStatus = 'success';
    chatState.lastSyncError = undefined;
    await putArtifact(artifact);
    await putChatState(chatState);
  } catch (error) {
    if (error instanceof Error && error.name === 'CommitRejectedError') throw error;
    const message = toErrorMessage(error);
    markStage(artifact, 'sync', 'failed', message);
    chatState.lastSyncStatus = 'failed';
    chatState.lastSyncError = message;
    await putArtifact(artifact);
    await putChatState(chatState);
    throw error;
  }
}

/** 所有世界书写操作按最终物理书名串行；chatKey 只定义条目归属，不作为物理锁。 */
export async function syncLorebook(
  artifact: MessageArtifact,
  force = false,
  options: { allowHistoryRecovery?: boolean } = {},
): Promise<void> {
  assertArtifactCommitCurrent(artifact);
  const settings = getSettings();
  const name = resolveTargetBookName(true, artifact.chatKey);
  if (!settings.lorebookSync && !force) {
    await syncLorebookOnce(artifact, name, force, options);
    return;
  }
  if (!name) throw new Error('没有可用的聊天世界书');
  await withLorebookMutation(name, async () => {
    assertArtifactCommitCurrent(artifact);
    await syncLorebookOnce(artifact, name, force, options);
  });
}

export interface LorebookMaintenancePreview {
  applied: boolean;
  name: string;
  dedicatedBook: boolean;
  currentManaged: number;
  legacyCandidates: number;
  removable: number;
  protectedUnknown: number;
  protectedForeign: number;
  removed: number;
}

function maintenancePreviewFromData(
  data: any,
  name: string,
  chatKey: string,
  dedicatedBook: boolean,
): LorebookMaintenancePreview {
  let currentManaged = 0;
  let legacyCandidates = 0;
  let removable = 0;
  let protectedUnknown = 0;
  let protectedForeign = 0;
  for (const entry of Object.values<any>(data?.entries ?? {})) {
    const info = managedInfo(entry);
    const generated = isMirrorAbyssGeneratedEntry(entry);
    if (info?.managed && info.chatKey === chatKey) {
      currentManaged += 1;
      const key = String(info.key || '');
      if (!key || legacyManagedKey(key)) {
        legacyCandidates += 1;
        removable += 1;
      }
      continue;
    }
    if (info?.managed && info.chatKey && info.chatKey !== chatKey) {
      protectedForeign += 1;
      continue;
    }
    if (generated && (!info?.managed || !info?.chatKey)) {
      legacyCandidates += 1;
      if (dedicatedBook) removable += 1;
      else protectedUnknown += 1;
    }
  }
  return {
    applied: false,
    name,
    dedicatedBook,
    currentManaged,
    legacyCandidates,
    removable,
    protectedUnknown,
    protectedForeign,
    removed: 0,
  };
}

/**
 * 玩家维护的只读预览。不创建世界书、不保存、不写聊天 metadata。
 */
export async function previewLorebookMaintenance(
  artifact: MessageArtifact,
): Promise<LorebookMaintenancePreview> {
  assertArtifactCommitCurrent(artifact);
  const name = resolveTargetBookName(false, artifact.chatKey);
  if (!name) return maintenancePreviewFromData(null, '', artifact.chatKey, false);
  return withLorebookMutation(name, async () => {
    assertArtifactCommitCurrent(artifact);
    const wi = await worldInfoApi();
    assertArtifactCommitCurrent(artifact);
    const data = await wi.loadWorldInfo(name);
    assertArtifactCommitCurrent(artifact);
    return maintenancePreviewFromData(
      data,
      name,
      artifact.chatKey,
      isDedicatedGeneratedBook(name, artifact.chatKey),
    );
  });
}

/**
 * 玩家确认后的维护执行。共享书 owner 未知条目不会进入写集合；执行时重新加载和规划，
 * 不信任预览阶段的 UID。调用者随后仍应执行一次普通 sync 来提交同步状态。
 */
export async function applyLorebookMaintenance(
  artifact: MessageArtifact,
): Promise<LorebookMaintenancePreview> {
  assertArtifactCommitCurrent(artifact);
  if (!artifact.snapshot || artifact.stages.state.status !== 'success') {
    throw new Error('没有成功状态表，停止世界书维护');
  }
  const name = resolveTargetBookName(true, artifact.chatKey);
  if (!name) throw new Error('没有可用的聊天世界书');
  return withLorebookMutation(name, async () => {
    assertArtifactCommitCurrent(artifact);
    const wi = await ensureLorebook(name, artifact.chatKey, artifact);
    assertArtifactCommitCurrent(artifact);
    const data = (await wi.loadWorldInfo(name)) || { entries: {} };
    assertArtifactCommitCurrent(artifact);
    data.entries ||= {};
    const dedicatedBook = isDedicatedGeneratedBook(name, artifact.chatKey);
    const preview = maintenancePreviewFromData(data, name, artifact.chatKey, dedicatedBook);
    const plan = await desiredSpecs(artifact);
    const cleanup = await legacyCleanupScope(artifact);
    assertArtifactCommitCurrent(artifact);
    const first = reconcileLorebookMaintenanceEntries(
      data,
      plan.desired,
      artifact.chatKey,
      wi,
      name,
      dedicatedBook,
      cleanup,
    );
    let removed = first.removed;
    if (first.changed) {
      assertArtifactCommitCurrent(artifact);
      await wi.saveWorldInfo(name, data, true);
      assertArtifactCommitCurrent(artifact);

      const verifiedData = (await wi.loadWorldInfo(name)) || data;
      assertArtifactCommitCurrent(artifact);
      const verification = reconcileLorebookMaintenanceEntries(
        verifiedData,
        plan.desired,
        artifact.chatKey,
        wi,
        name,
        dedicatedBook,
        cleanup,
      );
      removed += verification.removed;
      if (verification.changed) {
        await wi.saveWorldInfo(name, verifiedData, true);
        assertArtifactCommitCurrent(artifact);
      }

      const renderedTarget = await reloadWorldInfoEditor(wi, name, true);
      assertArtifactCommitCurrent(artifact);
      if (renderedTarget) {
        const postReloadData = (await wi.loadWorldInfo(name)) || verifiedData;
        assertArtifactCommitCurrent(artifact);
        const postReloadVerification = reconcileLorebookMaintenanceEntries(
          postReloadData,
          plan.desired,
          artifact.chatKey,
          wi,
          name,
          dedicatedBook,
          cleanup,
        );
        removed += postReloadVerification.removed;
        if (postReloadVerification.changed) {
          await wi.saveWorldInfo(name, postReloadData, true);
          assertArtifactCommitCurrent(artifact);
        }
      }
    }
    return { ...preview, applied: true, removed };
  });
}

export async function clearCurrentChatLorebookEntries(chatKey = currentChatKey()): Promise<number> {
  assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
  const name = resolveTargetBookName(false, chatKey);
  if (!name) return 0;
  return withLorebookMutation(name, async () => {
    assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
    const wi = await worldInfoApi();
    assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
    const data = await wi.loadWorldInfo(name);
    assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
    if (!data?.entries) return 0;
    let removed = 0;
    for (const [uid, entry] of Object.entries<any>(data.entries)) {
      const info = managedInfo(entry);
      if (info?.managed && info.chatKey === chatKey) {
        delete data.entries[uid];
        removed += 1;
      }
    }
    if (removed) {
      assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
      await wi.saveWorldInfo(name, data, true);
      assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
      await reloadWorldInfoEditor(wi, name);
      assertChatCommitCurrent(chatKey, '聊天已切换，停止清理旧聊天世界书');
    }
    return removed;
  });
}

export async function pauseCurrentChatLorebookEntries(chatKey = currentChatKey()): Promise<number> {
  assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
  const name = resolveTargetBookName(false, chatKey);
  if (!name) return 0;
  return withLorebookMutation(name, async () => {
    assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
    const wi = await worldInfoApi();
    assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
    const data = await wi.loadWorldInfo(name);
    assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
    if (!data?.entries) return 0;
    let managed = 0;
    let changed = false;
    for (const entry of Object.values<any>(data.entries)) {
      const info = managedInfo(entry);
      if (info?.managed && info.chatKey === chatKey) {
        managed += 1;
        if (!entry.disable) {
          entry.disable = true;
          changed = true;
        }
      }
    }
    if (changed) {
      assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
      await wi.saveWorldInfo(name, data, true);
      assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
      await reloadWorldInfoEditor(wi, name);
      assertChatCommitCurrent(chatKey, '聊天已切换，停止暂停旧聊天世界书');
    }
    return managed;
  });
}
