/**
 * 模块职责：创建、读取、附着消息级 artifact，并维护阶段状态。
 * 维护边界：artifact 是单条正文的规范结果，必须与 chatKey、messageIdentity 和 sourceFingerprint 绑定。
 */
import { MODULE_NAME } from '../constants';
import type { MessageArtifact, SillyTavernMessage, StageRecord } from '../types';
import { currentChatKey, messageFingerprint, messageIdentity, previousUserText } from '../core/context';
import { nowIso, safeText } from '../core/utils';

function idleStage(): StageRecord {
  return { status: 'idle', attempts: 0 };
}

export function createArtifact(message: SillyTavernMessage, messageIndex: number): MessageArtifact {
  const now = nowIso();
  return {
    schemaVersion: 1,
    chatKey: currentChatKey(),
    messageKey: messageIdentity(messageIndex),
    messageIndex,
    sourceFingerprint: messageFingerprint(messageIndex),
    playerText: previousUserText(messageIndex),
    assistantText: safeText(message.mes),
    createdAt: now,
    updatedAt: now,
    stages: {
      audit: idleStage(),
      revision: idleStage(),
      state: idleStage(),
      summary: idleStage(),
      sync: idleStage(),
    },
  };
}

export function attachArtifactToMessage(message: SillyTavernMessage, artifact: MessageArtifact): void {
  message.extra ||= {};
  message.extra[MODULE_NAME] = artifact;
}

export function getAttachedArtifact(message: SillyTavernMessage | null | undefined): MessageArtifact | null {
  const value = message?.extra?.[MODULE_NAME];
  return value && typeof value === 'object' ? (value as MessageArtifact) : null;
}

export function markStage(artifact: MessageArtifact, stage: keyof MessageArtifact['stages'], status: StageRecord['status'], error?: string): void {
  const current = artifact.stages[stage] ?? idleStage();
  const now = nowIso();
  artifact.stages[stage] = {
    ...current,
    status,
    attempts: status === 'running' ? current.attempts + 1 : current.attempts,
    startedAt: status === 'running' ? now : current.startedAt,
    finishedAt: ['success', 'failed', 'skipped', 'blocked'].includes(status) ? now : undefined,
    error: error || undefined,
  };
  artifact.updatedAt = now;
}
