/**
 * 模块职责：对 SillyTavern 返回的结构化结果执行确定性的 JSON Schema 子集校验。
 * 维护边界：只校验镜渊实际使用的 type/required/properties/items/enum/additionalProperties，
 * 不尝试替代完整 JSON Schema 实现，也不修改模型返回内容。
 */

export interface SchemaValidationIssue {
  path: string;
  message: string;
}

export interface SchemaValidationOptions {
  /** 仅供本地旧数据迁移使用；不会修改发送给供应商的 Schema。 */
  allowedAdditionalProperties?: Record<string, string[]>;
  allowedAdditionalPropertiesByPathPrefix?: Record<string, string[]>;
  allowedMissingRequiredByPathPrefix?: Record<string, string[]>;
}

function schemaRoot(schema: unknown): Record<string, any> | null {
  if (!schema || typeof schema !== 'object' || Array.isArray(schema)) return null;
  const source = schema as Record<string, any>;
  const value = source.value;
  if (value && typeof value === 'object' && !Array.isArray(value)) return value;
  return source;
}

function typeMatches(value: unknown, type: string): boolean {
  if (type === 'object') return Boolean(value) && typeof value === 'object' && !Array.isArray(value);
  if (type === 'array') return Array.isArray(value);
  if (type === 'string') return typeof value === 'string';
  if (type === 'boolean') return typeof value === 'boolean';
  if (type === 'number') return typeof value === 'number' && Number.isFinite(value);
  if (type === 'integer') return typeof value === 'number' && Number.isInteger(value);
  if (type === 'null') return value === null;
  return true;
}

function describeType(value: unknown): string {
  if (value === null) return 'null';
  if (Array.isArray(value)) return 'array';
  return typeof value;
}

function validateNode(
  value: unknown,
  schema: Record<string, any>,
  path: string,
  issues: SchemaValidationIssue[],
  limit: number,
  options: SchemaValidationOptions,
): void {
  if (issues.length >= limit) return;

  if (Array.isArray(schema.enum) && !schema.enum.some((item: unknown) => Object.is(item, value))) {
    issues.push({ path, message: `值不在允许枚举中` });
    return;
  }

  const types = Array.isArray(schema.type) ? schema.type : schema.type ? [schema.type] : [];
  if (types.length && !types.some((type: unknown) => typeof type === 'string' && typeMatches(value, type))) {
    issues.push({ path, message: `类型应为 ${types.join('|')}，实际为 ${describeType(value)}` });
    return;
  }

  if (schema.type === 'object' || (!schema.type && value && typeof value === 'object' && !Array.isArray(value))) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return;
    const object = value as Record<string, unknown>;
    const properties = schema.properties && typeof schema.properties === 'object' && !Array.isArray(schema.properties)
      ? schema.properties as Record<string, Record<string, any>>
      : {};
    const required = Array.isArray(schema.required) ? schema.required.filter((item: unknown) => typeof item === 'string') : [];
    const allowedMissing = new Set<string>();
    for (const [prefix, keys] of Object.entries(options.allowedMissingRequiredByPathPrefix ?? {})) {
      if (path.startsWith(prefix)) for (const key of keys) allowedMissing.add(key);
    }
    for (const key of required) {
      if (!Object.prototype.hasOwnProperty.call(object, key) && !allowedMissing.has(key)) {
        issues.push({ path: `${path}.${key}`, message: '缺少必填字段' });
        if (issues.length >= limit) return;
      }
    }
    if (schema.additionalProperties === false) {
      const allowedAdditional = new Set(options.allowedAdditionalProperties?.[path] ?? []);
      for (const [prefix, keys] of Object.entries(options.allowedAdditionalPropertiesByPathPrefix ?? {})) {
        if (path.startsWith(prefix)) for (const key of keys) allowedAdditional.add(key);
      }
      for (const key of Object.keys(object)) {
        if (!Object.prototype.hasOwnProperty.call(properties, key) && !allowedAdditional.has(key)) {
          issues.push({ path: `${path}.${key}`, message: '出现未声明字段' });
          if (issues.length >= limit) return;
        }
      }
    }
    for (const [key, childSchema] of Object.entries(properties)) {
      if (!Object.prototype.hasOwnProperty.call(object, key)) continue;
      if (!childSchema || typeof childSchema !== 'object' || Array.isArray(childSchema)) continue;
      validateNode(object[key], childSchema, `${path}.${key}`, issues, limit, options);
      if (issues.length >= limit) return;
    }
    return;
  }

  if (schema.type === 'array') {
    if (!Array.isArray(value)) return;
    const itemSchema = schema.items;
    if (!itemSchema || typeof itemSchema !== 'object' || Array.isArray(itemSchema)) return;
    value.forEach((item, index) => {
      if (issues.length >= limit) return;
      validateNode(item, itemSchema, `${path}[${index}]`, issues, limit, options);
    });
  }
}

export function validateStructuredValue(
  value: unknown,
  schema: unknown,
  limit = 12,
  options: SchemaValidationOptions = {},
): SchemaValidationIssue[] {
  const root = schemaRoot(schema);
  if (!root) return [];
  const issues: SchemaValidationIssue[] = [];
  validateNode(value, root, '$', issues, Math.max(1, limit), options);
  return issues;
}

export function formatSchemaIssues(issues: SchemaValidationIssue[]): string {
  return issues.map((issue) => `${issue.path}：${issue.message}`).join('；');
}
